'use client';

import * as React from 'react';
import { TrendChart, TrendDirection } from '../trend-chart/TrendChart';
import { Dropdown, DropdownMenuItem, DropdownVariant } from '../dropdown/Dropdown';
import { ContainerFooter } from '../container-footer/ContainerFooter';
import { FeaturedIcon, FeaturedIconSize, FeaturedIconColor, FeaturedIconStyle } from '../featured-icon/FeaturedIcon';
import { Badge } from '../badge/Badge';
import '../../../../../bellhopos-styles/src/components/trend-chart-card.css';

export type TrendChartCardType = 'metric' | 'simple' | 'featured-icon';
export type TrendChartCardBreakpoint = 'desktop' | 'mobile';
export type ValueType = 'currency' | 'percentage' | 'number';

export interface TrendChartCardProps {
  type?: TrendChartCardType;
  breakpoint?: TrendChartCardBreakpoint;
  heading?: string;
  value?: number;
  valueType?: ValueType;
  trend?: TrendDirection;
  showTrendIcon?: boolean;
  showDropdown?: boolean;
  dropdownVariant?: DropdownVariant;
  trendPercentage?: string;
  showChart?: boolean;
  chartData?: number[];
  showFooter?: boolean;
  footerButtonLabel?: string;
  icon?: string;
  iconSize?: FeaturedIconSize;
  iconColor?: FeaturedIconColor;
  iconStyle?: FeaturedIconStyle;
  onDropdownSelect?: (item: DropdownMenuItem) => void;
  onFooterButtonClick?: () => void;
}

const defaultDropdownMenuItems: DropdownMenuItem[] = [
  { id: 'view', label: 'View details', icon: 'visibility' },
  { id: 'edit', label: 'Edit', icon: 'edit' },
  { id: 'export', label: 'Export data', icon: 'download' },
  { id: 'divider', label: '', divider: true },
  { id: 'delete', label: 'Delete', icon: 'delete' },
];

export const TrendChartCard: React.FC<TrendChartCardProps> = ({
  type = 'metric',
  breakpoint = 'desktop',
  heading = 'RevPAR',
  value = 125.5,
  valueType = 'currency',
  trend = 'positive',
  showTrendIcon = true,
  showDropdown = true,
  dropdownVariant = 'icon-only-ghost',
  trendPercentage = '12.5%',
  showChart = false,
  chartData = [95, 105, 110, 108, 115, 120, 125],
  showFooter = false,
  footerButtonLabel = 'View report',
  icon = 'trending_up',
  iconSize = 'lg',
  iconColor = 'brand',
  iconStyle = 'outlined',
  onDropdownSelect,
  onFooterButtonClick,
}) => {
  const containerClasses = React.useMemo(() => {
    const classes = [
      'trend-chart-card',
      `trend-chart-card-${type}`,
      `trend-chart-card-${breakpoint}`,
    ];

    if (showFooter) {
      classes.push('has-footer');
    }

    return classes.join(' ');
  }, [type, breakpoint, showFooter]);

  const formattedValue = React.useMemo(() => {
    switch (valueType) {
      case 'currency':
        return `$${value.toFixed(2)}`;
      case 'percentage':
        return `${value.toFixed(1)}%`;
      default:
        // Special case for guest satisfaction ratings
        if (heading.toLowerCase().includes('satisfaction') && value >= 1000) {
          const rating = (value / 1000).toFixed(1);
          return `${rating}/5`;
        }
        return value.toLocaleString();
    }
  }, [value, valueType, heading]);

  const trendIcon = React.useMemo(() => {
    if (trend === 'positive') return 'trending_up';
    if (trend === 'negative') return 'trending_down';
    return 'trending_flat';
  }, [trend]);

  const badgeVariant = React.useMemo(() => {
    if (trend === 'positive') return 'green';
    if (trend === 'negative') return 'red';
    return 'gray';
  }, [trend]);

  const badgeIconName = React.useMemo(() => {
    if (trend === 'positive') return 'trending_up';
    if (trend === 'negative') return 'trending_down';
    return 'trending_flat';
  }, [trend]);

  const handleDropdownSelect = (item: DropdownMenuItem) => {
    onDropdownSelect?.(item);
  };

  const handleFooterButtonClick = () => {
    onFooterButtonClick?.();
  };

  return (
    <div className="trend-chart-card-wrapper">
      <div className={containerClasses}>
        {/* Header for metric variant */}
        {type === 'metric' && (
          <div className="trend-chart-card-header">
            <h3 className="trend-chart-card-heading">{heading}</h3>
            {showDropdown && (
              <div className="trend-chart-card-dropdown">
                <Dropdown
                  variant={dropdownVariant}
                  size="md"
                  iconName="more_vert"
                  menuItems={defaultDropdownMenuItems}
                  onItemClick={handleDropdownSelect}
                />
              </div>
            )}
          </div>
        )}

        {/* Header for simple variant */}
        {type === 'simple' && (
          <div className="trend-chart-card-header">
            <h3 className="trend-chart-card-heading">{heading}</h3>
            {showDropdown && (
              <div className="trend-chart-card-dropdown">
                <Dropdown
                  variant={dropdownVariant}
                  size="md"
                  iconName="more_vert"
                  menuItems={defaultDropdownMenuItems}
                  onItemClick={handleDropdownSelect}
                />
              </div>
            )}
          </div>
        )}

        {/* Dropdown Menu for featured-icon variant */}
        {showDropdown && type === 'featured-icon' && (
          <div className="trend-chart-card-dropdown">
            <Dropdown
              variant={dropdownVariant}
              size="md"
              iconName="more_vert"
              menuItems={defaultDropdownMenuItems}
              onItemClick={handleDropdownSelect}
            />
          </div>
        )}

        {/* Featured icon for featured-icon variant */}
        {type === 'featured-icon' && (
          <div className="trend-chart-card-icon">
            <FeaturedIcon
              icon={icon}
              size={iconSize}
              color={iconColor}
              style={iconStyle}
            />
          </div>
        )}

        {/* Heading for featured-icon variant */}
        {type === 'featured-icon' && (
          <h3 className="trend-chart-card-heading">{heading}</h3>
        )}

        {/* Number and content row */}
        <div className="trend-chart-card-row">
          <div className="trend-chart-card-number-wrap">
            <div className="trend-chart-card-number">{formattedValue}</div>

            {/* Trend icon for metric variant */}
            {type === 'metric' && showTrendIcon && (
              <span className={`trend-icon trend-icon-${trend}`}>
                <span className="material-symbols-outlined">{trendIcon}</span>
              </span>
            )}

            {/* Badge next to value when chart is shown for simple/featured-icon */}
            {showChart && showTrendIcon && (type === 'simple' || type === 'featured-icon') && (
              <div className="trend-chart-card-badge-inline">
                <Badge
                  variant={badgeVariant}
                  size="sm"
                  emphasis="medium"
                  icon={badgeIconName}
                  label={trendPercentage}
                />
              </div>
            )}
          </div>

          {/* Badge for simple and featured-icon variants (when chart is not shown) */}
          {(type === 'simple' || type === 'featured-icon') && showTrendIcon && !showChart && (
            <div className="trend-chart-card-badge-wrap">
              <Badge
                variant={badgeVariant}
                size="sm"
                emphasis="medium"
                icon={badgeIconName}
                label={trendPercentage}
              />
            </div>
          )}

          {/* Chart for any variant when showChart is true */}
          {showChart && (
            <TrendChart
              variant="line-only"
              trend={trend}
              data={chartData}
              animated={true}
              width={112}
              height={56}
            />
          )}
        </div>
      </div>

      {/* Footer outside container */}
      {showFooter && (
        <ContainerFooter
          size={type === 'metric' ? 'minimal' : 'standard'}
          buttonLabel={footerButtonLabel}
          onButtonClick={handleFooterButtonClick}
        />
      )}
    </div>
  );
};