'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/picker-menu.css';
import '../../../../../bellhopos-styles/src/tokens/bellhop-animations.css';
import { Button } from '../button/Button';
import { MonthPickerContent, MonthYear, DisabledMonth } from '../month-picker-content/MonthPickerContent';

export interface PickerMenuProps {
  minYear?: number;
  maxYear?: number;
  disabled?: boolean;
  disabledMonths?: DisabledMonth[];
  animationClass?: string;
  visible?: boolean;
  showFooter?: boolean;
  showTodayButton?: boolean;
  disableApply?: boolean;
  value?: MonthYear | null;
  children?: React.ReactNode;
  onChange?: (value: MonthYear | null) => void;
  onMonthYearSelect?: (selection: MonthYear) => void;
  onCancel?: () => void;
  onApply?: () => void;
  onToday?: () => void;
}

export const PickerMenu: React.FC<PickerMenuProps> = ({
  minYear = 1998,
  maxYear = 2060,
  disabled = false,
  disabledMonths = [],
  animationClass = 'animate-dropdown-enter',
  visible = true,
  showFooter = true,
  showTodayButton = false,
  disableApply = false,
  value,
  children,
  onChange,
  onMonthYearSelect,
  onCancel,
  onApply,
  onToday,
}) => {
  const [isClosing, setIsClosing] = React.useState(false);
  const [shouldRender, setShouldRender] = React.useState(visible);
  const [selectedMonth, setSelectedMonth] = React.useState<number | null>(null);
  const [selectedYear, setSelectedYear] = React.useState<number | null>(null);

  // Initialize with current date or provided value
  React.useEffect(() => {
    if (value) {
      setSelectedMonth(value.month);
      setSelectedYear(value.year);
    } else {
      // Initialize with current date
      const now = new Date();
      const currentMonth = now.getMonth();
      const currentYear = now.getFullYear();

      // Set initial selection to current month/year if within range
      if (currentYear >= minYear && currentYear <= maxYear) {
        setSelectedMonth(currentMonth);
        setSelectedYear(currentYear);
      } else {
        // If current year is out of range, select closest available year with current month
        if (currentYear < minYear) {
          setSelectedYear(minYear);
        } else {
          setSelectedYear(maxYear);
        }
        setSelectedMonth(currentMonth);
      }
    }
  }, [value, minYear, maxYear]);

  // Handle visibility changes with animation
  React.useEffect(() => {
    if (visible) {
      setShouldRender(true);
      setIsClosing(false);
    } else {
      setIsClosing(true);
      const timer = setTimeout(() => {
        setShouldRender(false);
        setIsClosing(false);
      }, 150);
      return () => clearTimeout(timer);
    }
  }, [visible]);

  const handleMonthYearSelect = (selection: MonthYear): void => {
    setSelectedMonth(selection.month);
    setSelectedYear(selection.year);
    onChange?.(selection);
    onMonthYearSelect?.(selection);
  };

  const handleCancel = (): void => {
    onCancel?.();
  };

  const handleApply = (): void => {
    if (children) {
      // For custom content (like DatePickerContent), just call onApply
      onApply?.();
    } else {
      // For MonthPickerContent, handle the selection
      if (selectedMonth !== null && selectedYear !== null) {
        const selection: MonthYear = {
          month: selectedMonth,
          year: selectedYear,
        };
        onApply?.();
      }
    }
  };

  if (!shouldRender) {
    return null;
  }

  const menuClasses = `picker-menu ${isClosing ? 'animate-dropdown-exit' : animationClass} ${!showFooter ? 'no-footer' : ''}`;

  return (
    <div className={menuClasses}>
      {/* Main Content Area - render children if provided, otherwise MonthPickerContent */}
      {children || (
        <MonthPickerContent
          minYear={minYear}
          maxYear={maxYear}
          disabled={disabled}
          disabledMonths={disabledMonths}
          scrollable={true}
          selectedMonth={selectedMonth}
          selectedYear={selectedYear}
          onChange={handleMonthYearSelect}
        />
      )}

      {/* Footer Actions - conditionally rendered */}
      {showFooter && (
        <div className="picker-menu-footer">
          <div className={`picker-menu-actions ${showTodayButton ? 'has-today-button' : ''}`}>
            {/* Today button on the left */}
            {showTodayButton && (
              <Button
                hierarchy="secondary"
                type="outline"
                size="sm"
                icon="only"
                iconName="today"
                onClick={onToday}
                className="today-button"
              />
            )}

            {/* Cancel and Apply buttons always on the right */}
            <div className="picker-menu-main-actions">
              <Button
                hierarchy="secondary"
                size="sm"
                label="Cancel"
                onClick={handleCancel}
              />
              <Button
                hierarchy="primary"
                size="sm"
                label="Apply"
                disabled={disableApply || (!children && (selectedMonth === null || selectedYear === null))}
                onClick={handleApply}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PickerMenu;