'use client';

import * as React from 'react';
import { FeaturedIcon, FeaturedIconColor, FeaturedIconStyle } from '../featured-icon/FeaturedIcon';
import { Button } from '../button/Button';

export type NotificationType =
  | 'primary'
  | 'gray'
  | 'success'
  | 'error'
  | 'warning'
  | 'progress'
  | 'image'
  | 'avatar'
  | 'no-icon';

export type NotificationBreakpoint = 'desktop' | 'mobile';

export interface NotificationProps {
  type?: NotificationType;
  breakpoint?: NotificationBreakpoint;
  title?: string;
  description?: string;
  actionText?: string;
  dismissText?: string;
  dismissible?: boolean;
  imageUrl?: string;
  avatarUrl?: string;
  progress?: number;
  icon?: string;
  featuredIconStyle?: FeaturedIconStyle;
  featuredIconColor?: FeaturedIconColor;
  animated?: boolean;
  closing?: boolean;
  className?: string;
  onAction?: () => void;
  onDismiss?: () => void;
  onClose?: () => void;
}

export const Notification: React.FC<NotificationProps> = ({
  type = 'primary',
  breakpoint = 'desktop',
  title,
  description,
  actionText,
  dismissText,
  dismissible = true,
  imageUrl,
  avatarUrl,
  progress,
  icon,
  featuredIconStyle = 'outlined',
  featuredIconColor,
  animated = false,
  closing = false,
  className = '',
  onAction,
  onDismiss,
  onClose,
}) => {
  const notificationClasses = React.useMemo(() => {
    const classes = [
      'notification',
      `notification-${type}`,
      `notification-${breakpoint}`,
    ];

    if (animated) {
      classes.push('notification-animated');
    }

    if (closing) {
      classes.push('notification-closing');
    }

    if (className) {
      classes.push(className);
    }

    return classes.join(' ');
  }, [type, breakpoint, animated, closing, className]);

  const iconName = React.useMemo(() => {
    switch (type) {
      case 'primary':
        return 'new_releases';
      case 'success':
        return 'check_circle';
      case 'error':
        return 'error';
      case 'warning':
        return 'warning';
      case 'gray':
        return 'info';
      default:
        return icon || '';
    }
  }, [type, icon]);

  const computedFeaturedIconColor: FeaturedIconColor = React.useMemo(() => {
    if (featuredIconColor) return featuredIconColor;

    switch (type) {
      case 'primary':
        return 'brand';
      case 'success':
        return 'success';
      case 'error':
        return 'error';
      case 'warning':
        return 'warning';
      case 'gray':
        return 'gray';
      default:
        return 'gray';
    }
  }, [type, featuredIconColor]);

  const handleAction = React.useCallback(() => {
    onAction?.();
  }, [onAction]);

  const handleDismiss = React.useCallback(() => {
    onDismiss?.();
  }, [onDismiss]);

  const handleClose = React.useCallback(() => {
    onClose?.();
  }, [onClose]);

  const progressDashArray = 50.27;
  const progressOffset = progress ? progressDashArray - (progressDashArray * progress) / 100 : progressDashArray;

  return (
    <div className={notificationClasses}>
      {/* Image variant (only for mobile) */}
      {type === 'image' && breakpoint === 'mobile' && (
        <div className="notification-image-container">
          <img src={imageUrl} alt="Notification image" className="notification-image" />
        </div>
      )}

      {/* Main content area */}
      <div className="notification-content">
        {/* Icon/Avatar/Progress section */}
        {type !== 'no-icon' && type !== 'image' && (
          <div className="notification-icon-wrapper">
            {/* Avatar */}
            {type === 'avatar' && (
              <div className="notification-avatar">
                <img src={avatarUrl} alt="Avatar" />
              </div>
            )}

            {/* Progress indicator */}
            {type === 'progress' && (
              <div className="notification-progress">
                <svg className="progress-ring" viewBox="0 0 20 20">
                  <circle
                    className="progress-ring-circle-bg"
                    cx="10"
                    cy="10"
                    r="8"
                    fill="none"
                    strokeWidth="2"
                  />
                  <circle
                    className="progress-ring-circle"
                    cx="10"
                    cy="10"
                    r="8"
                    fill="none"
                    strokeWidth="2"
                    style={{
                      strokeDasharray: `${progressDashArray} ${progressDashArray}`,
                      strokeDashoffset: progressOffset,
                    }}
                  />
                </svg>
              </div>
            )}

            {/* Featured Icon */}
            {type !== 'avatar' && type !== 'progress' && (
              <FeaturedIcon
                size="md"
                color={computedFeaturedIconColor}
                style={featuredIconStyle}
                icon={iconName}
              />
            )}
          </div>
        )}

        {/* Text content */}
        <div className="notification-text">
          <div className="notification-text-wrapper">
            {title && <h3 className="notification-title">{title}</h3>}
            {description && <p className="notification-description">{description}</p>}
          </div>

          {/* Actions */}
          {(actionText || dismissText) && (
            <div className="notification-actions">
              {dismissText && (
                <Button
                  label={dismissText}
                  hierarchy="tertiary"
                  size="sm"
                  onClick={handleDismiss}
                />
              )}
              {actionText && (
                <Button
                  label={actionText}
                  hierarchy="quaternary"
                  size="sm"
                  onClick={handleAction}
                />
              )}
            </div>
          )}
        </div>
      </div>

      {/* Close button */}
      {dismissible && (
        <button className="notification-close" onClick={handleClose}>
          <span className="material-symbols-outlined notification-close-icon">
            close
          </span>
        </button>
      )}
    </div>
  );
};