'use client';

import * as React from 'react';
import { Tooltip } from '../tooltip/Tooltip';
import { Tag } from '../tag/Tag';
import { AutocompleteMenu, AutocompleteMenuItem } from '../autocomplete-menu/AutocompleteMenu';
import '../../../../../bellhopos-styles/src/components/textarea.css';

export type TextareaType = 'default' | 'tags';
export type TextareaState = 'default' | 'focused' | 'hover' | 'placeholder' | 'disabled';

export interface TagData {
  id: string;
  label: string;
}

export interface TextareaProps {
  type?: TextareaType;
  state?: TextareaState;
  label?: string;
  placeholder?: string;
  hintText?: string;
  showLabel?: boolean;
  showHintText?: boolean;
  showHelpIcon?: boolean;
  error?: boolean;
  disabled?: boolean;
  required?: boolean;
  helpIconTooltip?: string;
  value?: string;
  rows?: number;
  resize?: 'none' | 'both' | 'horizontal' | 'vertical';
  maxLength?: number;
  width?: string;
  className?: string;
  
  // Tags specific props
  tags?: TagData[];
  allowTagCreation?: boolean;
  availableTags?: TagData[];
  enableAutocomplete?: boolean;
  
  // Events
  onChange?: (value: string) => void;
  onFocus?: () => void;
  onBlur?: () => void;
  onHelpClick?: () => void;
  onTagsChange?: (tags: TagData[]) => void;
  onTagCreated?: (tag: TagData) => void;
  onTagRemoved?: (tag: TagData) => void;
}

export const Textarea: React.FC<TextareaProps> = ({
  type = 'default',
  state: controlledState,
  label = 'Comment',
  placeholder = 'Write a message...',
  hintText = 'This is a hint text to help user.',
  showLabel = true,
  showHintText = true,
  showHelpIcon = true,
  error = false,
  disabled = false,
  required = false,
  helpIconTooltip = 'Help',
  value: controlledValue = '',
  rows = 4,
  resize = 'none',
  maxLength,
  width,
  className = '',
  
  // Tags props
  tags: controlledTags = [],
  allowTagCreation = true,
  availableTags = [],
  enableAutocomplete = true,
  
  // Events
  onChange,
  onFocus,
  onBlur,
  onHelpClick,
  onTagsChange,
  onTagCreated,
  onTagRemoved,
}) => {
  const [internalValue, setInternalValue] = React.useState(controlledValue);
  const [internalState, setInternalState] = React.useState<TextareaState>('default');
  const [internalTags, setInternalTags] = React.useState<TagData[]>(controlledTags);
  const [showHelpTooltip, setShowHelpTooltip] = React.useState(false);
  const [autocompleteVisible, setAutocompleteVisible] = React.useState(false);
  const [autocompleteItems, setAutocompleteItems] = React.useState<AutocompleteMenuItem[]>([]);
  const [currentSearchQuery, setCurrentSearchQuery] = React.useState('');
  const [selectedAutocompleteIndex, setSelectedAutocompleteIndex] = React.useState(-1);
  
  const editableDivRef = React.useRef<HTMLDivElement>(null);
  const tooltipTimer = React.useRef<NodeJS.Timeout | null>(null);

  // Use controlled or internal values
  const value = controlledValue || internalValue;
  const state = controlledState || internalState;
  const tags = controlledTags.length > 0 ? controlledTags : internalTags;

  // Update internal state when controlled values change
  React.useEffect(() => {
    if (controlledValue !== undefined) {
      setInternalValue(controlledValue);
    }
  }, [controlledValue]);

  React.useEffect(() => {
    if (controlledTags.length > 0) {
      setInternalTags(controlledTags);
    }
  }, [controlledTags]);

  // Compute container classes
  const containerClasses = React.useMemo(() => {
    const classes = ['textarea-container'];

    if (error) {
      classes.push('textarea-container-error');
    }

    if (state === 'focused') {
      classes.push('textarea-container-focused');
    }

    if (disabled) {
      classes.push('textarea-container-disabled');
    }

    return classes.join(' ');
  }, [error, state, disabled]);

  // Compute textarea classes for default type
  const textareaClasses = React.useMemo(() => {
    const classes = ['textarea'];

    if (error) {
      classes.push('textarea-error');
    }

    if (state !== 'default') {
      classes.push(`textarea-${state}`);
    }

    return classes.join(' ');
  }, [error, state]);

  // Handle textarea input for default type
  const handleTextareaInput = React.useCallback((event: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newValue = event.target.value;
    
    if (!controlledValue) {
      setInternalValue(newValue);
    }
    
    onChange?.(newValue);
  }, [controlledValue, onChange]);

  // Handle contentEditable input for tags type
  const handleContentEditableInput = React.useCallback((event: React.FormEvent<HTMLDivElement>) => {
    const target = event.target as HTMLElement;
    const text = target.textContent || '';
    
    if (!controlledValue) {
      setInternalValue(text);
    }
    
    onChange?.(text);

    // Show autocomplete for tags type
    if (type === 'tags') {
      displayAutocomplete(text);
    }
  }, [controlledValue, onChange, type]);

  // Handle focus
  const handleFocus = React.useCallback(() => {
    if (!controlledState) {
      setInternalState('focused');
    }
    onFocus?.();
  }, [controlledState, onFocus]);

  // Handle blur
  const handleBlur = React.useCallback(() => {
    // Create tag from current text when blurring for tags type
    if (type === 'tags' && value.trim()) {
      createTagFromText(value.trim());
    }

    if (!controlledState) {
      setInternalState('default');
    }
    onBlur?.();
  }, [controlledState, onBlur, type, value]);

  // Handle keydown for tags type
  const handleKeyDown = React.useCallback((event: React.KeyboardEvent<HTMLDivElement>) => {
    if (type !== 'tags') return;

    const target = event.target as HTMLElement;
    const text = target.textContent || '';

    // Handle autocomplete-specific keys first
    if (autocompleteVisible) {
      if (event.key === 'ArrowDown') {
        event.preventDefault();
        setSelectedAutocompleteIndex(prev => 
          Math.min(prev + 1, autocompleteItems.length - 1)
        );
        return;
      } else if (event.key === 'ArrowUp') {
        event.preventDefault();
        setSelectedAutocompleteIndex(prev => Math.max(prev - 1, 0));
        return;
      } else if (event.key === 'Escape') {
        hideAutocomplete();
        return;
      } else if (
        (event.key === 'Enter' || event.key === ' ') &&
        selectedAutocompleteIndex >= 0
      ) {
        event.preventDefault();
        selectAutocompleteItem(autocompleteItems[selectedAutocompleteIndex]);
        return;
      }
    }

    // Normal key handling for tag creation
    if (event.key === ' ' || event.key === 'Enter') {
      event.preventDefault();
      if (text.trim()) {
        createTagFromText(text.trim());
      }
    } else if (event.key === 'Backspace') {
      if (!text && tags.length > 0) {
        // Remove last tag if no text content
        const lastTag = tags[tags.length - 1];
        handleTagRemove(lastTag);
      }
    }
  }, [type, autocompleteVisible, autocompleteItems, selectedAutocompleteIndex, tags]);

  // Create tag from text
  const createTagFromText = React.useCallback((text: string) => {
    if (allowTagCreation && text.trim()) {
      const existingTag = tags.find(
        tag => tag.label.toLowerCase() === text.toLowerCase()
      );

      if (!existingTag) {
        const newTag: TagData = {
          id: Date.now().toString(),
          label: text.trim(),
        };

        const newTags = [...tags, newTag];
        setInternalTags(newTags);
        onTagsChange?.(newTags);
        onTagCreated?.(newTag);
        clearInput();
      }
    }
  }, [allowTagCreation, tags, onTagsChange, onTagCreated]);

  // Remove tag
  const handleTagRemove = React.useCallback((tag: TagData) => {
    const newTags = tags.filter(t => t.id !== tag.id);
    setInternalTags(newTags);
    onTagsChange?.(newTags);
    onTagRemoved?.(tag);
  }, [tags, onTagsChange, onTagRemoved]);

  // Clear input
  const clearInput = React.useCallback(() => {
    if (editableDivRef.current) {
      editableDivRef.current.textContent = '';
    }
    setInternalValue('');
    setCurrentSearchQuery('');
    onChange?.('');
  }, [onChange]);

  // Display autocomplete
  const displayAutocomplete = React.useCallback((query: string) => {
    if (!enableAutocomplete || !query.trim()) {
      hideAutocomplete();
      return;
    }

    setCurrentSearchQuery(query);

    // Filter available tags based on query and exclude already selected tags
    const selectedTagLabels = tags.map(tag => tag.label.toLowerCase());
    const filteredTags = availableTags.filter(
      tag =>
        tag.label.toLowerCase().includes(query.toLowerCase()) &&
        !selectedTagLabels.includes(tag.label.toLowerCase())
    );

    // Convert to autocomplete items
    const items: AutocompleteMenuItem[] = filteredTags.map(tag => ({
      id: tag.id,
      label: tag.label,
      disabled: false,
      selected: false,
    }));

    // Add "Create new tag" option if tag doesn't exist
    const exactMatch = filteredTags.find(
      tag => tag.label.toLowerCase() === query.toLowerCase()
    );

    if (!exactMatch && query.trim()) {
      items.unshift({
        id: 'create-new',
        label: `Create "${query}"`,
        disabled: false,
        selected: false,
      });
    }

    setAutocompleteItems(items);
    setAutocompleteVisible(items.length > 0);
    setSelectedAutocompleteIndex(items.length > 0 ? 0 : -1);
  }, [enableAutocomplete, tags, availableTags]);

  // Hide autocomplete
  const hideAutocomplete = React.useCallback(() => {
    setAutocompleteVisible(false);
    setAutocompleteItems([]);
    setSelectedAutocompleteIndex(-1);
  }, []);

  // Select autocomplete item
  const selectAutocompleteItem = React.useCallback((item: AutocompleteMenuItem) => {
    const searchQuery = currentSearchQuery;
    clearInput();

    if (item.id === 'create-new') {
      createTagFromText(searchQuery);
    } else {
      const tagData = availableTags.find(tag => tag.id === item.id);
      if (tagData) {
        const newTags = [...tags, tagData];
        setInternalTags(newTags);
        onTagsChange?.(newTags);
        onTagCreated?.(tagData);
      }
    }
    hideAutocomplete();
  }, [currentSearchQuery, clearInput, createTagFromText, availableTags, tags, onTagsChange, onTagCreated, hideAutocomplete]);

  // Handle autocomplete item click
  const handleAutocompleteItemClick = React.useCallback((item: AutocompleteMenuItem) => {
    selectAutocompleteItem(item);
  }, [selectAutocompleteItem]);

  // Handle autocomplete item hover
  const handleAutocompleteItemHover = React.useCallback((index: number) => {
    setSelectedAutocompleteIndex(index);
  }, []);

  // Handle help icon interactions
  const handleHelpIconClick = React.useCallback(() => {
    onHelpClick?.();
  }, [onHelpClick]);

  const handleHelpIconMouseEnter = React.useCallback(() => {
    if (tooltipTimer.current) {
      clearTimeout(tooltipTimer.current);
    }

    tooltipTimer.current = setTimeout(() => {
      setShowHelpTooltip(true);
    }, 300);
  }, []);

  const handleHelpIconMouseLeave = React.useCallback(() => {
    if (tooltipTimer.current) {
      clearTimeout(tooltipTimer.current);
      tooltipTimer.current = null;
    }
    setShowHelpTooltip(false);
  }, []);

  // Cleanup tooltip timer on unmount
  React.useEffect(() => {
    return () => {
      if (tooltipTimer.current) {
        clearTimeout(tooltipTimer.current);
      }
    };
  }, []);

  const wrapperClasses = ['textarea-wrapper', className].filter(Boolean).join(' ');

  return (
    <div className={wrapperClasses} style={{ width }}>
      <div className="textarea-with-label">
        {showLabel && (
          <div className="label-wrapper">
            <label className="label">{label}</label>
            {required && <span className="asterisk">*</span>}
            {showHelpIcon && (
              <div className="icon-with-tooltip">
                <span
                  className="material-symbols-outlined"
                  style={{
                    fontSize: '20px',
                    color: 'var(--color-neutral-400)',
                    cursor: 'pointer',
                  }}
                  onMouseEnter={handleHelpIconMouseEnter}
                  onMouseLeave={handleHelpIconMouseLeave}
                  onClick={handleHelpIconClick}
                >
                  help
                </span>
                <Tooltip
                  text={helpIconTooltip}
                  position="top"
                  variant="icon"
                  visible={showHelpTooltip}
                  style={{ position: 'absolute', top: 0, left: '50%' }}
                />
              </div>
            )}
          </div>
        )}

        <div className={containerClasses}>
          <div className="textarea-content">
            {/* Tags flowing below text content */}
            {type === 'tags' ? (
              <div className="tags-and-text-container">
                <div className="text-and-tags-flow">
                  <div
                    ref={editableDivRef}
                    className="textarea-editable"
                    contentEditable={!disabled}
                    aria-label={label}
                    aria-describedby={showHintText ? 'hint-text' : undefined}
                    aria-invalid={error}
                    data-placeholder={placeholder}
                    onInput={handleContentEditableInput}
                    onFocus={handleFocus}
                    onBlur={handleBlur}
                    onKeyDown={handleKeyDown}
                  />
                  {tags.length > 0 && (
                    <div className="tags-flow">
                      {tags.map(tag => (
                        <Tag
                          key={tag.id}
                          label={tag.label}
                          size="sm"
                          dismissible={!disabled}
                          onDismiss={() => handleTagRemove(tag)}
                        />
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <textarea
                className={textareaClasses}
                value={value}
                placeholder={placeholder}
                disabled={disabled}
                rows={rows}
                maxLength={maxLength}
                style={{ resize }}
                aria-label={label}
                aria-describedby={showHintText ? 'hint-text' : undefined}
                aria-invalid={error}
                onChange={handleTextareaInput}
                onFocus={handleFocus}
                onBlur={handleBlur}
              />
            )}
          </div>

          {/* Autocomplete Menu for Tags */}
          {type === 'tags' && (
            <div className="autocomplete-wrapper">
              <AutocompleteMenu
                menuItems={autocompleteItems}
                visible={autocompleteVisible}
                selectedIndex={selectedAutocompleteIndex}
                searchQuery={currentSearchQuery}
                maxHeight={200}
                onItemClick={handleAutocompleteItemClick}
                onItemHover={handleAutocompleteItemHover}
              />
            </div>
          )}
        </div>
      </div>

      {showHintText && hintText && (
        <div
          className={`hint-text ${error ? 'hint-error' : ''}`}
          id="hint-text"
        >
          {hintText}
        </div>
      )}
    </div>
  );
};