'use client';

import * as React from 'react';
import { Tooltip } from '../tooltip/Tooltip';
import '../../../../../bellhopos-styles/src/components/avatar-add.css';

export type AvatarAddSize = 'xxs' | 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';
export type AvatarAddState = 'default' | 'hover' | 'focus' | 'disabled';

export interface AvatarAddProps {
  size?: AvatarAddSize;
  state?: AvatarAddState;
  disabled?: boolean;
  showTooltip?: boolean;
  tooltipText?: string;
  onClick?: (event: React.MouseEvent<HTMLButtonElement>) => void;
}

export const AvatarAdd: React.FC<AvatarAddProps> = ({
  size = 'md',
  state = 'default',
  disabled = false,
  showTooltip = false,
  tooltipText = 'Add user',
  onClick,
}) => {
  const [isHovered, setIsHovered] = React.useState(false);
  const [isFocused, setIsFocused] = React.useState(false);

  const buttonClasses = React.useMemo(() => {
    const classes = ['avatar-add', `avatar-add-${size}`];

    if (disabled || state === 'disabled') {
      classes.push('avatar-add-disabled');
    } else if (state === 'focus' || isFocused) {
      classes.push('avatar-add-focus');
    } else if (state === 'hover' || isHovered) {
      classes.push('avatar-add-hover');
    }

    return classes.join(' ');
  }, [size, state, disabled, isHovered, isFocused]);

  const iconSizeClass = React.useMemo(() => {
    switch (size) {
      case 'xs':
        return 'icon-md';
      case 'sm':
        return 'icon-md';
      case 'md':
        return 'icon-lg';
      default:
        return 'icon-md';
    }
  }, [size]);

  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    if (!disabled) {
      onClick?.(event);
    }
  };

  const handleMouseEnter = () => {
    if (!disabled) {
      setIsHovered(true);
    }
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
  };

  const handleFocus = () => {
    if (!disabled) {
      setIsFocused(true);
    }
  };

  const handleBlur = () => {
    setIsFocused(false);
  };

  return (
    <div style={{ position: 'relative' }}>
      <button
        type="button"
        className={`${buttonClasses} avatar-add-button`}
        disabled={disabled}
        onClick={handleClick}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        onFocus={handleFocus}
        onBlur={handleBlur}
      >
        <span className="avatar-add-content">
          <span
            className={`material-symbols-outlined avatar-add-icon ${iconSizeClass}`}
          >
            add
          </span>
        </span>
      </button>

      {showTooltip && (
        <Tooltip
          text={tooltipText}
          position="top"
          visible={isHovered && !disabled}
        />
      )}
    </div>
  );
};