'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/avatar.css';

export type AvatarSize = 'xxs' | 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';
export type AvatarType = 'image' | 'placeholder' | 'text';
export type AvatarStatus = 'online' | 'offline' | 'none';

export interface AvatarProps {
  size?: AvatarSize;
  type?: AvatarType;
  status?: AvatarStatus;
  text?: string;
  imageSrc?: string;
  alt?: string;
  onMouseEnter?: () => void;
  onMouseLeave?: () => void;
}

export const Avatar: React.FC<AvatarProps> = ({
  size = 'md',
  type = 'image',
  status = 'none',
  text = 'RD',
  imageSrc = '/assets/avatars/regionalDirector.png',
  alt = 'Avatar',
  onMouseEnter,
  onMouseLeave,
}) => {
  const avatarClasses = React.useMemo(() => {
    const classes = ['avatar', `avatar-${size}`];
    
    if (status !== 'none') {
      classes.push('avatar-with-status');
    }
    
    return classes.join(' ');
  }, [size, status]);

  const statusClasses = React.useMemo(() => {
    const classes = [`avatar-status`, `avatar-status-${size}`];
    
    if (status === 'online') {
      classes.push('avatar-status-online');
    } else if (status === 'offline') {
      classes.push('avatar-status-offline');
    }
    
    return classes.join(' ');
  }, [size, status]);

  const textSizeClass = React.useMemo(() => {
    switch (size) {
      case 'xxs':
        return 'text-xxs';
      case 'xs':
        return 'text-xs';
      case 'sm':
        return 'text-sm';
      case 'md':
        return 'text-md';
      case 'lg':
        return 'text-lg';
      case 'xl':
        return 'text-xl';
      case '2xl':
        return 'text-2xl';
      default:
        return 'text-md';
    }
  }, [size]);

  const iconSizeClass = React.useMemo(() => {
    switch (size) {
      case 'xxs':
        return 'icon-sm';
      case 'xs':
        return 'icon-md';
      case 'sm':
        return 'icon-lg';
      case 'md':
        return 'icon-xl';
      case 'lg':
        return 'icon-2xl';
      case 'xl':
        return 'icon-3xl';
      case '2xl':
        return 'icon-4xl';
      default:
        return 'icon-xl';
    }
  }, [size]);

  return (
    <div 
      className={avatarClasses}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
    >
      <div className="avatar-border"></div>
      
      <div className="avatar-content">
        {type === 'image' && (
          <img
            src={imageSrc}
            alt={alt}
            className="avatar-image"
          />
        )}

        {type === 'placeholder' && (
          <span
            className={`material-symbols-outlined avatar-placeholder-icon ${iconSizeClass}`}
          >
            person
          </span>
        )}

        {type === 'text' && (
          <span className={`avatar-text ${textSizeClass}`}>
            {text}
          </span>
        )}
      </div>

      {status !== 'none' && (
        <div className={statusClasses}></div>
      )}
    </div>
  );
};