'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/sidebar.css';
import { NavItem } from '../nav-item/NavItem';
import { LogoBox, LogoType } from '../logo-box/LogoBox';
import { ButtonIcon } from '../button-icon/ButtonIcon';
import { Dropdown, DropdownMenuItem } from '../dropdown/Dropdown';

export interface MenuItem {
  label: string;
  icon: string;
  isActive?: boolean;
}

export interface FooterItem {
  label: string;
  icon: string;
}

export interface SidebarProps {
  logoType?: LogoType;
  avatarUrl?: string;
  avatarInitials?: string;
  avatarName?: string;
  avatarEmail?: string;
  menuItems?: MenuItem[];
  footerItems?: FooterItem[];
  onMenuItemClick?: (label: string) => void;
  onSearchClick?: () => void;
  onAvatarMenuClick?: (item: DropdownMenuItem) => void;
  className?: string;
  collapsed?: boolean;
}

export const Sidebar: React.FC<SidebarProps> = ({
  logoType = 'actabl',
  avatarUrl,
  avatarInitials = 'DM',
  avatarName = 'Daniel Mobara',
  avatarEmail = 'daniel@solsticehospitality.com',
  menuItems = [
    { label: 'Dashboard', icon: 'dashboard', isActive: true },
    { label: 'Analytics', icon: 'analytics', isActive: false },
    { label: 'Reports', icon: 'assessment', isActive: false },
    { label: 'Calendar', icon: 'calendar_today', isActive: false },
    { label: 'Messages', icon: 'message', isActive: false },
    { label: 'Contacts', icon: 'contacts', isActive: false },
    { label: 'Files', icon: 'folder', isActive: false },
  ],
  footerItems = [
    { label: 'Help', icon: 'help_outline' },
    { label: 'Settings', icon: 'settings' },
  ],
  onMenuItemClick,
  onSearchClick,
  onAvatarMenuClick,
  className = '',
  collapsed = false,
}) => {
  const [activeItem, setActiveItem] = React.useState(
    menuItems.find(item => item.isActive)?.label || ''
  );

  const avatarMenuItems: DropdownMenuItem[] = [
    { id: '1', label: 'View profile', icon: 'person', shortcut: '⌘P' },
    { id: '2', label: 'Account settings', icon: 'settings', shortcut: '⌘,' },
    { id: '3', label: 'Notifications', icon: 'notifications', shortcut: '⌘N' },
    { id: '4', label: 'Privacy & Security', icon: 'shield', shortcut: '⌘S' },
    { id: '5', divider: true },
    { id: '6', label: 'Billing', icon: 'credit_card', shortcut: '⌘B' },
    { id: '7', label: 'Team management', icon: 'group', shortcut: '⌘T' },
    { id: '8', label: 'Integrations', icon: 'extension', shortcut: '⌘I' },
    { id: '9', divider: true },
    { id: '10', label: 'Help center', icon: 'help', shortcut: '⌘H' },
    { id: '11', label: 'Keyboard shortcuts', icon: 'keyboard', shortcut: '?' },
    { id: '12', divider: true },
    { id: '13', label: 'Sign out', icon: 'logout', shortcut: '⇧⌘Q' },
  ];

  const handleNavItemClick = (label: string) => {
    setActiveItem(label);
    onMenuItemClick?.(label);
  };

  const handleAvatarMenuClick = (item: DropdownMenuItem) => {
    onAvatarMenuClick?.(item);
  };

  const sidebarClasses = [
    'sidebar-container',
    collapsed ? 'sidebar-collapsed' : '',
    className,
  ].filter(Boolean).join(' ');

  return (
    <div className={sidebarClasses}>
      <div className="navigation">
        {/* Gradient bar */}
        <div className="gradient-bar">
          <div className="detail-bar"></div>
        </div>

        {/* Main content */}
        <div className="sidebar-content">
          {/* Logo box */}
          <LogoBox logoType={logoType} />

          {/* Navigation section */}
          <div className="navigation-section">
            {/* Search */}
            <div className="search-container">
              <ButtonIcon
                hierarchy="secondary"
                size="sm"
                iconName="search"
                onClick={onSearchClick}
              />
            </div>

            {/* Nav items */}
            <div className="nav-items">
              {menuItems.map((item) => (
                <NavItem
                  key={item.label}
                  icon={item.icon}
                  label={item.label}
                  isActive={activeItem === item.label}
                  onClick={() => handleNavItemClick(item.label)}
                />
              ))}
            </div>
          </div>

          {/* Footer */}
          <div className="sidebar-footer">
            <div className="footer-navigation">
              {footerItems.map((item) => (
                <NavItem
                  key={item.label}
                  icon={item.icon}
                  label={item.label}
                  isActive={false}
                  onClick={() => handleNavItemClick(item.label)}
                />
              ))}
            </div>

            {/* Avatar Dropdown */}
            <Dropdown
              variant="avatar"
              size="md"
              avatarSize="md"
              avatarSrc={avatarUrl || '/assets/avatars/regionalDirector.png'}
              avatarName={avatarName}
              avatarEmail={avatarEmail}
              menuItems={avatarMenuItems}
              showIcons={true}
              onItemClick={handleAvatarMenuClick}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;