'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/tokens/bellhop-typography.css';
import '../../../../../bellhopos-styles/src/components/input-verification.css';

export type InputVerificationSize = 'sm' | 'md' | 'lg';

export interface InputVerificationProps {
  size?: InputVerificationSize;
  digits?: 4 | 6;
  label?: string;
  showLabel?: boolean;
  hintText?: string;
  showHintText?: boolean;
  error?: boolean;
  disabled?: boolean;
  required?: boolean;
  showSeparator?: boolean;
  placeholder?: string;
  width?: string;
  value?: string;
  onChange?: (value: string) => void;
  onComplete?: (value: string) => void;
  className?: string;
}

export const InputVerification: React.FC<InputVerificationProps> = ({
  size = 'md',
  digits = 4,
  label = 'Secure code',
  showLabel = true,
  hintText = 'This is a hint text to help user.',
  showHintText = true,
  error = false,
  disabled = false,
  required = false,
  showSeparator = true,
  placeholder,
  width,
  value = '',
  onChange,
  onComplete,
  className = '',
}) => {
  const [values, setValues] = React.useState<string[]>(Array(digits).fill(''));
  const inputRefs = React.useRef<(HTMLInputElement | null)[]>([]);

  // Initialize input refs array
  React.useEffect(() => {
    inputRefs.current = inputRefs.current.slice(0, digits);
  }, [digits]);

  // Sync with external value prop
  React.useEffect(() => {
    if (value !== undefined) {
      const newValues = value.split('').concat(Array(digits).fill('')).slice(0, digits);
      setValues(newValues);
    }
  }, [value, digits]);

  // Focus first input on mount
  React.useEffect(() => {
    if (!disabled && inputRefs.current[0]) {
      inputRefs.current[0].focus();
    }
  }, [disabled]);

  const updateValues = React.useCallback((newValues: string[]) => {
    setValues(newValues);
    const newValue = newValues.join('');
    onChange?.(newValue);

    // Check if all fields are filled
    if (newValues.every(val => val !== '')) {
      onComplete?.(newValue);
    }
  }, [onChange, onComplete]);

  const handleInputChange = React.useCallback((index: number, inputValue: string) => {
    // Only allow single digits
    const digit = inputValue.replace(/\D/g, '').slice(-1);

    const newValues = [...values];
    newValues[index] = digit;
    updateValues(newValues);

    // Auto-advance to next input if digit entered
    if (digit && index < digits - 1) {
      inputRefs.current[index + 1]?.focus();
    }
  }, [values, digits, updateValues]);

  const handleKeyDown = React.useCallback((index: number, event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Backspace') {
      const newValues = [...values];

      if (values[index]) {
        // Clear current field
        newValues[index] = '';
        updateValues(newValues);
      } else if (index > 0) {
        // Move to previous field and clear it
        newValues[index - 1] = '';
        updateValues(newValues);
        inputRefs.current[index - 1]?.focus();
      }
    } else if (event.key === 'ArrowLeft' && index > 0) {
      event.preventDefault();
      inputRefs.current[index - 1]?.focus();
    } else if (event.key === 'ArrowRight' && index < digits - 1) {
      event.preventDefault();
      inputRefs.current[index + 1]?.focus();
    } else if (event.key >= '0' && event.key <= '9') {
      // Replace current digit
      event.preventDefault();
      const newValues = [...values];
      newValues[index] = event.key;
      updateValues(newValues);

      // Auto-advance to next input
      if (index < digits - 1) {
        inputRefs.current[index + 1]?.focus();
      }
    }
  }, [values, digits, updateValues]);

  const handlePaste = React.useCallback((event: React.ClipboardEvent<HTMLInputElement>) => {
    event.preventDefault();

    const pastedText = event.clipboardData.getData('text');
    const pastedDigits = pastedText.replace(/\D/g, '').slice(0, digits);

    if (pastedDigits) {
      const newValues = pastedDigits.split('').concat(Array(digits).fill('')).slice(0, digits);
      updateValues(newValues);

      // Focus on the next empty input or last input
      const nextEmptyIndex = newValues.findIndex(val => val === '');
      const focusIndex = nextEmptyIndex === -1 ? digits - 1 : Math.min(nextEmptyIndex, digits - 1);
      inputRefs.current[focusIndex]?.focus();
    }
  }, [digits, updateValues]);

  const handleFocus = React.useCallback((index: number) => {
    // Select all text when input is focused
    inputRefs.current[index]?.select();
  }, []);

  const wrapperClasses = [
    'input-verification-wrapper',
    className
  ].filter(Boolean).join(' ');

  const inputClasses = [
    'verification-input',
    `size-${size}`,
    error ? 'error' : '',
  ].filter(Boolean).join(' ');

  const separatorClasses = [
    'separator',
    `size-${size}`
  ].filter(Boolean).join(' ');

  const renderInputs = () => {
    const inputs = [];

    for (let i = 0; i < digits; i++) {
      // Add separator for 6-digit codes
      if (digits === 6 && i === 3 && showSeparator) {
        inputs.push(
          <span key="separator" className={separatorClasses}>
            -
          </span>
        );
      }

      inputs.push(
        <input
          key={i}
          ref={el => inputRefs.current[i] = el}
          type="text"
          inputMode="numeric"
          pattern="[0-9]"
          maxLength={1}
          value={values[i] || ''}
          placeholder={placeholder && i < placeholder.length ? placeholder[i] : ''}
          disabled={disabled}
          className={inputClasses}
          onChange={(e) => handleInputChange(i, e.target.value)}
          onKeyDown={(e) => handleKeyDown(i, e)}
          onPaste={handlePaste}
          onFocus={() => handleFocus(i)}
          aria-label={`Digit ${i + 1} of ${digits}`}
        />
      );
    }

    return inputs;
  };

  return (
    <div className={wrapperClasses} style={{ width }}>
      {showLabel && (
        <div className="label-wrapper">
          <label className="label">{label}</label>
          {required && <span className="asterisk">*</span>}
        </div>
      )}

      <div className="input-verification-container">
        {renderInputs()}
      </div>

      {showHintText && hintText && (
        <div className={`hint-text ${error ? 'error' : ''}`}>
          {hintText}
        </div>
      )}
    </div>
  );
};

export default InputVerification;