'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/appbar.css';
import { Button } from '../button';
import { ButtonIcon } from '../button-icon/ButtonIcon';
import { PropertySwitcher, PropertyOption } from '../property-switcher/PropertySwitcher';
import { BadgeDot } from '../badge-dot/BadgeDot';
import { Breadcrumbs, BreadcrumbItem } from '../breadcrumbs/Breadcrumbs';

export interface AppbarProps {
  isMenuOpen?: boolean;
  onMenuToggle?: () => void;
  selectedProperty?: string;
  properties?: PropertyOption[];
  onPropertyChange?: (propertyName: string) => void;
  breadcrumbItems?: BreadcrumbItem[];
  onBreadcrumbClick?: (item: BreadcrumbItem) => void;
  notificationCount?: number;
  onNotificationClick?: () => void;
  onCalendarClick?: () => void;
  onSettingsClick?: () => void;
  logoSrc?: string;
  logoAlt?: string;
  className?: string;
}

export const Appbar: React.FC<AppbarProps> = ({
  isMenuOpen = false,
  onMenuToggle,
  selectedProperty = 'Solstice Hospitality Group',
  properties = [
    // Portfolio
    { id: '1', name: 'Solstice Hospitality Group', type: 'portfolio' },

    // Hawaii Region
    { id: '2', name: 'Hawaii', type: 'region' },
    { id: '3', name: 'Solstice Maui at Wailea Bay', type: 'property' },
    { id: '4', name: 'Solstice Kona Coast Retreat', type: 'property' },
    { id: '5', name: 'Solstice Hana Oceanfront', type: 'property' },

    // Sicily Region
    { id: '6', name: 'Sicily', type: 'region' },
    { id: '7', name: 'Solstice Taormina Clifftop', type: 'property' },
    { id: '8', name: 'Solstice Etna Vineyard Estate', type: 'property' },
    { id: '9', name: 'Solstice Palermo Seaside', type: 'property' },

    // Dubai Region
    { id: '10', name: 'Dubai', type: 'region' },
    { id: '11', name: 'Solstice Jumeirah Beachfront', type: 'property' },
    { id: '12', name: 'Solstice Desert Dunes Retreat', type: 'property' },
    { id: '13', name: 'Solstice Palm Island Estate', type: 'property' },

    // Thailand Region
    { id: '14', name: 'Thailand', type: 'region' },
    { id: '15', name: 'Solstice Phuket Ocean Pavilion', type: 'property' },
    { id: '16', name: 'Solstice Chiang Mai Mountain Estate', type: 'property' },
    { id: '17', name: 'Solstice Koh Samui Beachfront', type: 'property' },

    // Maldives Region
    { id: '18', name: 'Maldives', type: 'region' },
    { id: '19', name: 'Solstice North Atoll Sanctuary', type: 'property' },
    { id: '20', name: 'Solstice Coral Lagoon Retreat', type: 'property' },
    { id: '21', name: 'Solstice Azure Waters Villa', type: 'property' },

    // Brazil Region
    { id: '22', name: 'Brazil', type: 'region' },
    { id: '23', name: 'Solstice Maragogi Bay', type: 'property' },
  ],
  onPropertyChange,
  breadcrumbItems = [
    { label: 'Dashboard', path: '/dashboard' },
    { label: 'Dashboards', isActive: true },
  ],
  onBreadcrumbClick,
  notificationCount = 1,
  onNotificationClick,
  onCalendarClick,
  onSettingsClick,
  logoSrc = '/bellhopos/assets/logos/solstice.svg',
  logoAlt = 'Solstice',
  className,
}) => {
  const handleMenuToggle = () => {
    onMenuToggle?.();
  };

  const handleNotificationClick = () => {
    onNotificationClick?.();
  };

  const handleBreadcrumbClick = (item: BreadcrumbItem) => {
    if (item.path && !item.isActive) {
      onBreadcrumbClick?.(item);
    }
  };

  const handlePropertyChange = (propertyName: string) => {
    onPropertyChange?.(propertyName);
  };

  return (
    <header className={[
      'appbar',
      className
    ]
      .filter(Boolean)
      .join(' ')}>
      {/* Left Section */}
      <div className="left-section">
        {/* Menu Toggle */}
        <ButtonIcon
          hierarchy="tertiary"
          size="sm"
          iconName={isMenuOpen ? 'menu_open' : 'last_page'}
          onClick={handleMenuToggle}
        />

        {/* Logo */}
        <div className="logo">
          <img src={logoSrc} alt={logoAlt} className="logo-image" />
        </div>

        {/* Property Switcher */}
        <PropertySwitcher
          selectedProperty={selectedProperty}
          properties={properties}
          onPropertyChange={handlePropertyChange}
        />

        {/* Center Section - Breadcrumbs */}
        <Breadcrumbs
          items={breadcrumbItems}
          showHome={true}
          onItemClick={handleBreadcrumbClick}
        />
      </div>

      {/* Right Section */}
      <div className="right-section">
        {/* Calendar Icon */}
        <div className="icon-button-wrapper">
          <ButtonIcon
            hierarchy="tertiary"
            size="sm"
            iconName="calendar_today"
            onClick={onCalendarClick}
          />
          <BadgeDot
            size="sm"
            color="success"
            outline={true}
            className="icon-badge-dot"
          />
        </div>

        {/* Settings Icon */}
        <div className="icon-button-wrapper">
          <ButtonIcon
            hierarchy="tertiary"
            size="sm"
            iconName="settings"
            onClick={onSettingsClick}
          />
          <BadgeDot
            size="sm"
            color="blue"
            outline={true}
            className="icon-badge-dot"
          />
        </div>

        {/* Notifications */}
        <div className="icon-button-wrapper">
          <ButtonIcon
            hierarchy="tertiary"
            size="sm"
            iconName="notifications"
            onClick={handleNotificationClick}
          />
          {notificationCount > 0 && (
            <BadgeDot
              size="sm"
              color="error"
              outline={true}
              className="icon-badge-dot"
            />
          )}
        </div>
      </div>
    </header>
  );
};

export default Appbar;