'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/page-navigation.css';

export interface PageNavigationSingleLevelProps {
  label: string;
  icon?: string;
  badge?: string | number;
  isActive?: boolean;
  onItemClick: () => void;
  className?: string;
}

export const PageNavigationSingleLevel: React.FC<PageNavigationSingleLevelProps> = ({
  label,
  icon = 'radio_button_unchecked',
  badge,
  isActive = false,
  onItemClick,
  className = '',
}) => {
  const itemClasses = [
    'page-navigation-single-level',
    isActive ? 'active' : '',
    className,
  ].filter(Boolean).join(' ');

  const handleClick = () => {
    onItemClick();
  };

  return (
    <div className={itemClasses} onClick={handleClick}>
      <div className="page-navigation-item-content">
        <span className="page-navigation-item-icon material-symbols-outlined">
          {icon}
        </span>
        <span className="page-navigation-item-label">{label}</span>
        {badge && (
          <span className="page-navigation-item-badge">
            {badge}
          </span>
        )}
      </div>
    </div>
  );
};