'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/checkbox.css';

export type CheckboxSize = 'sm' | 'md';

export interface CheckboxProps {
  size?: CheckboxSize;
  disabled?: boolean;
  indeterminate?: boolean;
  checked?: boolean;
  defaultChecked?: boolean;
  id?: string;
  className?: string;
  onChange?: (checked: boolean) => void;
}

export const Checkbox: React.FC<CheckboxProps> = ({
  size = 'md',
  disabled = false,
  indeterminate = false,
  checked,
  defaultChecked = false,
  id,
  className = '',
  onChange,
}) => {
  const [internalChecked, setInternalChecked] = React.useState(defaultChecked);
  const [isFocused, setIsFocused] = React.useState(false);
  const [isHovered, setIsHovered] = React.useState(false);

  // Determine if controlled or uncontrolled
  const isControlled = checked !== undefined;
  const isChecked = isControlled ? checked : internalChecked;

  const checkboxClasses = React.useMemo(() => {
    const classes = ['checkbox', `checkbox-${size}`];

    if (isChecked || indeterminate) {
      classes.push('checkbox-checked');
    }

    if (disabled) {
      classes.push('checkbox-disabled');
    }

    if (isFocused && !disabled) {
      classes.push('checkbox-focused');
    }

    if (isHovered && !disabled) {
      classes.push('checkbox-hover');
    }

    if (className) {
      classes.push(className);
    }

    return classes.join(' ');
  }, [size, isChecked, indeterminate, disabled, isFocused, isHovered, className]);

  const handleClick = React.useCallback(() => {
    if (disabled) return;

    const newChecked = indeterminate ? false : !isChecked;

    // Always update internal state for uncontrolled components
    if (!isControlled) {
      setInternalChecked(newChecked);
    }

    // Always call onChange if provided
    onChange?.(newChecked);
  }, [disabled, indeterminate, isChecked, isControlled, onChange]);

  const handleFocus = React.useCallback(() => {
    setIsFocused(true);
  }, []);

  const handleBlur = React.useCallback(() => {
    setIsFocused(false);
  }, []);

  const handleMouseEnter = React.useCallback(() => {
    setIsHovered(true);
  }, []);

  const handleMouseLeave = React.useCallback(() => {
    setIsHovered(false);
  }, []);

  const handleKeyDown = React.useCallback((event: React.KeyboardEvent) => {
    if (event.key === ' ' || event.key === 'Enter') {
      event.preventDefault();
      handleClick();
    }
  }, [handleClick]);

  return (
    <div
      id={id}
      className={checkboxClasses}
      onClick={handleClick}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onFocus={handleFocus}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      tabIndex={disabled ? -1 : 0}
      role="checkbox"
      aria-checked={indeterminate ? 'mixed' : isChecked}
      aria-disabled={disabled}
    >
      {isChecked && !indeterminate && (
        <span className="material-symbols-outlined checkbox-icon check-icon">
          check
        </span>
      )}
      {indeterminate && (
        <span className="material-symbols-outlined checkbox-icon minus-icon">
          remove
        </span>
      )}
    </div>
  );
};