'use client';

import * as React from 'react';
import { Avatar, AvatarSize, AvatarType, AvatarStatus } from '../avatar/Avatar';
import { AvatarAdd } from '../avatar-add/AvatarAdd';
import { Tooltip } from '../tooltip/Tooltip';
import './AvatarStacked.css';

export interface AvatarData {
  type: AvatarType;
  imagePath?: string;
  text?: string;
  status?: AvatarStatus;
  tooltipText?: string;
}

export interface AvatarStackedProps {
  size?: AvatarSize;
  avatars?: AvatarData[];
  maxVisible?: number;
  showAddButton?: boolean;
}

export const AvatarStacked: React.FC<AvatarStackedProps> = ({
  size = 'md',
  avatars = [],
  maxVisible = 10,
  showAddButton = true,
}) => {
  const [hoveredIndex, setHoveredIndex] = React.useState(-1);

  const visibleAvatars = React.useMemo(() => {
    return avatars.slice(0, maxVisible - 1);
  }, [avatars, maxVisible]);

  const remainingCount = React.useMemo(() => {
    const remaining = avatars.length - (maxVisible - 1);
    return remaining > 0 ? remaining : 0;
  }, [avatars.length, maxVisible]);

  const showCountAvatar = remainingCount > 0;

  const avatarStackedClasses = React.useMemo(() => {
    return `avatar-stacked avatar-stacked-${size}`;
  }, [size]);

  return (
    <div className={avatarStackedClasses}>
      {/* Visible Avatars */}
      {visibleAvatars.map((avatar, index) => (
        <div key={index} className="avatar-with-tooltip">
          <Avatar
            size={size}
            type={avatar.type}
            imageSrc={avatar.imagePath ? `/assets/avatars/${avatar.imagePath}` : undefined}
            text={avatar.text}
            status={avatar.status || 'none'}
            onMouseEnter={() => setHoveredIndex(index)}
            onMouseLeave={() => setHoveredIndex(-1)}
          />
          {avatar.tooltipText && (
            <Tooltip
              text={avatar.tooltipText}
              position="top"
              visible={hoveredIndex === index}
              style={{ position: 'absolute', top: 0, left: '50%' }}
            />
          )}
        </div>
      ))}

      {/* Count Avatar */}
      {showCountAvatar && (
        <Avatar
          size={size}
          type="text"
          text={`+${remainingCount}`}
          status="none"
        />
      )}

      {/* Add Button */}
      {showAddButton && (
        <AvatarAdd
          size={size}
          showTooltip={true}
          tooltipText="Add member"
        />
      )}
    </div>
  );
};