'use client';

import * as React from 'react';
import { Button } from '../button/Button';
import { Avatar } from '../avatar/Avatar';
import { DropdownMenu } from '../dropdown-menu/DropdownMenu';
import type { DropdownMenuItem, DropdownMenuHeader } from '../dropdown-menu/DropdownMenu';
import '../../../../../bellhopos-styles/src/components/dropdown.css';
import '../../../../../bellhopos-styles/src/tokens/bellhop-animations.css';

// Re-export for backward compatibility
export { DropdownMenuItem, DropdownMenuHeader };

export type DropdownSize = 'sm' | 'md';
export type DropdownState = 'default' | 'focus' | 'disabled';
export type DropdownVariant =
  | 'outlined'
  | 'ghost'
  | 'icon-only-outlined'
  | 'icon-only-ghost'
  | 'avatar';

export type DropdownPosition =
  | 'bottom-right'
  | 'bottom-left'
  | 'top-right'
  | 'top-left'
  | 'bottom-center'
  | 'top-center'
  | 'left-top'
  | 'left-center'
  | 'left-bottom'
  | 'right-top'
  | 'right-center'
  | 'right-bottom';

export interface DropdownProps {
  size?: DropdownSize;
  state?: DropdownState;
  variant?: DropdownVariant;
  label?: string;
  iconName?: string;
  disabled?: boolean;
  menuItems?: DropdownMenuItem[];
  header?: DropdownMenuHeader;
  avatarSrc?: string;
  avatarAlt?: string;
  avatarSize?: 'sm' | 'md' | 'lg';
  avatarName?: string;
  avatarEmail?: string;
  showIcons?: boolean;
  forcePosition?: string;
  onItemClick?: (item: DropdownMenuItem) => void;
}

export const Dropdown: React.FC<DropdownProps> = ({
  size = 'md',
  state = 'default',
  variant = 'outlined',
  label = 'Options',
  iconName = 'more_vert',
  disabled = false,
  menuItems = [],
  header,
  avatarSrc = '',
  avatarAlt = 'Avatar',
  avatarSize = 'md',
  avatarName,
  avatarEmail,
  showIcons = true,
  forcePosition,
  onItemClick,
}) => {
  const [isOpen, setIsOpen] = React.useState(false);
  const dropdownRef = React.useRef<HTMLDivElement>(null);

  // Click outside handler
  React.useEffect(() => {
    if (!isOpen) return;

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  const toggleDropdown = () => {
    if (disabled) return;
    setIsOpen(!isOpen);
  };

  const handleMenuItemClick = (item: DropdownMenuItem) => {
    if (item.disabled) return;
    onItemClick?.(item);
    setIsOpen(false);
  };

  // Compute button state
  const buttonState = disabled || state === 'disabled' 
    ? 'disabled' 
    : (isOpen || state === 'focus') 
      ? 'focus' 
      : 'default';

  // Determine what to render
  const isIconOnly = variant === 'icon-only-outlined' || variant === 'icon-only-ghost';
  const showAvatar = variant === 'avatar';
  const showButton = !showAvatar;

  // Position and header - always position underneath the element
  const positionClass = `dropdown-menu-bottom-right`;
  const menuHeader = showAvatar ? {
    avatarGroup: true,
    avatarSrc,
    name: avatarName,
    email: avatarEmail,
  } : header;

  return (
    <div className="dropdown-container" ref={dropdownRef}>
      {/* Button variants */}
      {showButton && (
        <div className={isOpen ? 'dropdown-open' : ''}>
          <Button
            hierarchy={variant === 'ghost' || variant === 'icon-only-ghost' ? 'tertiary' : 'secondary'}
            icon={isIconOnly ? 'only' : 'trailing'}
            size={size}
            label={isIconOnly ? '' : label}
            iconName={isIconOnly ? iconName : 'expand_more'}
            state={buttonState}
            disabled={disabled}
            onClick={toggleDropdown}
          />
        </div>
      )}

      {/* Avatar variant */}
      {showAvatar && (
        <div
          className={`dropdown-avatar ${isOpen ? 'dropdown-avatar-focus' : ''} ${disabled ? 'dropdown-avatar-disabled' : ''}`}
          onClick={!disabled ? toggleDropdown : undefined}
        >
          <Avatar
            type="image"
            size={avatarSize}
            imageSrc={avatarSrc}
            alt={avatarAlt}
          />
        </div>
      )}

      {/* Menu */}
      <DropdownMenu
        visible={isOpen}
        showIcons={showIcons}
        menuItems={menuItems}
        header={menuHeader}
        className={positionClass}
        onItemClick={handleMenuItemClick}
      />
    </div>
  );
};