'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/date-range-picker.css';
import { Button } from '../button/Button';
import { InputText } from '../input-text/InputText';
import { PickerMenu } from '../picker-menu/PickerMenu';
import { DateRangePickerContent, SelectedDateRange } from '../date-range-picker-content/DateRangePickerContent';
import { SelectedDate, DisabledDate } from '../date-picker-content/DatePickerContent';

export type DateRangePickerVariant = 'dropdown-outlined' | 'dropdown-ghost' | 'input';

export interface DateRangePickerProps {
  variant?: DateRangePickerVariant;
  minYear?: number;
  maxYear?: number;
  disabled?: boolean;
  disabledDates?: DisabledDate[];
  startLabel?: string;
  endLabel?: string;
  startPlaceholder?: string;
  endPlaceholder?: string;
  inputWidth?: string;
  showLabel?: boolean;
  showFooter?: boolean;
  showOtherMonthDays?: boolean;
  value?: SelectedDateRange | null;
  onChange?: (value: SelectedDateRange | null) => void;
  onDateRangeSelect?: (value: SelectedDateRange | null) => void;
}

export const DateRangePicker: React.FC<DateRangePickerProps> = ({
  variant = 'input',
  minYear = 1998,
  maxYear = 2060,
  disabled = false,
  disabledDates = [],
  startLabel = 'Start Date',
  endLabel = 'End Date',
  startPlaceholder = 'Choose start date',
  endPlaceholder = 'Choose end date',
  inputWidth = '200px',
  showLabel = true,
  showFooter = true,
  showOtherMonthDays = false,
  value,
  onChange,
  onDateRangeSelect,
}) => {
  const [selectedValue, setSelectedValue] = React.useState<SelectedDateRange | null>(value || null);
  const [tempSelection, setTempSelection] = React.useState<SelectedDateRange | null>(null);
  const [isMenuOpen, setIsMenuOpen] = React.useState(false);
  const [isMenuClosing, setIsMenuClosing] = React.useState(false);
  const containerRef = React.useRef<HTMLDivElement>(null);

  // Sync with external value prop
  React.useEffect(() => {
    if (value !== undefined) {
      setSelectedValue(value);
    }
  }, [value]);

  const formatDate = (date: SelectedDate | null): string => {
    if (!date) return '';
    // Format as MM/DD/YYYY
    const month = (date.month + 1).toString().padStart(2, '0');
    const day = date.day.toString().padStart(2, '0');
    return `${month}/${day}/${date.year}`;
  };

  const getButtonLabel = (): string => {
    if (!selectedValue || !selectedValue.startDate) return 'Select date range';

    const startStr = formatDate(selectedValue.startDate);
    const endStr = selectedValue.endDate ? formatDate(selectedValue.endDate) : '';

    if (endStr) {
      return `${startStr} - ${endStr}`;
    }
    return startStr;
  };

  const handleTriggerClick = (): void => {
    if (disabled) return;
    if (!isMenuOpen && showFooter) {
      setTempSelection(selectedValue);
    }
    setIsMenuOpen(!isMenuOpen);
  };

  const handleDateRangeSelect = (range: SelectedDateRange | null): void => {
    if (showFooter && range) {
      // With footer: just update temp selection, don't apply yet
      setTempSelection(range);
    } else {
      // Without footer: immediately apply and close
      setSelectedValue(range);
      onChange?.(range);
      onDateRangeSelect?.(range);
      if (!showFooter) {
        closeMenu();
      }
    }
  };

  const handleMenuCancel = (): void => {
    setTempSelection(null);
    closeMenu();
  };

  const handleMenuApply = (): void => {
    if (tempSelection) {
      setSelectedValue(tempSelection);
      onChange?.(tempSelection);
      onDateRangeSelect?.(tempSelection);
      setTempSelection(null);
    }
    closeMenu();
  };

  const closeMenu = (): void => {
    setIsMenuClosing(true);
    setTimeout(() => {
      setIsMenuOpen(false);
      setIsMenuClosing(false);
    }, 150);
  };

  const handleBackdropClick = (): void => {
    handleMenuCancel();
  };

  return (
    <>
      <div className="date-range-picker-container" ref={containerRef}>
        {/* Dropdown Outlined Variant */}
        {variant === 'dropdown-outlined' && (
          <div className="date-range-picker-trigger" onClick={handleTriggerClick}>
            <Button
              hierarchy="secondary"
              type="outline"
              size="sm"
              icon="trailing"
              label={getButtonLabel()}
              iconName="expand_more"
              disabled={disabled}
            />
          </div>
        )}

        {/* Dropdown Ghost Variant */}
        {variant === 'dropdown-ghost' && (
          <div className="date-range-picker-trigger" onClick={handleTriggerClick}>
            <Button
              hierarchy="tertiary"
              type="ghost"
              size="sm"
              icon="trailing"
              label={getButtonLabel()}
              iconName="expand_more"
              disabled={disabled}
            />
          </div>
        )}

        {/* Input Variant */}
        {variant === 'input' && (
          <div className="date-range-picker-trigger">
            <div className="date-range-inputs" onClick={handleTriggerClick}>
              <InputText
                label={startLabel}
                placeholder={startPlaceholder}
                value={formatDate(selectedValue?.startDate || null)}
                disabled={disabled}
                showTrailingIcon={true}
                trailingIcon="calendar_today"
                showHelpIcon={false}
                showHintText={false}
                showLabel={showLabel}
                width={inputWidth}
                readOnly
              />
              <InputText
                label={endLabel}
                placeholder={endPlaceholder}
                value={formatDate(selectedValue?.endDate || null)}
                disabled={disabled}
                showTrailingIcon={true}
                trailingIcon="calendar_today"
                showHelpIcon={false}
                showHintText={false}
                showLabel={showLabel}
                width={inputWidth}
                readOnly
              />
            </div>
          </div>
        )}

        {/* Date Range Picker Menu */}
        <div className="date-range-picker-menu-container">
          <PickerMenu
            visible={isMenuOpen}
            showFooter={showFooter}
            disableApply={showFooter && (!tempSelection?.startDate || !tempSelection?.endDate)}
            onCancel={handleMenuCancel}
            onApply={handleMenuApply}
          >
            <DateRangePickerContent
              minYear={minYear}
              maxYear={maxYear}
              disabled={disabled}
              disabledDates={disabledDates}
              showOtherMonthDays={showOtherMonthDays}
              value={tempSelection || selectedValue}
              onChange={handleDateRangeSelect}
              onDateRangeSelect={handleDateRangeSelect}
            />
          </PickerMenu>
        </div>
      </div>

      {/* Backdrop */}
      {(isMenuOpen || isMenuClosing) && (
        <div className="date-range-picker-backdrop" onClick={handleBackdropClick}></div>
      )}
    </>
  );
};

export default DateRangePicker;