'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/date-picker-content.css';
import { Button } from '../button/Button';
import { MonthPickerContent, MonthYear } from '../month-picker-content/MonthPickerContent';

export interface SelectedDate {
  year: number;
  month: number; // 0-11
  day: number; // 1-31
}

export interface DisabledDate {
  year: number;
  month: number;
  day: number;
}

interface CalendarCell {
  day: number;
  isCurrentMonth: boolean;
  isToday: boolean;
  isSelected: boolean;
  isDisabled: boolean;
  isRangeStart: boolean;
  isRangeEnd: boolean;
  isInRange: boolean;
  date: Date;
}

export interface DatePickerContentProps {
  minYear?: number;
  maxYear?: number;
  disabled?: boolean;
  disabledDates?: DisabledDate[];
  scrollable?: boolean;
  animationClass?: string;
  initialMonth?: number | null;
  initialYear?: number | null;
  displayMonth?: number;
  displayYear?: number;
  rangeStart?: SelectedDate | null;
  rangeEnd?: SelectedDate | null;
  value?: SelectedDate | null;
  showOtherMonthDays?: boolean;
  isDateInRange?: (date: SelectedDate) => boolean;
  isDateSelected?: (date: SelectedDate) => boolean;
  isDateRangeStart?: (date: SelectedDate) => boolean;
  isDateRangeEnd?: (date: SelectedDate) => boolean;
  onChange?: (value: SelectedDate | null) => void;
  onDateSelect?: (date: SelectedDate | null) => void;
  onMonthChange?: (month: { month: number; year: number }) => void;
  onMonthYearChange?: (month: number, year: number) => void;
}

export const DatePickerContent: React.FC<DatePickerContentProps> = React.memo(({
  minYear = 1998,
  maxYear = 2060,
  disabled = false,
  disabledDates = [],
  scrollable = true,
  animationClass = 'animate-dropdown-enter',
  initialMonth = null,
  initialYear = null,
  displayMonth,
  displayYear,
  rangeStart = null,
  rangeEnd = null,
  value,
  showOtherMonthDays = true,
  isDateInRange,
  isDateSelected,
  isDateRangeStart,
  isDateRangeEnd,
  onChange,
  onDateSelect,
  onMonthChange,
  onMonthYearChange,
}) => {
  const today = new Date();

  const selectedDateRef = React.useRef<SelectedDate | null>(value || null);
  const [, forceUpdate] = React.useState({});
  const [currentMonth, setCurrentMonth] = React.useState(
    displayMonth !== undefined ? displayMonth : (initialMonth !== null ? initialMonth : today.getMonth())
  );
  const [currentYear, setCurrentYear] = React.useState(
    displayYear !== undefined ? displayYear : (initialYear !== null ? initialYear : today.getFullYear())
  );
  const [isMonthDropdownOpen, setIsMonthDropdownOpen] = React.useState(false);
  const [isMonthDropdownClosing, setIsMonthDropdownClosing] = React.useState(false);

  const monthNames = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December',
  ];
  const dayNames = ['Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa', 'Su'];

  // Sync with value prop only when actually different
  React.useEffect(() => {
    if (value !== undefined) {
      const current = selectedDateRef.current;
      const isDifferent = !current !== !value ||
        (current && value && (
          current.year !== value.year ||
          current.month !== value.month ||
          current.day !== value.day
        ));

      if (isDifferent) {
        selectedDateRef.current = value;
        // Only auto-navigate to value's month if we're not in external control mode
        if (value && displayMonth === undefined && displayYear === undefined) {
          setCurrentMonth(value.month);
          setCurrentYear(value.year);
        }
        forceUpdate({});
      }
    }
  }, [value]);

  // Sync with initial values
  React.useEffect(() => {
    if (initialMonth !== null) setCurrentMonth(initialMonth);
    if (initialYear !== null) setCurrentYear(initialYear);
  }, [initialMonth, initialYear]);

  // Sync with display month/year for date range picker
  React.useEffect(() => {
    if (displayMonth !== undefined) setCurrentMonth(displayMonth);
    if (displayYear !== undefined) setCurrentYear(displayYear);
  }, [displayMonth, displayYear]);

  const isInRangeMode = React.useMemo(() => {
    return rangeStart !== null || rangeEnd !== null;
  }, [rangeStart, rangeEnd]);

  const calendarCells = React.useMemo(() => {
    const cells: CalendarCell[] = [];
    const firstDay = new Date(currentYear, currentMonth, 1);
    const lastDay = new Date(currentYear, currentMonth + 1, 0);

    // Helper functions defined inside useMemo to avoid dependency issues
    const isSameDay = (date1: Date, date2: Date): boolean => {
      return (
        date1.getFullYear() === date2.getFullYear() &&
        date1.getMonth() === date2.getMonth() &&
        date1.getDate() === date2.getDate()
      );
    };

    const isDateDisabled = (date: Date): boolean => {
      if (!disabledDates || !Array.isArray(disabledDates)) {
        return false;
      }
      const year = date.getFullYear();
      const month = date.getMonth();
      const day = date.getDate();
      return disabledDates.some(
        (disabled) =>
          disabled.year === year &&
          disabled.month === month &&
          disabled.day === day
      );
    };

    // Get the day of the week for the first day (0 = Sunday, 6 = Saturday)
    let firstDayOfWeek = firstDay.getDay();
    // Convert to Monday start (0 = Monday, 6 = Sunday)
    firstDayOfWeek = firstDayOfWeek === 0 ? 6 : firstDayOfWeek - 1;

    // Add empty cells for days before the first of the month
    if (showOtherMonthDays) {
      for (let i = 0; i < firstDayOfWeek; i++) {
        const prevMonthLastDay = new Date(currentYear, currentMonth, -i);
        cells.unshift({
          day: prevMonthLastDay.getDate(),
          isCurrentMonth: false,
          isToday: false,
          isSelected: false,
          isDisabled: true,
          isRangeStart: false,
          isRangeEnd: false,
          isInRange: false,
          date: prevMonthLastDay,
        });
      }
    } else {
      // Add empty cells without dates
      for (let i = 0; i < firstDayOfWeek; i++) {
        cells.unshift({
          day: 0, // Use 0 to indicate empty cell
          isCurrentMonth: false,
          isToday: false,
          isSelected: false,
          isDisabled: true,
          isRangeStart: false,
          isRangeEnd: false,
          isInRange: false,
          date: new Date(currentYear, currentMonth, -i),
        });
      }
    }

    // Add cells for current month
    for (let day = 1; day <= lastDay.getDate(); day++) {
      const date = new Date(currentYear, currentMonth, day);

      let isRangeStart = false;
      let isRangeEnd = false;
      let isInRange = false;

      // Check for range start using callback
      if (isDateRangeStart) {
        const cellDate = { year: date.getFullYear(), month: date.getMonth(), day: date.getDate() };
        isRangeStart = isDateRangeStart(cellDate);
      } else if (rangeStart && rangeStart.year !== undefined && rangeStart.month !== undefined && rangeStart.day !== undefined) {
        const start = new Date(rangeStart.year, rangeStart.month, rangeStart.day);
        isRangeStart = date.getTime() === start.getTime();
      }

      // Check for range end using callback
      if (isDateRangeEnd) {
        const cellDate = { year: date.getFullYear(), month: date.getMonth(), day: date.getDate() };
        isRangeEnd = isDateRangeEnd(cellDate);
      } else if (rangeStart && rangeEnd &&
          rangeStart.year !== undefined && rangeStart.month !== undefined && rangeStart.day !== undefined &&
          rangeEnd.year !== undefined && rangeEnd.month !== undefined && rangeEnd.day !== undefined) {
        const start = new Date(rangeStart.year, rangeStart.month, rangeStart.day);
        const end = new Date(rangeEnd.year, rangeEnd.month, rangeEnd.day);
        isRangeEnd = date.getTime() === end.getTime();
        isInRange = date > start && date < end;
      }

      cells.push({
        day,
        isCurrentMonth: true,
        isToday: isSameDay(date, today),
        isSelected: false, // We'll update this after calendar generation
        isDisabled: isDateDisabled(date),
        isRangeStart,
        isRangeEnd,
        isInRange,
        date,
      });
    }

    // Add next month days to fill the grid (only if showing other month days)
    if (showOtherMonthDays) {
      const totalCells = cells.length;
      const remainingCells = 42 - totalCells; // 6 weeks × 7 days = 42 cells max

      for (let day = 1; day <= remainingCells; day++) {
        const nextMonthDay = new Date(currentYear, currentMonth + 1, day);
        cells.push({
          day: nextMonthDay.getDate(),
          isCurrentMonth: false,
          isToday: false,
          isSelected: false,
          isDisabled: true,
          isRangeStart: false,
          isRangeEnd: false,
          isInRange: false,
          date: nextMonthDay,
        });

        // Stop when we have a complete week (7 days per row)
        if (cells.length % 7 === 0) break;
      }
    }

    return cells;
  }, [currentMonth, currentYear, rangeStart, rangeEnd, disabledDates, isInRangeMode, showOtherMonthDays]);


  const handleCellClick = (cell: CalendarCell) => {
    if (cell.isDisabled || disabled || !cell.isCurrentMonth) {
      return;
    }

    const newSelectedDate = {
      year: cell.date.getFullYear(),
      month: cell.date.getMonth(),
      day: cell.date.getDate(),
    };

    // If we're in range mode, let the parent handle it
    if (rangeStart !== null || rangeEnd !== null) {
      onDateSelect?.(newSelectedDate);
      return;
    }

    // In regular mode, manage internal state
    const currentSelected = selectedDateRef.current;
    const isCurrentlySelected = currentSelected &&
      currentSelected.year === newSelectedDate.year &&
      currentSelected.month === newSelectedDate.month &&
      currentSelected.day === newSelectedDate.day;

    if (isCurrentlySelected) {
      // Deselect
      selectedDateRef.current = null;
      onChange?.(null);
      onDateSelect?.(null);
    } else {
      // Select
      selectedDateRef.current = newSelectedDate;
      onChange?.(newSelectedDate);
      onDateSelect?.(newSelectedDate);
    }

    // Force re-render of cells only
    forceUpdate({});
  };


  const handleMonthDropdownToggle = () => {
    if (isMonthDropdownOpen) {
      closeMonthDropdown();
    } else {
      setIsMonthDropdownOpen(true);
    }
  };

  const closeMonthDropdown = () => {
    setIsMonthDropdownClosing(true);
    setTimeout(() => {
      setIsMonthDropdownOpen(false);
      setIsMonthDropdownClosing(false);
    }, 150);
  };

  const handleMonthYearSelect = (monthYear: MonthYear) => {
    closeMonthDropdown();

    // Delay the calendar update until after the dropdown animation completes
    setTimeout(() => {
      setCurrentMonth(monthYear.month);
      setCurrentYear(monthYear.year);
      onMonthChange?.({ month: monthYear.month, year: monthYear.year });
      onMonthYearChange?.(monthYear.month, monthYear.year);
    }, 100); // Shorter delay for more responsive feel
  };

  const handlePreviousMonth = () => {
    if (disabled) return;

    let newMonth = currentMonth - 1;
    let newYear = currentYear;

    if (newMonth < 0) {
      newMonth = 11;
      newYear = currentYear - 1;
    }

    // Check if new date is within allowed range
    if (newYear >= minYear) {
      setCurrentMonth(newMonth);
      setCurrentYear(newYear);
      onMonthChange?.({ month: newMonth, year: newYear });
      onMonthYearChange?.(newMonth, newYear);
    }
  };

  const handleNextMonth = () => {
    if (disabled) return;

    let newMonth = currentMonth + 1;
    let newYear = currentYear;

    if (newMonth > 11) {
      newMonth = 0;
      newYear = currentYear + 1;
    }

    // Check if new date is within allowed range
    if (newYear <= maxYear) {
      setCurrentMonth(newMonth);
      setCurrentYear(newYear);
      onMonthChange?.({ month: newMonth, year: newYear });
      onMonthYearChange?.(newMonth, newYear);
    }
  };


  const getCellClass = (cell: CalendarCell): string => {
    const classes = ['calendar-cell'];
    if (!cell.isCurrentMonth) classes.push('other-month');
    if (cell.isToday) classes.push('today');
    if (cell.isRangeStart) classes.push('range-start');
    if (cell.isRangeEnd) classes.push('range-end');
    if (cell.isInRange) classes.push('in-range');

    // Use external isDateSelected function if provided, otherwise use internal logic
    const cellDate = { year: cell.date.getFullYear(), month: cell.date.getMonth(), day: cell.date.getDate() };
    let isSelected = false;

    if (isDateSelected && cell.isCurrentMonth) {
      isSelected = isDateSelected(cellDate);
    } else if (!isInRangeMode && selectedDateRef.current && cell.isCurrentMonth) {
      isSelected = cell.date.getFullYear() === selectedDateRef.current.year &&
        cell.date.getMonth() === selectedDateRef.current.month &&
        cell.date.getDate() === selectedDateRef.current.day;
    }

    // Check if date is in range using external function if provided
    if (isDateInRange && cell.isCurrentMonth && isDateInRange(cellDate)) {
      classes.push('in-range');
    }

    if (isSelected) classes.push('selected');
    if (cell.isDisabled) classes.push('disabled');
    else if (cell.isCurrentMonth) classes.push('selectable');
    return classes.join(' ');
  };

  const currentMonthYear = `${monthNames[currentMonth]} ${currentYear}`;

  return (
    <div className="date-picker-content">
      {/* Month Navigation */}
      <div className="month-navigation">
        <Button
          hierarchy="tertiary"
          type="ghost"
          size="sm"
          icon="only"
          iconName="chevron_left"
          onClick={handlePreviousMonth}
          disabled={disabled || (currentYear === minYear && currentMonth === 0)}
          className="nav-button"
        />

        <Button
          hierarchy="tertiary"
          type="ghost"
          size="sm"
          label={currentMonthYear}
          icon="trailing"
          iconName="expand_more"
          onClick={handleMonthDropdownToggle}
          className={`${isMonthDropdownOpen ? 'dropdown-open' : ''}`}
        />

        <Button
          hierarchy="tertiary"
          type="ghost"
          size="sm"
          icon="only"
          iconName="chevron_right"
          onClick={handleNextMonth}
          disabled={disabled || (currentYear === maxYear && currentMonth === 11)}
          className="nav-button"
        />

      </div>

      {/* Calendar Grid or Month Picker */}
      {!isMonthDropdownOpen && (
        <div className="calendar-grid">
          {/* Day Names Header */}
          <div className="day-names">
            {dayNames.map((dayName) => (
              <div key={dayName} className="day-name">
                {dayName}
              </div>
            ))}
          </div>

          {/* Date Cells */}
          <div className="date-cells">
            {calendarCells.map((cell, index) => (
              <div
                key={index}
                className={getCellClass(cell)}
                onClick={() => handleCellClick(cell)}
              >
                <span className="date-number">{cell.day === 0 ? '' : cell.day}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Month Picker Content */}
      {(isMonthDropdownOpen || isMonthDropdownClosing) && (
        <div
          className={`month-picker-inline ${
            isMonthDropdownClosing ? 'animate-fade-out' : ''
          }`}
        >
          <MonthPickerContent
            scrollable={true}
            height="275px"
            selectedMonth={currentMonth}
            selectedYear={currentYear}
            onChange={handleMonthYearSelect}
            minYear={minYear}
            maxYear={maxYear}
          />
        </div>
      )}
    </div>
  );
});

export default DatePickerContent;