import React from 'react';
import '../../../../../bellhopos-styles/src/components/chart-tooltip.css';

export interface TooltipItem {
  color?: string;
  label?: string;
  value: string;
}

export interface ChartTooltipProps {
  visible?: boolean;
  x?: number;
  y?: number;
  header?: string;
  items?: TooltipItem[];
  total?: string;
  showTotal?: boolean;
  storybookMode?: boolean;
}

export const ChartTooltip: React.FC<ChartTooltipProps> = ({
  visible = false,
  x = 0,
  y = 0,
  header = '',
  items = [],
  total = '',
  showTotal = false,
  storybookMode = false,
}) => {
  return (
    <div
      className={`chart-tooltip ${visible ? 'visible' : ''} ${storybookMode ? 'storybook-mode' : ''}`}
      style={{
        left: `${x}px`,
        top: `${y}px`,
      }}
    >
      <div className="tooltip-content">
        <div className="tooltip-items">
          {items.map((item, index) => (
            <div key={index} className="tooltip-item">
              {item.color && (
                <span
                  className="tooltip-dot"
                  style={{ backgroundColor: item.color }}
                />
              )}
              {item.label && (
                <span className="tooltip-label">{item.label}:</span>
              )}
              <span className="tooltip-value">{item.value}</span>
            </div>
          ))}
        </div>
        {showTotal && total && (
          <div className="tooltip-total">
            <span className="total-label">Total:</span>
            <span className="total-value">{total}</span>
          </div>
        )}
      </div>
    </div>
  );
};