'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/autocomplete-menu.css';
import '../../../../../bellhopos-styles/src/tokens/bellhop-animations.css';

export interface AutocompleteMenuItem {
  id: string;
  label: string;
  disabled?: boolean;
  selected?: boolean;
}

export interface AutocompleteMenuProps {
  menuItems?: AutocompleteMenuItem[];
  visible?: boolean;
  selectedIndex?: number;
  maxHeight?: number;
  multiSelect?: boolean;
  searchQuery?: string;
  onItemClick?: (item: AutocompleteMenuItem) => void;
  onItemHover?: (index: number) => void;
}

export const AutocompleteMenu: React.FC<AutocompleteMenuProps> = ({
  menuItems = [],
  visible = false,
  selectedIndex = -1,
  maxHeight = 280,
  multiSelect = false,
  searchQuery = '',
  onItemClick,
  onItemHover,
}) => {
  const [isAnimating, setIsAnimating] = React.useState(false);
  const [shouldRender, setShouldRender] = React.useState(visible);
  const [items, setItems] = React.useState<AutocompleteMenuItem[]>(menuItems);

  React.useEffect(() => {
    setItems(menuItems);
  }, [menuItems]);

  React.useEffect(() => {
    if (visible) {
      setShouldRender(true);
      setIsAnimating(false);
    } else {
      setIsAnimating(true);
      const timer = setTimeout(() => {
        setShouldRender(false);
        setIsAnimating(false);
      }, 150); // Match exit animation duration
      return () => clearTimeout(timer);
    }
  }, [visible]);

  const getMenuClasses = React.useCallback(() => {
    const classes = ['autocomplete-menu'];
    if (isAnimating && !visible) {
      classes.push('animate-dropdown-exit');
    } else if (visible) {
      classes.push('animate-dropdown-enter');
    }
    return classes.join(' ');
  }, [isAnimating, visible]);

  const getItemClasses = React.useCallback((index: number, item: AutocompleteMenuItem) => {
    const classes = ['autocomplete-item'];
    if (item.disabled) {
      classes.push('disabled');
    }
    if (index === selectedIndex) {
      classes.push('selected');
    }
    return classes.join(' ');
  }, [selectedIndex]);

  const getHighlightedText = React.useCallback((text: string) => {
    if (!searchQuery || searchQuery.length < 3) {
      return text;
    }

    const regex = new RegExp(`(${searchQuery})`, 'gi');
    const parts = text.split(regex);
    
    return (
      <>
        {parts.map((part, index) =>
          regex.test(part) ? (
            <span key={index} className="highlight">{part}</span>
          ) : (
            <React.Fragment key={index}>{part}</React.Fragment>
          )
        )}
      </>
    );
  }, [searchQuery]);

  const handleItemClick = React.useCallback((item: AutocompleteMenuItem, index: number) => {
    if (!item.disabled) {
      if (multiSelect) {
        // Toggle selection in multi-select mode
        const updatedItems = items.map(i => 
          i.id === item.id ? { ...i, selected: !i.selected } : i
        );
        setItems(updatedItems);
        const updatedItem = updatedItems.find(i => i.id === item.id)!;
        onItemClick?.(updatedItem);
      } else {
        onItemClick?.(item);
      }
    }
  }, [multiSelect, items, onItemClick]);

  const handleItemMouseEnter = React.useCallback((index: number) => {
    onItemHover?.(index);
  }, [onItemHover]);

  const handleMouseDown = React.useCallback((e: React.MouseEvent) => {
    e.preventDefault();
  }, []);

  if (!shouldRender || items.length === 0) {
    return null;
  }

  return (
    <div
      className={getMenuClasses()}
      style={{ maxHeight: `${maxHeight}px` }}
    >
      {items.map((item, index) => (
        <div
          key={item.id}
          className={getItemClasses(index, item)}
          onMouseEnter={() => handleItemMouseEnter(index)}
          role="option"
          aria-selected={index === selectedIndex}
          aria-disabled={item.disabled}
        >
          <div
            className="item-content"
            onClick={() => handleItemClick(item, index)}
            onMouseDown={handleMouseDown}
          >
            <span
              className="item-text"
              title={item.label}
            >
              {getHighlightedText(item.label)}
            </span>
            {multiSelect && item.selected && (
              <span className="check-icon material-symbols-outlined">
                check
              </span>
            )}
          </div>
        </div>
      ))}
    </div>
  );
};