'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/dropdown-menu.css';
import '../../../../../bellhopos-styles/src/tokens/bellhop-animations.css';
import { Avatar } from '../avatar/Avatar';

export interface DropdownMenuItem {
  id: string;
  label?: string;
  icon?: string;
  shortcut?: string;
  disabled?: boolean;
  divider?: boolean;
}

export interface DropdownMenuHeader {
  title?: string;
  avatarGroup?: boolean;
  avatarSrc?: string;
  name?: string;
  email?: string;
}

export interface DropdownMenuProps {
  header?: DropdownMenuHeader;
  menuItems?: DropdownMenuItem[];
  visible?: boolean;
  showIcons?: boolean;
  scrollable?: boolean;
  className?: string;
  onItemClick?: (item: DropdownMenuItem) => void;
}

export const DropdownMenu: React.FC<DropdownMenuProps> = ({
  header,
  menuItems = [],
  visible = true,
  showIcons = true,
  scrollable = false,
  className = '',
  onItemClick,
}) => {
  const [isClosing, setIsClosing] = React.useState(false);
  const [shouldRender, setShouldRender] = React.useState(visible);

  React.useEffect(() => {
    if (visible) {
      setShouldRender(true);
      setIsClosing(false);
    } else {
      setIsClosing(true);
      const timer = setTimeout(() => {
        setShouldRender(false);
        setIsClosing(false);
      }, 150);
      return () => clearTimeout(timer);
    }
  }, [visible]);

  const dropdownClasses = React.useMemo(() => {
    const classes = ['dropdown-menu'];
    if (scrollable) {
      classes.push('dropdown-menu-scrollable');
    }
    if (className) {
      classes.push(className);
    }
    if (isClosing) {
      classes.push('animate-dropdown-exit');
    } else {
      classes.push('animate-dropdown-enter');
    }
    return classes.join(' ');
  }, [scrollable, className, isClosing]);

  const headerClasses = React.useMemo(() => {
    const classes = ['dropdown-header'];
    if (header?.avatarGroup) {
      classes.push('dropdown-header-avatar');
    }
    return classes.join(' ');
  }, [header?.avatarGroup]);

  const getMenuItemClasses = (item: DropdownMenuItem): string => {
    const classes = ['dropdown-item'];
    if (item.disabled) {
      classes.push('dropdown-item-disabled');
    }
    return classes.join(' ');
  };

  const handleItemClick = (item: DropdownMenuItem): void => {
    if (!item.disabled && !item.divider) {
      onItemClick?.(item);
    }
  };

  if (!shouldRender) {
    return null;
  }

  return (
    <div className={dropdownClasses}>
      {/* Header Section */}
      {header && (
        <div className={headerClasses}>
          {/* Avatar Group Header */}
          {header.avatarGroup && (
            <div className="avatar-group">
              <Avatar
                size="md"
                type="image"
                status="online"
                imageSrc={header.avatarSrc || ''}
                alt={header.name || 'Avatar'}
              />
              <div className="avatar-text">
                <div className="avatar-name">{header.name}</div>
                <div className="avatar-email">{header.email}</div>
              </div>
            </div>
          )}
          {/* Simple Text Header */}
          {!header.avatarGroup && header.title && (
            <div className="header-title">{header.title}</div>
          )}
        </div>
      )}

      {/* Menu Items Section */}
      <div className="menu-items">
        {menuItems.map((item) => (
          <React.Fragment key={item.id}>
            {/* Divider */}
            {item.divider && <div className="menu-divider" />}

            {/* Menu Item */}
            {!item.divider && (
              <div
                className={getMenuItemClasses(item)}
                onClick={() => handleItemClick(item)}
              >
                <div className="item-content">
                  <div className="item-main">
                    {item.icon && showIcons && (
                      <span className="material-symbols-outlined item-icon">
                        {item.icon}
                      </span>
                    )}
                    <span className="item-text" title={item.label}>
                      {item.label}
                    </span>
                  </div>
                  {item.shortcut && (
                    <span className="item-shortcut">{item.shortcut}</span>
                  )}
                </div>
              </div>
            )}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
};