'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/product-switcher.css';

export interface Product {
  id: string;
  name: string;
  description: string;
  logo: string;
  current?: boolean;
}

export interface ProductSwitcherProps {
  isOpen?: boolean;
  onClose?: () => void;
  anchorPosition?: { top: number; left: number };
  products?: Product[];
  onProductSelect?: (product: Product) => void;
  className?: string;
}

export const ProductSwitcher: React.FC<ProductSwitcherProps> = ({
  isOpen = false,
  onClose,
  anchorPosition = { top: 0, left: 0 },
  products = [
    {
      id: 'alice',
      name: 'Alice',
      description: 'Housekeeping & Guest Services',
      logo: './assets/logos/AL.svg',
    },
    {
      id: 'hotel-effectiveness',
      name: 'Hotel Effectiveness',
      description: 'Labor planning',
      logo: './assets/logos/HE.svg',
    },
    {
      id: 'profit-sword',
      name: 'ProfitSword',
      description: 'B.I and Finance',
      logo: './assets/logos/PS.svg',
    },
    {
      id: 'transcendent',
      name: 'Transcendent',
      description: 'Asset Management & CapEx',
      logo: './assets/logos/TR.svg',
    },
  ],
  onProductSelect,
  className,
}) => {
  const [isClosing, setIsClosing] = React.useState(false);
  const containerRef = React.useRef<HTMLDivElement>(null);

  // Handle click outside to close
  React.useEffect(() => {
    const handleDocumentClick = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (
        !target.closest('.product-switcher-container') &&
        !target.closest('.logo-active')
      ) {
        onClose?.();
      }
    };

    if (isOpen) {
      document.addEventListener('click', handleDocumentClick);
    }

    return () => {
      document.removeEventListener('click', handleDocumentClick);
    };
  }, [isOpen, onClose]);

  // Handle closing animation
  React.useEffect(() => {
    if (!isOpen && isClosing) {
      setIsClosing(false);
    }
  }, [isOpen, isClosing]);

  const handleClose = () => {
    setIsClosing(true);
    setTimeout(() => {
      onClose?.();
    }, 200); // Animation duration
  };

  const handleProductClick = (product: Product) => {
    onProductSelect?.(product);
    handleClose();
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Backdrop */}
      <div className="product-switcher-backdrop" />

      {/* Product Switcher Container */}
      <div
        ref={containerRef}
        className={[
          'product-switcher-container',
          isClosing ? 'closing' : '',
          className
        ]
          .filter(Boolean)
          .join(' ')}
        style={{
          top: anchorPosition.top,
          left: anchorPosition.left,
        }}
      >
        <div className="product-switcher-popover">
          {products.map((product) => (
            <div
              key={product.id}
              className={[
                'product-item',
                product.current ? 'current' : ''
              ]
                .filter(Boolean)
                .join(' ')}
              onClick={() => handleProductClick(product)}
            >
              <div className="product-icon-container">
                <img
                  src={product.logo}
                  alt={`${product.name} logo`}
                  className="product-icon"
                />
              </div>

              <div className="product-info">
                <div className="product-name">{product.name}</div>
                <div className="product-description">{product.description}</div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </>
  );
};

export default ProductSwitcher;