'use client';

import * as React from 'react';
import { BarChart, BarChartData, BarChartType, BarChartOrientation } from '../bar-chart/BarChart';
import { Dropdown, DropdownMenuItem, DropdownVariant } from '../dropdown/Dropdown';
import { ContainerFooter } from '../container-footer/ContainerFooter';
import '../../../../../bellhopos-styles/src/components/bar-chart-card.css';

export type BarChartCardBreakpoint = 'desktop' | 'mobile';

export interface ChartLegendItem {
  name: string;
  color: string;
}

export interface AxisConfig {
  show: boolean;
  label?: string;
  tickCount?: number;
  showGridLines?: boolean;
}

export interface TargetLineConfig {
  value: number;
}

export interface BarChartCardData {
  title: string;
  subtitle: string;
  value: string;
  badge?: string;
  chartData: BarChartData;
  legend?: ChartLegendItem[];
  xAxis?: AxisConfig;
  yAxis?: AxisConfig;
  targetLine?: TargetLineConfig;
}

export interface BarChartCardProps {
  breakpoint?: BarChartCardBreakpoint;
  data: BarChartCardData;
  chartType?: BarChartType;
  orientation?: BarChartOrientation;
  animated?: boolean;
  showDropdown?: boolean;
  dropdownVariant?: DropdownVariant;
  showFooter?: boolean;
  footerButtonLabel?: string;
  showXAxis?: boolean;
  showYAxis?: boolean;
  showTargetLine?: boolean;
  targetLineColor?: 'neutral' | 'brand' | 'success';
  onDropdownSelect?: (item: DropdownMenuItem) => void;
  onFooterButtonClick?: () => void;
}

const defaultDropdownMenuItems: DropdownMenuItem[] = [
  { id: 'view-report', label: 'View full report', icon: 'assessment' },
  { id: 'export-csv', label: 'Export as CSV', icon: 'download' },
  { id: 'export-pdf', label: 'Export as PDF', icon: 'picture_as_pdf' },
  { id: 'divider', label: '', divider: true },
  { id: 'configure', label: 'Configure chart', icon: 'settings' },
  { id: 'share', label: 'Share chart', icon: 'share' },
];

export const BarChartCard: React.FC<BarChartCardProps> = ({
  breakpoint = 'desktop',
  data,
  chartType = 'stacked',
  orientation = 'vertical',
  animated = true,
  showDropdown = true,
  dropdownVariant = 'icon-only-ghost',
  showFooter = false,
  footerButtonLabel = 'View report',
  showXAxis = false,
  showYAxis = false,
  showTargetLine = false,
  targetLineColor = 'neutral',
  onDropdownSelect,
  onFooterButtonClick,
}) => {
  const containerClasses = React.useMemo(() => {
    const classes = ['bar-chart-card', `bar-chart-card-${breakpoint}`];
    if (showFooter) {
      classes.push('has-footer');
    }
    return classes.join(' ');
  }, [breakpoint, showFooter]);

  const effectiveXAxis = React.useMemo((): AxisConfig => ({
    ...(data.xAxis || { show: false }),
    show: showXAxis,
  }), [data.xAxis, showXAxis]);

  const effectiveYAxis = React.useMemo((): AxisConfig => ({
    ...(data.yAxis || { show: false }),
    show: showYAxis,
  }), [data.yAxis, showYAxis]);

  const xAxisTicks = React.useMemo(() => {
    if (!effectiveXAxis.show || !data.chartData.categories) return [];
    return data.chartData.categories;
  }, [effectiveXAxis.show, data.chartData.categories]);

  const getMaxValue = (): number => {
    if (!data.chartData.series.length) return 0;

    if (chartType === 'stacked') {
      const numBars = data.chartData.series[0].values.length;
      let maxTotal = 0;

      for (let i = 0; i < numBars; i++) {
        const total = data.chartData.series.reduce(
          (sum, series) => sum + (series.values[i] || 0),
          0
        );
        maxTotal = Math.max(maxTotal, total);
      }

      return maxTotal;
    } else {
      return Math.max(...data.chartData.series[0].values);
    }
  };

  const yAxisTicks = React.useMemo(() => {
    if (!effectiveYAxis.show) return [];

    const maxValue = getMaxValue();
    const tickCount = effectiveYAxis.tickCount || 5;
    const ticks: number[] = [];

    for (let i = 0; i <= tickCount; i++) {
      ticks.push(Math.round((maxValue / tickCount) * i));
    }

    return ticks;
  }, [effectiveYAxis.show, effectiveYAxis.tickCount, data.chartData, chartType]);

  const formatYAxisTick = (value: number): string => {
    if (value >= 1000) {
      return (value / 1000).toLocaleString() + ',000';
    }
    return value.toLocaleString();
  };

  const targetLinePosition = React.useMemo(() => {
    if (!showTargetLine || !data.targetLine) return null;

    const maxValue = getMaxValue();
    if (maxValue === 0) return null;

    const percentage = (data.targetLine.value / maxValue) * 100;
    return Math.min(100, Math.max(0, percentage));
  }, [showTargetLine, data.targetLine, data.chartData, chartType]);

  const targetLineColorVar = React.useMemo(() => {
    const colorMap = {
      neutral: 'var(--color-neutral-900)',
      brand: 'var(--color-brand-600)',
      success: 'var(--color-success-600)',
    };
    return colorMap[targetLineColor];
  }, [targetLineColor]);

  const handleDropdownSelect = (item: DropdownMenuItem) => {
    onDropdownSelect?.(item);
  };

  const handleFooterButtonClick = () => {
    onFooterButtonClick?.();
  };

  const showAxes = effectiveYAxis.show || effectiveXAxis.show;

  return (
    <div className="bar-chart-card-wrapper">
      <div className={containerClasses}>
          {/* Dropdown Menu */}
          {showDropdown && (
            <div className="bar-chart-card-dropdown">
              <Dropdown
                variant={dropdownVariant}
                size="md"
                iconName="more_vert"
                menuItems={defaultDropdownMenuItems}
                onItemClick={handleDropdownSelect}
                forcePosition="bottom-right"
              />
            </div>
          )}

          {/* Header Section */}
          <div className="bar-chart-card-header">
            <h3 className="bar-chart-card-heading">{data.title}</h3>
            <p className="bar-chart-card-subtitle">{data.subtitle}</p>

            {/* Number and badge row */}
            <div className="bar-chart-card-row">
              <div className="bar-chart-card-number">{data.value}</div>
              {data.badge && (
                <div className="bar-chart-card-badge">{data.badge}</div>
              )}
            </div>
          </div>

          {/* Chart Section */}
          <div className="bar-chart-card-content">
            {/* Legend */}
            {data.legend && data.legend.length > 0 && (
              <div className="bar-chart-card-legend">
                {data.legend.map((item, index) => (
                  <div key={index} className="legend-item">
                    <div
                      className="legend-color"
                      style={{ backgroundColor: item.color }}
                    />
                    <span className="legend-text">{item.name}</span>
                  </div>
                ))}
              </div>
            )}

            {/* Chart with Axes */}
            {showAxes ? (
              <div className="bar-chart-card-chart-container">
                {/* Y-Axis Labels */}
                {effectiveYAxis.show && orientation === 'vertical' && (
                  <div className="y-axis-container">
                    <div className="y-axis-labels">
                      {yAxisTicks.slice().reverse().map((tick, index) => (
                        <div key={index} className="y-axis-tick-label">
                          {formatYAxisTick(tick)}
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Chart Area with Grid */}
                <div className="chart-grid-container">
                  {/* Background Grid Lines */}
                  {effectiveYAxis.showGridLines && orientation === 'vertical' && (
                    <div className="grid-lines">
                      {yAxisTicks.slice().reverse().map((_, index) => (
                        <div key={index} className="grid-line" />
                      ))}
                    </div>
                  )}

                  {/* Chart */}
                  <div className="chart-content">
                    {/* Target Line (only for vertical orientation) */}
                    {data.targetLine &&
                      targetLinePosition !== null &&
                      orientation === 'vertical' && (
                        <div
                          className="target-line"
                          style={{
                            bottom: `${targetLinePosition}%`,
                            borderColor: targetLineColorVar,
                          }}
                        />
                      )}

                    <BarChart
                      data={data.chartData}
                      type={chartType}
                      orientation={orientation}
                      animated={animated}
                    />
                  </div>

                  {/* X-Axis */}
                  {effectiveXAxis.show && (
                    <div className="x-axis-container">
                      <div className="x-axis-labels">
                        {xAxisTicks.map((tick, index) => (
                          <div key={index} className="x-axis-tick-label">
                            {tick}
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              /* Simple Chart without Axes */
              <div className="simple-chart-container">
                <BarChart
                  data={data.chartData}
                  type={chartType}
                  orientation={orientation}
                  animated={animated}
                />
              </div>
            )}
          </div>
        </div>

      {/* Footer outside container */}
      {showFooter && (
        <ContainerFooter
          size="standard"
          buttonLabel={footerButtonLabel}
          onButtonClick={handleFooterButtonClick}
        />
      )}
    </div>
  );
};