'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/page-navigation.css';
import { PageNavigationSingleLevel } from './PageNavigationSingleLevel';
import { PageNavigationMultiLevel } from './PageNavigationMultiLevel';

export interface ChildItem {
  label: string;
  badge?: string | number;
  showBadge?: boolean;
  isActive?: boolean;
}

export interface NavigationItem {
  id: string;
  label: string;
  icon?: string;
  type: 'single' | 'expandable';
  isActive?: boolean;
  isExpanded?: boolean;
  badge?: string | number;
  children?: ChildItem[];
}

export interface PageNavigationProps {
  title?: string;
  navigationItems: NavigationItem[];
  onItemClick?: (itemId: string, childIndex?: number) => void;
  className?: string;
}

export const PageNavigation: React.FC<PageNavigationProps> = ({
  title = 'Navigation',
  navigationItems: initialItems,
  onItemClick,
  className = '',
}) => {
  const [navigationItems, setNavigationItems] = React.useState<NavigationItem[]>(initialItems);

  const clearAllSelections = () => {
    setNavigationItems(items =>
      items.map(item => ({
        ...item,
        isActive: false,
        children: item.children?.map(child => ({ ...child, isActive: false }))
      }))
    );
  };

  const onSingleLevelClick = (itemId: string) => {
    clearAllSelections();
    setNavigationItems(items =>
      items.map(item =>
        item.id === itemId
          ? { ...item, isActive: true }
          : item
      )
    );
    onItemClick?.(itemId);
  };

  const onMultiLevelClick = (itemId: string, childIndex?: number) => {
    if (childIndex !== undefined) {
      // Child item clicked - activate it and clear others
      clearAllSelections();
      setNavigationItems(items =>
        items.map(item =>
          item.id === itemId && item.children
            ? {
                ...item,
                children: item.children.map((child, index) => ({
                  ...child,
                  isActive: index === childIndex
                }))
              }
            : item
        )
      );
      onItemClick?.(itemId, childIndex);
    } else {
      // Parent item clicked - toggle expansion
      setNavigationItems(items =>
        items.map(item =>
          item.id === itemId
            ? { ...item, isExpanded: !item.isExpanded }
            : item
        )
      );
    }
  };

  const pageNavigationClasses = [
    'page-navigation',
    className,
  ].filter(Boolean).join(' ');

  return (
    <div className={pageNavigationClasses}>
      <div className="page-navigation-header">
        <h2 className="page-navigation-title">{title}</h2>
      </div>

      <nav className="page-navigation-list">
        {navigationItems.map(item => (
          item.type === 'single' ? (
            <PageNavigationSingleLevel
              key={item.id}
              label={item.label}
              icon={item.icon}
              badge={item.badge}
              isActive={item.isActive || false}
              onItemClick={() => onSingleLevelClick(item.id)}
            />
          ) : (
            <PageNavigationMultiLevel
              key={item.id}
              label={item.label}
              icon={item.icon}
              badge={item.badge}
              children={item.children || []}
              isExpanded={item.isExpanded || false}
              onItemClick={(childIndex) => onMultiLevelClick(item.id, childIndex)}
            />
          )
        ))}
      </nav>
    </div>
  );
};