'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/radio-button-label.css';
import { RadioButton } from '../radio-button/RadioButton';

export interface RadioButtonLabelProps {
  label?: string;
  supportingText?: string;
  size?: 'sm' | 'md';
  disabled?: boolean;
  value?: any;
  name?: string;
  selectedValue?: any;
  onChange?: (value: any) => void;
  className?: string;
  id?: string;
}

export const RadioButtonLabel: React.FC<RadioButtonLabelProps> = ({
  label = '',
  supportingText = '',
  size = 'md',
  disabled = false,
  value = '',
  name = '',
  selectedValue = null,
  onChange,
  className = '',
  id,
}) => {
  const selected = selectedValue === value;

  const wrapperClasses = [
    'radio-button-label-wrapper',
    disabled ? 'radio-button-label-disabled' : '',
    className
  ].filter(Boolean).join(' ');

  const labelTextClasses = [
    'label-text',
    disabled ? 'label-disabled' : ''
  ].filter(Boolean).join(' ');

  const supportingTextClasses = [
    'supporting-text',
    disabled ? 'supporting-disabled' : ''
  ].filter(Boolean).join(' ');

  return (
    <label className={wrapperClasses} htmlFor={id}>
      <RadioButton
        id={id}
        selected={selected}
        value={value}
        size={size}
        disabled={disabled}
        name={name}
        onChange={onChange}
      />

      <div className="label-content">
        <span className={labelTextClasses}>
          {label}
        </span>
        {supportingText && (
          <p className={supportingTextClasses}>
            {supportingText}
          </p>
        )}
      </div>
    </label>
  );
};

export default RadioButtonLabel;