'use client';

import * as React from 'react';
import { Tooltip } from '../tooltip/Tooltip';
import '../../../../../bellhopos-styles/src/components/input.css';

export type InputPasswordState = 'placeholder' | 'filled' | 'hover' | 'focused';
export type InputPasswordError = boolean;

export interface InputPasswordProps {
  state?: InputPasswordState;
  error?: InputPasswordError;
  required?: boolean;
  disabled?: boolean;
  showHelpIcon?: boolean;
  showLeadingIcon?: boolean;
  showLabel?: boolean;
  showHintText?: boolean;
  label?: string;
  placeholder?: string;
  hintText?: string;
  leadingIcon?: string;
  helpIconTooltip?: string;
  value?: string;
  width?: string;
  className?: string;
  onChange?: (value: string) => void;
  onFocus?: () => void;
  onBlur?: () => void;
  onHelpClick?: () => void;
}

export const InputPassword: React.FC<InputPasswordProps> = ({
  state: controlledState,
  error = false,
  required = false,
  disabled = false,
  showHelpIcon = false,
  showLeadingIcon = true,
  showLabel = true,
  showHintText = true,
  label = 'Password',
  placeholder = 'Enter your password',
  hintText = 'Must be at least 8 characters',
  leadingIcon = 'lock',
  helpIconTooltip = 'Password requirements',
  value: controlledValue = '',
  width,
  className = '',
  onChange,
  onFocus,
  onBlur,
  onHelpClick,
}) => {
  const [internalValue, setInternalValue] = React.useState(controlledValue);
  const [internalState, setInternalState] = React.useState<InputPasswordState>(
    controlledValue ? 'filled' : 'placeholder'
  );
  const [isHovered, setIsHovered] = React.useState(false);
  const [isFocused, setIsFocused] = React.useState(false);
  const [showHelpTooltip, setShowHelpTooltip] = React.useState(false);
  const [showPassword, setShowPassword] = React.useState(false);
  const tooltipTimer = React.useRef<NodeJS.Timeout | null>(null);

  // Use controlled or internal value
  const value = controlledValue || internalValue;
  const state = controlledState || internalState;

  // Update internal state when controlled value changes
  React.useEffect(() => {
    if (controlledValue !== undefined) {
      setInternalValue(controlledValue);
      setInternalState(controlledValue ? 'filled' : 'placeholder');
    }
  }, [controlledValue]);

  // Compute input classes
  const inputClasses = React.useMemo(() => {
    const classes = ['input-field', 'input-field-with-toggle'];

    // Use controlled state if provided, otherwise use internal focus state
    const isCurrentlyFocused = controlledState === 'focused' || (!controlledState && isFocused);
    const isCurrentlyHovered = controlledState === 'hover' || (!controlledState && isHovered && !isCurrentlyFocused);

    if (isCurrentlyHovered) {
      classes.push('input-hover');
    }

    if (isCurrentlyFocused) {
      classes.push('input-focused');
    }

    if (error) {
      classes.push('input-error');
    }

    if (disabled) {
      classes.push('input-disabled');
    }

    if (showLeadingIcon) {
      classes.push('input-icon-leading');
    }

    return classes.join(' ');
  }, [controlledState, isHovered, isFocused, error, disabled, showLeadingIcon]);

  // Compute text color class
  const textColorClass = React.useMemo(() => {
    return value ? 'text-filled' : 'text-placeholder';
  }, [value]);

  // Handle input change
  const handleInputChange = React.useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = event.target.value || '';
    
    if (!controlledValue) {
      setInternalValue(newValue);
      setInternalState(newValue ? 'filled' : 'placeholder');
    }
    
    onChange?.(newValue);
  }, [controlledValue, onChange]);

  // Handle input focus
  const handleInputFocus = React.useCallback(() => {
    setIsFocused(true);
    onFocus?.();
  }, [onFocus]);

  // Handle input blur
  const handleInputBlur = React.useCallback(() => {
    setIsFocused(false);
    onBlur?.();
  }, [onBlur]);

  // Handle mouse enter
  const handleMouseEnter = React.useCallback(() => {
    if (!isFocused) {
      setIsHovered(true);
    }
  }, [isFocused]);

  // Handle mouse leave
  const handleMouseLeave = React.useCallback(() => {
    setIsHovered(false);
  }, []);

  // Handle password visibility toggle
  const handleTogglePasswordVisibility = React.useCallback(() => {
    if (!disabled) {
      setShowPassword(prev => !prev);
    }
  }, [disabled]);

  // Handle help icon click
  const handleHelpIconClick = React.useCallback(() => {
    onHelpClick?.();
  }, [onHelpClick]);

  // Handle help icon mouse enter (tooltip)
  const handleHelpIconMouseEnter = React.useCallback(() => {
    if (tooltipTimer.current) {
      clearTimeout(tooltipTimer.current);
    }

    tooltipTimer.current = setTimeout(() => {
      setShowHelpTooltip(true);
    }, 300);
  }, []);

  // Handle help icon mouse leave (tooltip)
  const handleHelpIconMouseLeave = React.useCallback(() => {
    if (tooltipTimer.current) {
      clearTimeout(tooltipTimer.current);
      tooltipTimer.current = null;
    }
    setShowHelpTooltip(false);
  }, []);

  // Cleanup tooltip timer on unmount
  React.useEffect(() => {
    return () => {
      if (tooltipTimer.current) {
        clearTimeout(tooltipTimer.current);
      }
    };
  }, []);

  const wrapperClasses = ['input-wrapper', className].filter(Boolean).join(' ');

  return (
    <div className={wrapperClasses} style={{ width }}>
      <div className="input-with-label">
        {showLabel && (
          <div className="label-wrapper">
            <label className="label">{label}</label>
            {required && <span className="asterisk">*</span>}
            {showHelpIcon && (
              <div className="icon-with-tooltip">
                <span
                  className="help-icon material-symbols-outlined"
                  onMouseEnter={handleHelpIconMouseEnter}
                  onMouseLeave={handleHelpIconMouseLeave}
                  onClick={handleHelpIconClick}
                >
                  help
                </span>
                <Tooltip
                  text={helpIconTooltip}
                  position="top"
                  variant="icon"
                  visible={showHelpTooltip}
                  style={{ position: 'absolute', top: 0, left: '50%' }}
                />
              </div>
            )}
          </div>
        )}
        <div
          className={inputClasses}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >
          <div className="input-content">
            {showLeadingIcon && (
              <span className="leading-icon material-symbols-outlined">
                {leadingIcon}
              </span>
            )}
            <input
              type={showPassword ? 'text' : 'password'}
              value={value}
              placeholder={placeholder}
              disabled={disabled}
              className={`input-element ${textColorClass}`}
              onChange={handleInputChange}
              onFocus={handleInputFocus}
              onBlur={handleInputBlur}
            />
          </div>
          {/* Password visibility toggle icon */}
          <span
            className="visibility-toggle material-symbols-outlined"
            onClick={handleTogglePasswordVisibility}
            title={showPassword ? 'Hide password' : 'Show password'}
          >
            {showPassword ? 'visibility_off' : 'visibility'}
          </span>
        </div>
      </div>
      {showHintText && hintText && (
        <div className={`hint-text ${error ? 'hint-error' : ''}`}>
          {hintText}
        </div>
      )}
    </div>
  );
};