'use client';

import * as React from 'react';
import { ChartTooltip, TooltipItem } from '../chart-tooltip/ChartTooltip';
import '../../../../../bellhopos-styles/src/components/bar-chart.css';

export type BarChartType = 'simple' | 'stacked';
export type BarChartOrientation = 'vertical' | 'horizontal';

export interface BarChartData {
  series: {
    name: string;
    values: number[];
    color?: string;
  }[];
  categories?: string[];
}

export interface BarSegment {
  value: number;
  height: number;
  width: number;
  color: string;
  seriesName?: string;
}

export interface ProcessedBar {
  segments: BarSegment[];
  totalValue: number;
  category?: string;
}

export interface BarChartProps {
  data?: BarChartData;
  type?: BarChartType;
  orientation?: BarChartOrientation;
  animated?: boolean;
  maxHeight?: number;
  maxWidth?: number;
}

const defaultData: BarChartData = {
  series: [
    {
      name: 'Series 1',
      values: [30, 45, 20, 35, 50, 40, 60, 35, 25, 55, 40],
      color: '#94a3b8',
    },
    {
      name: 'Series 2',
      values: [20, 25, 40, 30, 35, 45, 25, 30, 40, 20, 50],
      color: '#2563eb',
    },
    {
      name: 'Series 3',
      values: [25, 15, 35, 20, 15, 20, 30, 25, 30, 35, 25],
      color: '#7c3aed',
    },
  ],
};

export const BarChart: React.FC<BarChartProps> = ({
  data = defaultData,
  type = 'stacked',
  orientation = 'vertical',
  animated = true,
  maxHeight = 150,
  maxWidth = 200,
}) => {
  const [tooltipVisible, setTooltipVisible] = React.useState(false);
  const [tooltipX, setTooltipX] = React.useState(0);
  const [tooltipY, setTooltipY] = React.useState(0);
  const [tooltipHeader, setTooltipHeader] = React.useState('');
  const [tooltipItems, setTooltipItems] = React.useState<TooltipItem[]>([]);
  const [tooltipTotal, setTooltipTotal] = React.useState('');
  const [showTooltipTotal, setShowTooltipTotal] = React.useState(false);

  const processedData = React.useMemo((): ProcessedBar[] => {
    if (!data.series?.length || !data.series[0].values.length) {
      return [];
    }

    const bars: ProcessedBar[] = [];

    if (type === 'simple') {
      const values = data.series[0].values;
      const maxValue = Math.max(...values);
      const colors = [
        'var(--color-brand-600)',
        'var(--color-orange-500)',
        'var(--color-success-500)',
        'var(--color-purple-600)',
        'var(--color-accent-500)',
        'var(--color-teal-500)',
        'var(--color-lime-500)',
        'var(--color-amber-500)',
      ];

      for (let i = 0; i < values.length; i++) {
        const value = values[i] || 0;
        const segments: BarSegment[] = [];

        if (value > 0) {
          const height = (value / maxValue) * maxHeight;
          const width = (value / maxValue) * maxWidth;
          segments.push({
            value,
            height,
            width,
            color: colors[i % colors.length],
            seriesName: `Bar ${i + 1}`,
          });
        }

        bars.push({
          segments,
          totalValue: value,
          category: data.categories?.[i],
        });
      }
    } else {
      const numBars = data.series[0].values.length;
      const maxTotal = Math.max(
        ...Array.from({ length: numBars }, (_, i) =>
          data.series.reduce(
            (sum, series) => sum + (series.values[i] || 0),
            0
          )
        )
      );

      for (let barIndex = 0; barIndex < numBars; barIndex++) {
        const segments: BarSegment[] = [];
        let totalValue = 0;

        for (const series of data.series) {
          const value = series.values[barIndex] || 0;
          totalValue += value;

          if (value > 0) {
            const height = (value / maxTotal) * maxHeight;
            const width = (value / maxTotal) * maxWidth;
            segments.push({
              value,
              height,
              width,
              color: series.color || '#64748b',
              seriesName: series.name,
            });
          }
        }

        bars.push({
          segments,
          totalValue,
          category: data.categories?.[barIndex],
        });
      }
    }

    return bars;
  }, [data, type, maxHeight, maxWidth]);

  const containerClasses = React.useMemo(() => {
    const classes = ['bar-chart', type, orientation];
    if (animated) {
      classes.push('bar-chart-animated');
    }
    return classes.join(' ');
  }, [type, orientation, animated]);

  const handleColumnHover = React.useCallback((
    event: React.MouseEvent,
    bar: ProcessedBar,
    columnIndex: number
  ) => {
    setTooltipVisible(true);
    setTooltipX(event.clientX);
    setTooltipY(event.clientY);

    setTooltipHeader(bar.category || `Column ${columnIndex + 1}`);

    const items: TooltipItem[] = [];
    bar.segments.forEach((segment) => {
      if (segment.seriesName && segment.value > 0) {
        items.push({
          color: segment.color,
          label: segment.seriesName,
          value: segment.value.toString(),
        });
      }
    });

    setTooltipItems(items);
    setTooltipTotal(bar.totalValue.toString());
    setShowTooltipTotal(items.length > 1);
  }, []);

  const handleColumnMove = React.useCallback((event: React.MouseEvent) => {
    if (tooltipVisible) {
      setTooltipX(event.clientX);
      setTooltipY(event.clientY);
    }
  }, [tooltipVisible]);

  const handleColumnLeave = React.useCallback(() => {
    setTooltipVisible(false);
  }, []);

  if (orientation === 'vertical') {
    return (
      <>
        <div className={`vertical-container ${containerClasses}`}>
          {processedData.map((bar, i) => (
            <div
              key={i}
              className="bar-column vertical"
              onMouseEnter={(e) => handleColumnHover(e, bar, i)}
              onMouseMove={handleColumnMove}
              onMouseLeave={handleColumnLeave}
            >
              {bar.segments.map((segment, segIndex) => (
                <div
                  key={segIndex}
                  className="bar-segment vertical"
                  style={{
                    height: `${segment.height}px`,
                    backgroundColor: segment.color,
                  }}
                />
              ))}
            </div>
          ))}
        </div>

        <ChartTooltip
          visible={tooltipVisible}
          x={tooltipX}
          y={tooltipY}
          header={tooltipHeader}
          items={tooltipItems}
          total={tooltipTotal}
          showTotal={showTooltipTotal}
        />
      </>
    );
  }

  return (
    <>
      <div className={`horizontal-container ${containerClasses}`}>
        {processedData.map((bar, i) => (
          <div
            key={i}
            className="bar-row horizontal"
            onMouseEnter={(e) => handleColumnHover(e, bar, i)}
            onMouseMove={handleColumnMove}
            onMouseLeave={handleColumnLeave}
          >
            {bar.segments.map((segment, segIndex) => (
              <div
                key={segIndex}
                className="bar-segment horizontal"
                style={{
                  width: `${(segment.value / bar.totalValue) * 100}%`,
                  backgroundColor: segment.color,
                }}
              />
            ))}
          </div>
        ))}
      </div>

      <ChartTooltip
        visible={tooltipVisible}
        x={tooltipX}
        y={tooltipY}
        header={tooltipHeader}
        items={tooltipItems}
        total={tooltipTotal}
        showTotal={showTooltipTotal}
      />
    </>
  );
};