'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/checkbox-label.css';
import { Checkbox } from '../checkbox/Checkbox';

export interface CheckboxLabelProps {
  label?: string;
  supportingText?: string;
  size?: 'sm' | 'md';
  disabled?: boolean;
  checked?: boolean;
  defaultChecked?: boolean;
  indeterminate?: boolean;
  onChange?: (checked: boolean) => void;
  className?: string;
  id?: string;
}

export const CheckboxLabel: React.FC<CheckboxLabelProps> = ({
  label = '',
  supportingText = '',
  size = 'md',
  disabled = false,
  checked,
  defaultChecked,
  indeterminate = false,
  onChange,
  className = '',
  id,
}) => {
  const wrapperClasses = [
    'checkbox-label-wrapper',
    disabled ? 'checkbox-label-disabled' : '',
    className
  ].filter(Boolean).join(' ');

  const labelTextClasses = [
    'label-text',
    disabled ? 'label-disabled' : ''
  ].filter(Boolean).join(' ');

  const supportingTextClasses = [
    'supporting-text',
    disabled ? 'supporting-disabled' : ''
  ].filter(Boolean).join(' ');

  return (
    <label className={wrapperClasses} htmlFor={id}>
      <Checkbox
        id={id}
        checked={checked}
        defaultChecked={defaultChecked}
        indeterminate={indeterminate}
        size={size}
        disabled={disabled}
        onChange={onChange}
      />

      <div className="label-content">
        <span className={labelTextClasses}>
          {label}
        </span>
        {supportingText && (
          <p className={supportingTextClasses}>
            {supportingText}
          </p>
        )}
      </div>
    </label>
  );
};

export default CheckboxLabel;