'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/date-range-picker-content.css';
import { DatePickerContent, SelectedDate, DisabledDate } from '../date-picker-content/DatePickerContent';

export interface SelectedDateRange {
  startDate: SelectedDate | null;
  endDate: SelectedDate | null;
}

export interface DateRangePickerContentProps {
  minYear?: number;
  maxYear?: number;
  disabled?: boolean;
  disabledDates?: DisabledDate[];
  showOtherMonthDays?: boolean;
  value?: SelectedDateRange | null;
  onChange?: (value: SelectedDateRange | null) => void;
  onDateRangeSelect?: (value: SelectedDateRange | null) => void;
}

export const DateRangePickerContent: React.FC<DateRangePickerContentProps> = ({
  minYear = 1998,
  maxYear = 2060,
  disabled = false,
  disabledDates = [],
  showOtherMonthDays = true,
  value,
  onChange,
  onDateRangeSelect,
}) => {
  const [selectedRange, setSelectedRange] = React.useState<SelectedDateRange | null>(value || null);

  // Initialize left calendar with current month
  const today = new Date();
  const currentMonth = today.getMonth();
  const currentYear = today.getFullYear();

  const [leftMonth, setLeftMonth] = React.useState<number>(currentMonth);
  const [leftYear, setLeftYear] = React.useState<number>(currentYear);

  // Helper functions for month navigation
  const getNextMonth = (month: number, year: number) => {
    const nextMonth = month + 1;
    if (nextMonth > 11) {
      return { month: 0, year: year + 1 };
    }
    return { month: nextMonth, year };
  };

  const getPreviousMonth = (month: number, year: number) => {
    const prevMonth = month - 1;
    if (prevMonth < 0) {
      return { month: 11, year: year - 1 };
    }
    return { month: prevMonth, year };
  };

  const nextMonthYear = getNextMonth(currentMonth, currentYear);
  const [rightMonth, setRightMonth] = React.useState<number>(nextMonthYear.month);
  const [rightYear, setRightYear] = React.useState<number>(nextMonthYear.year);

  // Sync with external value prop
  React.useEffect(() => {
    if (value !== undefined) {
      setSelectedRange(value);
    }
  }, [value]);

  const handleLeftDateSelect = (date: SelectedDate | null): void => {
    if (!date) return;

    let newRange: SelectedDateRange;

    if (!selectedRange?.startDate || (selectedRange.startDate && selectedRange.endDate)) {
      // Start new range
      newRange = { startDate: date, endDate: null };
    } else if (selectedRange.startDate && !selectedRange.endDate) {
      // Complete the range
      const startDate = selectedRange.startDate;
      const isAfterStart = date.year > startDate.year ||
        (date.year === startDate.year && date.month > startDate.month) ||
        (date.year === startDate.year && date.month === startDate.month && date.day > startDate.day);

      if (isAfterStart) {
        newRange = { startDate, endDate: date };
      } else {
        newRange = { startDate: date, endDate: startDate };
      }
    } else {
      newRange = { startDate: date, endDate: null };
    }

    setSelectedRange(newRange);
    onChange?.(newRange);
    onDateRangeSelect?.(newRange);
  };

  const handleRightDateSelect = (date: SelectedDate | null): void => {
    if (!date) return;

    let newRange: SelectedDateRange;

    if (!selectedRange?.startDate || (selectedRange.startDate && selectedRange.endDate)) {
      // Start new range
      newRange = { startDate: date, endDate: null };
    } else if (selectedRange.startDate && !selectedRange.endDate) {
      // Complete the range
      const startDate = selectedRange.startDate;
      const isAfterStart = date.year > startDate.year ||
        (date.year === startDate.year && date.month > startDate.month) ||
        (date.year === startDate.year && date.month === startDate.month && date.day > startDate.day);

      if (isAfterStart) {
        newRange = { startDate, endDate: date };
      } else {
        newRange = { startDate: date, endDate: startDate };
      }
    } else {
      newRange = { startDate: date, endDate: null };
    }

    setSelectedRange(newRange);
    onChange?.(newRange);
    onDateRangeSelect?.(newRange);
  };

  const handleLeftMonthYearChange = (month: number, year: number): void => {
    setLeftMonth(month);
    setLeftYear(year);

    // Ensure right calendar is always at least one month ahead
    if (year > rightYear || (year === rightYear && month >= rightMonth)) {
      const nextMonthYear = getNextMonth(month, year);
      setRightMonth(nextMonthYear.month);
      setRightYear(nextMonthYear.year);
    }
  };

  const handleRightMonthYearChange = (month: number, year: number): void => {
    setRightMonth(month);
    setRightYear(year);

    // Ensure left calendar is always at least one month behind
    if (year < leftYear || (year === leftYear && month <= leftMonth)) {
      const prevMonthYear = getPreviousMonth(month, year);
      setLeftMonth(prevMonthYear.month);
      setLeftYear(prevMonthYear.year);
    }
  };

  const isDateInRange = (date: SelectedDate): boolean => {
    if (!selectedRange?.startDate || !selectedRange?.endDate) return false;

    const dateTime = new Date(date.year, date.month, date.day).getTime();
    const startTime = new Date(selectedRange.startDate.year, selectedRange.startDate.month, selectedRange.startDate.day).getTime();
    const endTime = new Date(selectedRange.endDate.year, selectedRange.endDate.month, selectedRange.endDate.day).getTime();

    // Only return true for dates between start and end (excluding start and end themselves)
    return dateTime > startTime && dateTime < endTime;
  };

  const isDateSelected = (date: SelectedDate): boolean => {
    // Don't mark dates as selected if they are range start/end - let them use range classes instead
    return false;
  };

  const isDateRangeStart = (date: SelectedDate): boolean => {
    if (!selectedRange?.startDate) return false;

    return selectedRange.startDate.year === date.year &&
      selectedRange.startDate.month === date.month &&
      selectedRange.startDate.day === date.day;
  };

  const isDateRangeEnd = (date: SelectedDate): boolean => {
    if (!selectedRange?.endDate) return false;

    return selectedRange.endDate.year === date.year &&
      selectedRange.endDate.month === date.month &&
      selectedRange.endDate.day === date.day;
  };

  return (
    <div className="date-range-picker-content">
      <div className="date-pickers">
        <div className="left-picker">
          <DatePickerContent
            minYear={minYear}
            maxYear={maxYear}
            disabled={disabled}
            disabledDates={disabledDates}
            showOtherMonthDays={showOtherMonthDays}
            displayMonth={leftMonth}
            displayYear={leftYear}
            value={selectedRange?.startDate || null}
            isDateInRange={isDateInRange}
            isDateSelected={isDateSelected}
            isDateRangeStart={isDateRangeStart}
            isDateRangeEnd={isDateRangeEnd}
            onChange={handleLeftDateSelect}
            onMonthYearChange={handleLeftMonthYearChange}
          />
        </div>
        <div className="right-picker">
          <DatePickerContent
            minYear={minYear}
            maxYear={maxYear}
            disabled={disabled}
            disabledDates={disabledDates}
            showOtherMonthDays={showOtherMonthDays}
            displayMonth={rightMonth}
            displayYear={rightYear}
            value={selectedRange?.endDate || null}
            isDateInRange={isDateInRange}
            isDateSelected={isDateSelected}
            isDateRangeStart={isDateRangeStart}
            isDateRangeEnd={isDateRangeEnd}
            onChange={handleRightDateSelect}
            onMonthYearChange={handleRightMonthYearChange}
          />
        </div>
      </div>
    </div>
  );
};

export default DateRangePickerContent;