'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/breadcrumbs.css';
import { ButtonIcon } from '../button-icon/ButtonIcon';

export interface BreadcrumbItem {
  label: string;
  path?: string;
  isActive?: boolean;
  icon?: string;
}

export interface BreadcrumbsProps {
  items: BreadcrumbItem[];
  separator?: string;
  showHome?: boolean;
  maxVisibleItems?: number;
  onItemClick?: (item: BreadcrumbItem) => void;
  onNavigate?: (path: string) => void;
  className?: string;
}

export const Breadcrumbs: React.FC<BreadcrumbsProps> = ({
  items = [],
  separator = 'chevron_right',
  showHome = true,
  maxVisibleItems = 4,
  onItemClick,
  onNavigate,
  className = '',
}) => {
  const { displayItems, showEllipsis, collapsedItems } = React.useMemo(() => {
    if (!items || items.length <= maxVisibleItems) {
      return {
        displayItems: items ? [...items] : [],
        showEllipsis: false,
        collapsedItems: [],
      };
    } else {
      const lastItems = items.slice(-(maxVisibleItems - 2));
      return {
        displayItems: [items[0], ...lastItems],
        showEllipsis: true,
        collapsedItems: items.slice(1, -(maxVisibleItems - 2)),
      };
    }
  }, [items, maxVisibleItems]);

  const handleItemClick = React.useCallback((item: BreadcrumbItem) => {
    if (!item.isActive && item.path) {
      onItemClick?.(item);
      onNavigate?.(item.path);
    }
  }, [onItemClick, onNavigate]);

  const handleHomeClick = React.useCallback(() => {
    const homeItem: BreadcrumbItem = {
      label: 'Home',
      path: '/',
      icon: 'cottage',
    };
    onItemClick?.(homeItem);
    onNavigate?.('/');
  }, [onItemClick, onNavigate]);

  const handleEllipsisClick = React.useCallback(() => {
    if (collapsedItems.length > 0) {
      handleItemClick(collapsedItems[0]);
    }
  }, [collapsedItems, handleItemClick]);

  const renderBreadcrumbItem = React.useCallback((item: BreadcrumbItem, index: number) => {
    if (item.isActive || !item.path) {
      return (
        <div
          key={index}
          className="breadcrumb-button breadcrumb-current"
          aria-current="page"
        >
          <span className="breadcrumb-text">{item.label}</span>
        </div>
      );
    }

    return (
      <button
        key={index}
        type="button"
        className="breadcrumb-button"
        onClick={() => handleItemClick(item)}
      >
        <span className="breadcrumb-text">{item.label}</span>
      </button>
    );
  }, [handleItemClick]);

  const breadcrumbsClasses = React.useMemo(() => {
    const classes = ['breadcrumbs', className].filter(Boolean);
    return classes.join(' ');
  }, [className]);

  return (
    <nav className={breadcrumbsClasses} aria-label="Breadcrumb">
      <div className="breadcrumbs-container">
        {/* Home button */}
        {showHome && (
          <div className="breadcrumb-item">
            <ButtonIcon
              hierarchy="tertiary"
              size="xs"
              iconName="cottage"
              onClick={handleHomeClick}
              aria-label="Home"
            />
          </div>
        )}

        {/* Separator after home */}
        {showHome && (displayItems.length > 0 || showEllipsis) && (
          <div className="breadcrumb-separator">
            <span className="material-symbols-outlined">{separator}</span>
          </div>
        )}

        {/* First item (if ellipsis is shown) */}
        {showEllipsis && displayItems.length > 0 && (
          <>
            <div className="breadcrumb-item">
              {renderBreadcrumbItem(displayItems[0], 0)}
            </div>

            <div className="breadcrumb-separator">
              <span className="material-symbols-outlined">{separator}</span>
            </div>

            {/* Ellipsis button */}
            <div className="breadcrumb-item">
              <button
                type="button"
                className="breadcrumb-button breadcrumb-ellipsis"
                onClick={handleEllipsisClick}
                title={`Show ${collapsedItems.length} hidden items`}
              >
                <span className="breadcrumb-text">...</span>
              </button>
            </div>

            <div className="breadcrumb-separator">
              <span className="material-symbols-outlined">{separator}</span>
            </div>

            {/* Remaining items */}
            {displayItems.slice(1).map((item, index) => (
              <React.Fragment key={index + 1}>
                <div className="breadcrumb-item">
                  {renderBreadcrumbItem(item, index + 1)}
                </div>

                {index < displayItems.slice(1).length - 1 && (
                  <div className="breadcrumb-separator">
                    <span className="material-symbols-outlined">{separator}</span>
                  </div>
                )}
              </React.Fragment>
            ))}
          </>
        )}

        {/* All items (when no ellipsis) */}
        {!showEllipsis && displayItems.map((item, index) => (
          <React.Fragment key={index}>
            <div className="breadcrumb-item">
              {renderBreadcrumbItem(item, index)}
            </div>

            {index < displayItems.length - 1 && (
              <div className="breadcrumb-separator">
                <span className="material-symbols-outlined">{separator}</span>
              </div>
            )}
          </React.Fragment>
        ))}
      </div>
    </nav>
  );
};