'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/nav-item.css';

export interface NavItemProps {
  icon: string;
  label: string;
  isActive?: boolean;
  disabled?: boolean;
  onClick?: () => void;
  className?: string;
}

export const NavItem: React.FC<NavItemProps> = ({
  icon,
  label,
  isActive = false,
  disabled = false,
  onClick,
  className = '',
}) => {
  const navItemClasses = [
    'nav-item',
    isActive ? 'active' : '',
    disabled ? 'disabled' : '',
    className,
  ].filter(Boolean).join(' ');

  const handleClick = () => {
    if (!disabled && onClick) {
      onClick();
    }
  };

  const handleKeyDown = (event: React.KeyboardEvent) => {
    if ((event.key === 'Enter' || event.key === ' ') && !disabled && onClick) {
      event.preventDefault();
      onClick();
    }
  };

  return (
    <div className={navItemClasses}>
      <button
        className="nav-item-button"
        aria-label={label}
        type="button"
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        disabled={disabled}
        tabIndex={disabled ? -1 : 0}
      >
        <span className="material-symbols-outlined icon">{icon}</span>
      </button>
      <p className="nav-item-label">{label}</p>
    </div>
  );
};

export default NavItem;