import React from 'react';
import '../../../../../bellhopos-styles/src/components/badge-dot.css';

export type BadgeDotSize = 'sm' | 'md' | 'lg';
export type BadgeDotColor = 'success' | 'blue' | 'error' | 'warning';

export interface BadgeDotProps {
  size?: BadgeDotSize;
  color?: BadgeDotColor;
  outline?: boolean;
  className?: string;
}

export const BadgeDot: React.FC<BadgeDotProps> = ({
  size = 'md',
  color = 'error',
  outline = false,
  className,
}) => {
  const dotClasses = [
    'badge-dot',
    `badge-dot-${size}`,
    `badge-dot-${color}`,
    outline ? 'badge-dot-outline' : '',
    className
  ]
    .filter(Boolean)
    .join(' ');

  return <div className={dotClasses} />;
};

export default BadgeDot;