import React from 'react';
import '../../../../../bellhopos-styles/src/components/illustrations.css';

export type IllustrationSize = 'sm' | 'md' | 'lg' | 'xl' | '2xl' | '3xl' | '4xl';

export interface IllustrationsProps {
  size?: IllustrationSize;
  title?: string;
  description?: string;
  svgPath?: string;
  alt?: string;
  className?: string;
}

const getSvgDimensions = (size: IllustrationSize): { width: number; height: number } => {
  switch (size) {
    case 'sm':
      return { width: 120, height: 120 };
    case 'md':
      return { width: 160, height: 160 };
    case 'lg':
      return { width: 200, height: 200 };
    case 'xl':
      return { width: 280, height: 280 };
    case '2xl':
      return { width: 360, height: 360 };
    case '3xl':
      return { width: 480, height: 480 };
    case '4xl':
      return { width: 600, height: 600 };
    default:
      return { width: 200, height: 200 };
  }
};

export const Illustrations: React.FC<IllustrationsProps> = ({
  size = 'lg',
  title = '',
  description = '',
  svgPath = '/illustrations/Search-not-found.svg',
  alt = 'Illustration',
  className,
}) => {
  const dimensions = getSvgDimensions(size);

  const classNames = ['illustration', `illustration-${size}`, className].filter(Boolean).join(' ');

  return (
    <div className={classNames}>
      <div className="illustration-wrapper">
        <div
          className="illustration-svg-container"
          style={{
            width: `${dimensions.width}px`,
            height: `${dimensions.height}px`,
          }}
        >
          <img
            src={svgPath}
            alt={alt}
            style={{
              width: `${dimensions.width}px`,
              height: `${dimensions.height}px`,
            }}
            className="illustration-image"
          />
        </div>
        {(title || description) && (
          <div className="illustration-content">
            {title && <h3 className="illustration-title">{title}</h3>}
            {description && <p className="illustration-description">{description}</p>}
          </div>
        )}
      </div>
    </div>
  );
};

Illustrations.displayName = 'Illustrations';