'use client';

import * as React from 'react';
import { Avatar } from '../avatar/Avatar';
import '../../../../../bellhopos-styles/src/components/tag.css';
import '../../../../../bellhopos-styles/src/tokens/bellhop-animations.css';

export type TagVariant = 'text-only' | 'avatar';
export type TagSize = 'sm' | 'md' | 'lg';

export interface TagProps {
  variant?: TagVariant;
  size?: TagSize;
  label?: string;
  dismissible?: boolean;
  disabled?: boolean;
  maxWidth?: number;
  className?: string;
  onDismiss?: () => void;
}

export const Tag: React.FC<TagProps> = ({
  variant = 'text-only',
  size = 'md',
  label = 'Label',
  dismissible = false,
  disabled = false,
  maxWidth = 120,
  className = '',
  onDismiss,
}) => {
  const [isDismissing, setIsDismissing] = React.useState(false);

  const handleDismiss = React.useCallback((event?: React.MouseEvent) => {
    if (event) {
      event.stopPropagation();
    }

    if (dismissible && !disabled && !isDismissing) {
      setIsDismissing(true);
      
      // Simulate animation duration
      setTimeout(() => {
        onDismiss?.();
        setIsDismissing(false);
      }, 200);
    }
  }, [dismissible, disabled, isDismissing, onDismiss]);

  const tagClasses = React.useMemo(() => {
    const classes = ['tag', `tag-${size}`, `tag-${variant}`];

    if (dismissible) {
      classes.push('tag-dismissible');
    }

    if (disabled) {
      classes.push('tag-disabled');
    }

    if (isDismissing) {
      classes.push('animate-dismiss');
    }

    if (className) {
      classes.push(className);
    }

    return classes.join(' ');
  }, [size, variant, dismissible, disabled, isDismissing, className]);

  const labelStyle = React.useMemo(() => ({
    maxWidth: `${maxWidth}px`,
  }), [maxWidth]);

  return (
    <span className={tagClasses}>
      <div className="tag-content">
        {/* Avatar variant */}
        {variant === 'avatar' && (
          <Avatar
            size="xxs"
            type="image"
          />
        )}

        {/* Label */}
        <span className="tag-label-wrapper">
          <span className="tag-label" style={labelStyle}>
            {label}
          </span>
        </span>
      </div>

      {/* Dismiss button (if dismissible) */}
      {dismissible && (
        <button
          className="tag-dismiss"
          onClick={handleDismiss}
          disabled={disabled}
          type="button"
          aria-label="Dismiss"
        >
          <span className="material-symbols-outlined tag-dismiss-icon">
            close
          </span>
        </button>
      )}
    </span>
  );
};