'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/container-footer.css';
import { Button } from '../button/Button';

export type ContainerFooterSize = 'minimal' | 'standard';

export interface ContainerFooterProps {
  size?: ContainerFooterSize;
  buttonLabel?: string;
  onButtonClick?: () => void;
}

export const ContainerFooter: React.FC<ContainerFooterProps> = ({
  size = 'standard',
  buttonLabel = 'View report',
  onButtonClick
}) => {
  const footerClasses = ['container-footer', `container-footer-${size}`].join(' ');

  return (
    <div className={footerClasses}>
      <div className="container-footer-content">
        <Button
          hierarchy="quaternary"
          type="link"
          size="md"
          label={buttonLabel}
          onClick={onButtonClick}
        />
      </div>
    </div>
  );
};