'use client';

import * as React from 'react';
import { PieChart, PieChartData, PieChartHole } from '../pie-chart/PieChart';
import { Dropdown, DropdownMenuItem, DropdownVariant } from '../dropdown/Dropdown';
import { ContainerFooter } from '../container-footer/ContainerFooter';
import { Badge } from '../badge/Badge';
import '../../../../../bellhopos-styles/src/components/pie-chart-card.css';

export type PieChartCardBreakpoint = 'desktop' | 'mobile';

export interface ChartLegendItem {
  name: string;
  color: string;
  value?: string;
  percentage?: string;
}

export interface PieChartCardData {
  title: string;
  subtitle: string;
  value: string;
  badge?: string;
  chartData: PieChartData;
  legend?: ChartLegendItem[];
}

export interface PieChartCardProps {
  breakpoint?: PieChartCardBreakpoint;
  data: PieChartCardData;
  hole?: PieChartHole;
  size?: number;
  animated?: boolean;
  gap?: number;
  showDropdown?: boolean;
  dropdownVariant?: DropdownVariant;
  showFooter?: boolean;
  footerButtonLabel?: string;
  showLegend?: boolean;
  onDropdownSelect?: (item: DropdownMenuItem) => void;
  onFooterButtonClick?: () => void;
}

const defaultDropdownMenuItems: DropdownMenuItem[] = [
  { id: 'view-report', label: 'View full report', icon: 'assessment' },
  { id: 'export-csv', label: 'Export as CSV', icon: 'download' },
  { id: 'export-pdf', label: 'Export as PDF', icon: 'picture_as_pdf' },
  { id: 'divider', label: '', divider: true },
  { id: 'configure', label: 'Configure chart', icon: 'settings' },
  { id: 'share', label: 'Share chart', icon: 'share' },
];

export const PieChartCard: React.FC<PieChartCardProps> = ({
  breakpoint = 'desktop',
  data,
  hole = '85%',
  size = 160,
  animated = true,
  gap = 5,
  showDropdown = true,
  dropdownVariant = 'icon-only-ghost',
  showFooter = false,
  footerButtonLabel = 'View report',
  showLegend = true,
  onDropdownSelect,
  onFooterButtonClick,
}) => {
  const containerClasses = React.useMemo(() => {
    const classes = ['pie-chart-card', `pie-chart-card-${breakpoint}`];
    if (showFooter) {
      classes.push('has-footer');
    }
    return classes.join(' ');
  }, [breakpoint, showFooter]);

  const legendItems = React.useMemo((): ChartLegendItem[] => {
    if (data.legend && data.legend.length > 0) {
      return data.legend;
    }

    // Generate legend from chart data
    const total = data.chartData.series.reduce((sum, item) => sum + item.value, 0);

    return data.chartData.series.map((item) => ({
      name: item.name,
      color: item.color || '#000',
      percentage: total > 0 ? `${Math.round((item.value / total) * 100)}%` : '0%',
    }));
  }, [data]);

  const handleDropdownSelect = (item: DropdownMenuItem) => {
    onDropdownSelect?.(item);
  };

  const handleFooterButtonClick = () => {
    onFooterButtonClick?.();
  };

  return (
    <div className="pie-chart-card-wrapper">
      <div className={containerClasses}>
        {/* Dropdown Menu */}
        {showDropdown && (
          <div className="pie-chart-card-dropdown">
            <Dropdown
              variant={dropdownVariant}
              size="md"
              iconName="more_vert"
              menuItems={defaultDropdownMenuItems}
              onItemClick={handleDropdownSelect}
            />
          </div>
        )}

        {/* Header Section */}
        <div className="pie-chart-card-header">
          <h3 className="pie-chart-card-heading">{data.title}</h3>
          <p className="pie-chart-card-subtitle">{data.subtitle}</p>
        </div>

        {/* Chart Section */}
        <div className="pie-chart-card-content">
          <div className="chart-and-legend-container">
            {/* Chart */}
            <div className="pie-chart-container">
              <div className="chart-wrapper">
                <PieChart
                  data={data.chartData}
                  hole={hole}
                  size={size}
                  animated={animated}
                  gap={gap}
                />
                <div className={`chart-center-content ${animated ? 'animated' : ''}`}>
                  <div className="chart-center-value">{data.value}</div>
                  {data.badge && (
                    <div className="chart-center-badge-container">
                      <Badge
                        variant="green"
                        size="sm"
                        emphasis="medium"
                        icon="trending_up"
                        label={data.badge}
                      />
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Legend */}
            {showLegend && legendItems.length > 0 && (
              <div className="pie-chart-card-legend">
                {legendItems.map((item, index) => (
                  <div key={index} className="legend-item">
                    <div
                      className="legend-color"
                      style={{ backgroundColor: item.color }}
                    />
                    <div className="legend-content">
                      <span className="legend-text">{item.name}</span>
                      {item.percentage && (
                        <div className="legend-values">
                          <span className="legend-percentage">{item.percentage}</span>
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Footer outside container */}
      {showFooter && (
        <ContainerFooter
          size="standard"
          buttonLabel={footerButtonLabel}
          onButtonClick={handleFooterButtonClick}
        />
      )}
    </div>
  );
};