'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/month-picker.css';
import { Button } from '../button/Button';
import { InputText } from '../input-text/InputText';
import { PickerMenu } from '../picker-menu/PickerMenu';
import { MonthYear, DisabledMonth } from '../month-picker-content/MonthPickerContent';

export type MonthPickerVariant = 'dropdown-outlined' | 'dropdown-ghost' | 'input';

export interface MonthPickerProps {
  variant?: MonthPickerVariant;
  minYear?: number;
  maxYear?: number;
  disabled?: boolean;
  disabledMonths?: DisabledMonth[];
  label?: string;
  placeholder?: string;
  inputWidth?: string;
  showLabel?: boolean;
  showFooter?: boolean;
  value?: MonthYear | null;
  onChange?: (value: MonthYear | null) => void;
  onMonthYearSelect?: (value: MonthYear) => void;
}

export const MonthPicker: React.FC<MonthPickerProps> = ({
  variant = 'dropdown-outlined',
  minYear = 1998,
  maxYear = 2060,
  disabled = false,
  disabledMonths = [],
  label = 'Select Month',
  placeholder = 'Choose month and year',
  inputWidth = '200px',
  showLabel = true,
  showFooter = true,
  value,
  onChange,
  onMonthYearSelect,
}) => {
  const [selectedValue, setSelectedValue] = React.useState<MonthYear | null>(value || null);
  const [tempSelection, setTempSelection] = React.useState<MonthYear | null>(null);
  const [isMenuOpen, setIsMenuOpen] = React.useState(false);
  const [isMenuClosing, setIsMenuClosing] = React.useState(false);
  const containerRef = React.useRef<HTMLDivElement>(null);

  // Sync with external value prop
  React.useEffect(() => {
    if (value !== undefined) {
      setSelectedValue(value);
    }
  }, [value]);

  const getDisplayValue = (): string => {
    if (!selectedValue) return '';
    // US convention: MM/YYYY (01/2025)
    const month = (selectedValue.month + 1).toString().padStart(2, '0');
    return `${month}/${selectedValue.year}`;
  };

  const getButtonLabel = (): string => {
    return getDisplayValue() || placeholder;
  };

  const handleTriggerClick = (): void => {
    if (disabled) return;
    if (!isMenuOpen && showFooter) {
      // When opening with footer, initialize temp selection with current value
      setTempSelection(selectedValue);
    }
    setIsMenuOpen(!isMenuOpen);
  };

  const handleInputValueChange = (inputValue: string): void => {
    if (disabled) return;
    parseInputValue(inputValue);
  };

  const handleInputFocus = (): void => {
    if (disabled) return;
    if (!isMenuOpen && showFooter) {
      // When opening with footer, initialize temp selection with current value
      setTempSelection(selectedValue);
    }
    setIsMenuOpen(true);
  };

  const parseInputValue = (inputValue: string): void => {
    // Parse MM/YYYY format
    const match = inputValue.match(/^(\d{1,2})\/(\d{4})$/);
    if (match) {
      const month = parseInt(match[1], 10) - 1; // Convert to 0-based month
      const year = parseInt(match[2], 10);

      // Validate month and year
      if (
        month >= 0 &&
        month <= 11 &&
        year >= minYear &&
        year <= maxYear
      ) {
        const newValue: MonthYear = { month, year };
        setSelectedValue(newValue);
        onChange?.(newValue);
        onMonthYearSelect?.(newValue);
        return;
      }
    }
    // If parsing fails, keep the current selected value but update display
  };

  const handleMonthYearSelect = (monthYear: MonthYear): void => {
    if (showFooter) {
      // With footer: just update temp selection, don't apply yet
      setTempSelection(monthYear);
    } else {
      // Without footer: immediately apply and close
      setSelectedValue(monthYear);
      onChange?.(monthYear);
      onMonthYearSelect?.(monthYear);
      closeMenu();
    }
  };

  const handleMenuCancel = (): void => {
    // Reset temp selection and close
    setTempSelection(null);
    closeMenu();
  };

  const handleMenuApply = (): void => {
    // Apply the temp selection and close
    if (tempSelection) {
      setSelectedValue(tempSelection);
      onChange?.(tempSelection);
      onMonthYearSelect?.(tempSelection);
      setTempSelection(null);
    }
    closeMenu();
  };


  const closeMenu = (): void => {
    setIsMenuClosing(true);
    setTimeout(() => {
      setIsMenuOpen(false);
      setIsMenuClosing(false);
    }, 150);
  };

  const handleBackdropClick = (): void => {
    handleMenuCancel();
  };

  const handleCalendarIconClick = (): void => {
    handleTriggerClick();
  };

  return (
    <>
      <div className="month-picker-container" ref={containerRef}>
        {/* Dropdown Outlined Variant */}
        {variant === 'dropdown-outlined' && (
          <div className="month-picker-trigger" onClick={handleTriggerClick}>
            <Button
              hierarchy="secondary"
              type="outline"
              size="sm"
              icon="trailing"
              label={getButtonLabel()}
              iconName="expand_more"
              disabled={disabled}
            />
          </div>
        )}

        {/* Dropdown Ghost Variant */}
        {variant === 'dropdown-ghost' && (
          <div className="month-picker-trigger" onClick={handleTriggerClick}>
            <Button
              hierarchy="tertiary"
              type="ghost"
              size="sm"
              icon="trailing"
              label={getButtonLabel()}
              iconName="expand_more"
              disabled={disabled}
            />
          </div>
        )}

        {/* Input Variant */}
        {variant === 'input' && (
          <div className="month-picker-trigger input-field-container">
            <InputText
              label={label}
              placeholder={placeholder}
              value={getDisplayValue()}
              disabled={disabled}
              showTrailingIcon={true}
              trailingIcon="calendar_month"
              showHelpIcon={false}
              showHintText={false}
              showLabel={showLabel}
              width={inputWidth}
              onChange={handleInputValueChange}
              onFocus={handleInputFocus}
            />
            {/* Overlay for icon click detection */}
            <div className="calendar-icon-overlay" onClick={handleCalendarIconClick}></div>
          </div>
        )}

        {/* Month Picker Menu */}
        <div className="month-picker-menu-container">
          <PickerMenu
            visible={isMenuOpen}
            minYear={minYear}
            maxYear={maxYear}
            disabled={disabled}
            disabledMonths={disabledMonths}
            showFooter={showFooter}
            value={tempSelection || selectedValue}
            onChange={handleMonthYearSelect}
            onMonthYearSelect={handleMonthYearSelect}
            onCancel={handleMenuCancel}
            onApply={handleMenuApply}
          />
        </div>
      </div>

      {/* Backdrop */}
      {(isMenuOpen || isMenuClosing) && (
        <div className="month-picker-backdrop" onClick={handleBackdropClick}></div>
      )}
    </>
  );
};

export default MonthPicker;