'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/tokens/bellhop-typography.css';
import '../../../../../bellhopos-styles/src/components/button.css';

export type ButtonHierarchy = 'primary' | 'secondary' | 'tertiary' | 'quaternary';
export type ButtonType = 'solid' | 'outline' | 'ghost' | 'link';
export type ButtonIconType = 'none' | 'leading' | 'trailing' | 'only';
export type ButtonState = 'default' | 'hover' | 'focus' | 'disabled';
export type ButtonSize = 'xs' | 'sm' | 'md' | 'lg';

export interface ButtonProps {
  hierarchy?: ButtonHierarchy;
  type?: ButtonType;
  icon?: ButtonIconType;
  state?: ButtonState;
  size?: ButtonSize;
  label?: string;
  iconName?: string;
  disabled?: boolean;
  loading?: boolean;
  className?: string;
  onClick?: (event: React.MouseEvent<HTMLButtonElement>) => void;
}

export const Button: React.FC<ButtonProps> = ({
  hierarchy = 'primary',
  type = 'solid',
  icon = 'none',
  state = 'default',
  size = 'md',
  label = 'Label',
  iconName,
  disabled = false,
  loading = false,
  className,
  onClick,
}) => {
  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    if (!disabled && !loading && onClick) {
      onClick(event);
    }
  };

  const buttonClasses = [
    'btn',
    `btn-${hierarchy}`,
    `btn-${type}`,
    `btn-${size}`,
    `btn-icon-${icon}`,
    disabled || state === 'disabled' ? 'btn-disabled' : '',
    loading ? 'btn-loading' : '',
    state === 'focus' ? 'btn-focus' : '',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  const showLabel = icon !== 'only';
  const showLeadingIcon = icon === 'leading' && (iconName || loading);
  const showTrailingIcon = icon === 'trailing' && iconName && !loading;
  const showOnlyIcon = icon === 'only' && (iconName || loading);

  const getIconSizeClass = () => {
    switch (size) {
      case 'sm':
        return 'icon-md';
      case 'md':
        return 'icon-md';
      case 'lg':
        return 'icon-lg';
      default:
        return 'icon-md';
    }
  };

  const getTextSizeClass = () => {
    switch (size) {
      case 'sm':
        return 'text-sm';
      case 'md':
        return 'text-sm';
      case 'lg':
        return 'text-md';
      default:
        return 'text-sm';
    }
  };

  return (
    <button
      className={buttonClasses}
      disabled={disabled}
      onClick={handleClick}
    >
      {showLeadingIcon && (
        <span className={`btn-icon ${getIconSizeClass()}`}>
          {loading ? (
            <span className="btn-loading-icon">⟳</span>
          ) : (
            <span className="btn-icon-material material-symbols-outlined">{iconName}</span>
          )}
        </span>
      )}

      {showOnlyIcon && (
        <span className={`btn-icon ${getIconSizeClass()}`}>
          {loading ? (
            <span className="btn-loading-icon">⟳</span>
          ) : (
            <span className="btn-icon-material material-symbols-outlined">{iconName}</span>
          )}
        </span>
      )}

      {showLabel && (
        <span className={`btn-label ${getTextSizeClass()}`}>
          {label}
        </span>
      )}

      {showTrailingIcon && (
        <span className={`btn-icon ${getIconSizeClass()}`}>
          <span className="btn-icon-material material-symbols-outlined">{iconName}</span>
        </span>
      )}
    </button>
  );
};