'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/button.css'; // Temporary fallback
// import '../../../../../bellhopos-styles/src/components/button-icon.css';

export type ButtonIconHierarchy = 'primary' | 'secondary' | 'tertiary' | 'quaternary';
export type ButtonIconState = 'default' | 'hover' | 'focus' | 'disabled';
export type ButtonIconSize = 'xs' | 'sm' | 'md' | 'lg';

export interface ButtonIconProps {
  hierarchy?: ButtonIconHierarchy;
  state?: ButtonIconState;
  size?: ButtonIconSize;
  iconName: string;
  disabled?: boolean;
  loading?: boolean;
  onClick?: (event: React.MouseEvent<HTMLButtonElement>) => void;
  className?: string;
  'aria-label'?: string;
}

export const ButtonIcon: React.FC<ButtonIconProps> = ({
  hierarchy = 'primary',
  state = 'default',
  size = 'md',
  iconName,
  disabled = false,
  loading = false,
  onClick,
  className = '',
  'aria-label': ariaLabel,
}) => {
  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    if (!disabled && !loading && onClick) {
      onClick(event);
    }
  };

  const buttonClasses = [
    'btn', // Temporary: use button classes until button-icon.css exists
    `btn-${hierarchy}`,
    'btn-solid', // ButtonIcon always uses solid type
    `btn-${size}`,
    'btn-icon-only', // Temporary: use existing icon-only styling
    disabled || state === 'disabled' ? 'btn-disabled' : '',
    loading ? 'btn-loading' : '',
    state === 'focus' ? 'btn-focus' : '',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  const getIconSizeClass = () => {
    switch (size) {
      case 'xs':
        return 'icon-xs';
      case 'sm':
        return 'icon-sm';
      case 'md':
        return 'icon-md';
      case 'lg':
        return 'icon-lg';
      default:
        return 'icon-md';
    }
  };

  return (
    <button
      className={buttonClasses}
      disabled={disabled}
      onClick={handleClick}
      aria-label={ariaLabel || iconName}
    >
      <span className={`btn-icon ${getIconSizeClass()}`}>
        {loading ? (
          <span className="btn-loading-icon">⟳</span>
        ) : (
          <span className="btn-icon-material material-symbols-outlined">{iconName}</span>
        )}
      </span>
    </button>
  );
};

export default ButtonIcon;