'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/input-number.css';
import { ButtonIcon } from '../button-icon/ButtonIcon';
import { Tooltip } from '../tooltip/Tooltip';

export type InputNumberState = 'placeholder' | 'filled' | 'hover' | 'focused';
export type InputNumberError = boolean;

export interface InputNumberProps {
  state?: InputNumberState;
  error?: InputNumberError;
  required?: boolean;
  disabled?: boolean;
  showHelpIcon?: boolean;
  showLeadingIcon?: boolean;
  showLabel?: boolean;
  showHintText?: boolean;
  label?: string;
  placeholder?: string;
  hintText?: string;
  leadingIcon?: string;
  helpIconTooltip?: string;
  value?: number | null;
  min?: number | null;
  max?: number | null;
  step?: number;
  prefix?: string;
  suffix?: string;
  width?: string;
  onChange?: (value: number | null) => void;
  onFocus?: () => void;
  onBlur?: () => void;
  onHelpClick?: () => void;
  className?: string;
}

export const InputNumber: React.FC<InputNumberProps> = ({
  state = 'placeholder',
  error = false,
  required = false,
  disabled = false,
  showHelpIcon = false,
  showLeadingIcon = false,
  showLabel = true,
  showHintText = true,
  label = 'Amount',
  placeholder = '0',
  hintText = 'Enter a numeric value.',
  leadingIcon = 'tag',
  helpIconTooltip = 'Help',
  value,
  min = null,
  max = null,
  step = 1,
  prefix = '',
  suffix = '',
  width,
  onChange,
  onFocus,
  onBlur,
  onHelpClick,
  className = '',
}) => {
  const [internalState, setInternalState] = React.useState<InputNumberState>(state);
  const [isHovered, setIsHovered] = React.useState(false);
  const [isFocused, setIsFocused] = React.useState(false);
  const [showHelpTooltip, setShowHelpTooltip] = React.useState(false);
  const [internalValue, setInternalValue] = React.useState<number | null>(0);
  const [hasValidationError, setHasValidationError] = React.useState(false);
  const tooltipTimerRef = React.useRef<NodeJS.Timeout | null>(null);
  const inputRef = React.useRef<HTMLInputElement>(null);

  // Determine if this is controlled mode (value prop was explicitly passed)
  const isControlled = value !== undefined;
  const currentValue = isControlled ? value : internalValue;

  // Check if current value is within bounds
  const isOutOfBounds = React.useCallback((val: number | null): boolean => {
    if (val === null) return false;
    if (min !== null && val < min) return true;
    if (max !== null && val > max) return true;
    return false;
  }, [min, max]);

  // Update validation error state whenever value changes
  React.useEffect(() => {
    setHasValidationError(isOutOfBounds(currentValue));
  }, [currentValue, isOutOfBounds]);

  // Update internal state based on value
  React.useEffect(() => {
    if (currentValue !== null && currentValue !== undefined) {
      setInternalState('filled');
    } else if (!isFocused && !isHovered) {
      setInternalState('placeholder');
    }
  }, [currentValue, isFocused, isHovered]);

  const validateValue = React.useCallback((val: number): number => {
    if (min !== null && val < min) {
      return min;
    }
    if (max !== null && val > max) {
      return max;
    }
    return val;
  }, [min, max]);

  const updateValue = React.useCallback((newValue: number | null, allowOutOfBounds = false) => {
    let finalValue: number | null;

    if (newValue === null) {
      finalValue = null;
    } else if (allowOutOfBounds) {
      // Allow out of bounds values (for manual typing)
      finalValue = newValue;
    } else {
      // Constrain to bounds (for increment/decrement buttons)
      finalValue = validateValue(newValue);
    }

    if (!isControlled) {
      setInternalValue(finalValue);
    }

    onChange?.(finalValue);
  }, [isControlled, validateValue, onChange]);

  const handleInputChange = React.useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const inputValue = event.target.value;
    const numericValue = inputValue === '' ? null : parseFloat(inputValue);

    if (numericValue !== null && !isNaN(numericValue)) {
      updateValue(numericValue, true); // Allow out of bounds for manual typing
    } else if (inputValue === '') {
      updateValue(null, true);
    }
  }, [updateValue]);

  const increment = React.useCallback(() => {
    const baseValue = currentValue ?? 0;
    const newValue = baseValue + step;
    updateValue(newValue);
  }, [currentValue, step, updateValue]);

  const decrement = React.useCallback(() => {
    const baseValue = currentValue ?? 0;
    const newValue = baseValue - step;
    updateValue(newValue);
  }, [currentValue, step, updateValue]);

  const handleInputFocus = React.useCallback(() => {
    setIsFocused(true);
    setInternalState('focused');
    onFocus?.();
  }, [onFocus]);

  const handleInputBlur = React.useCallback(() => {
    setIsFocused(false);
    if (currentValue !== null && currentValue !== undefined) {
      setInternalState('filled');
    } else {
      setInternalState('placeholder');
    }
    onBlur?.();
  }, [currentValue, onBlur]);

  const handleMouseEnter = React.useCallback(() => {
    if (!isFocused) {
      setIsHovered(true);
      setInternalState('hover');
    }
  }, [isFocused]);

  const handleMouseLeave = React.useCallback(() => {
    setIsHovered(false);
    if (!isFocused) {
      if (currentValue !== null && currentValue !== undefined) {
        setInternalState('filled');
      } else {
        setInternalState('placeholder');
      }
    }
  }, [isFocused, currentValue]);

  const handleHelpIconClick = React.useCallback(() => {
    onHelpClick?.();
  }, [onHelpClick]);

  const handleHelpIconMouseEnter = React.useCallback(() => {
    if (tooltipTimerRef.current) {
      clearTimeout(tooltipTimerRef.current);
    }
    tooltipTimerRef.current = setTimeout(() => {
      setShowHelpTooltip(true);
    }, 300);
  }, []);

  const handleHelpIconMouseLeave = React.useCallback(() => {
    if (tooltipTimerRef.current) {
      clearTimeout(tooltipTimerRef.current);
      tooltipTimerRef.current = null;
    }
    setShowHelpTooltip(false);
  }, []);

  // Cleanup timer on unmount
  React.useEffect(() => {
    return () => {
      if (tooltipTimerRef.current) {
        clearTimeout(tooltipTimerRef.current);
      }
    };
  }, []);

  // Show error if either the error prop is true OR validation fails
  const showError = error || hasValidationError;

  // Generate error message for validation
  const getValidationErrorMessage = React.useCallback(() => {
    if (!hasValidationError || currentValue === null) return '';

    // If both min and max are defined, show range message
    if (min !== null && max !== null) {
      return `Enter a number between ${min} and ${max}.`;
    }

    // If only min is defined
    if (min !== null && currentValue < min) {
      return `Value must be at least ${min}`;
    }

    // If only max is defined
    if (max !== null && currentValue > max) {
      return `Value must be no more than ${max}`;
    }

    return '';
  }, [hasValidationError, currentValue, min, max]);

  // Determine the hint text to display
  const displayHintText = showError && hasValidationError ? getValidationErrorMessage() : hintText;

  const inputClasses = [
    'input-field',
    internalState === 'hover' || isHovered ? 'input-hover' : '',
    internalState === 'focused' || isFocused ? 'input-focused' : '',
    showError ? 'input-error' : '',
    disabled ? 'input-disabled' : '',
    showLeadingIcon ? 'input-icon-leading' : '',
    className
  ].filter(Boolean).join(' ');

  const textColorClass = (currentValue !== null && currentValue !== undefined) ? 'text-filled' : 'text-placeholder';

  const wrapperClasses = [
    'input-wrapper',
    className
  ].filter(Boolean).join(' ');

  return (
    <div className={wrapperClasses} style={{ width }}>
      <div className="input-with-label">
        {showLabel && (
          <div className="label-wrapper">
            <label className="label">{label}</label>
            {required && <span className="asterisk">*</span>}
            {showHelpIcon && (
              <div className="icon-with-tooltip">
                <span
                  className="help-icon material-symbols-outlined"
                  onMouseEnter={handleHelpIconMouseEnter}
                  onMouseLeave={handleHelpIconMouseLeave}
                  onClick={handleHelpIconClick}
                >
                  help
                </span>
                <Tooltip
                  text={helpIconTooltip}
                  position="top"
                  visible={showHelpTooltip}
                />
              </div>
            )}
          </div>
        )}
        <div
          className={inputClasses}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >
          <div className="input-content">
            {showLeadingIcon && (
              <span className="leading-icon material-symbols-outlined">
                {leadingIcon}
              </span>
            )}
            {prefix && <span className="prefix-text">{prefix}</span>}
            <input
              ref={inputRef}
              type="number"
              value={currentValue ?? ''}
              placeholder={placeholder}
              disabled={disabled}
              className={`input-element ${textColorClass}`}
              onChange={handleInputChange}
              onFocus={handleInputFocus}
              onBlur={handleInputBlur}
              min={min ?? undefined}
              max={max ?? undefined}
              step={step}
            />
            {suffix && <span className="suffix-text">{suffix}</span>}
            <ButtonIcon
              hierarchy="tertiary"
              size="xs"
              iconName="remove"
              disabled={disabled || (min !== null && currentValue !== null && currentValue <= min)}
              onClick={decrement}
              aria-label="Decrease value"
            />
            <ButtonIcon
              hierarchy="tertiary"
              size="xs"
              iconName="add"
              disabled={disabled || (max !== null && currentValue !== null && currentValue >= max)}
              onClick={increment}
              aria-label="Increase value"
            />
          </div>
        </div>
      </div>
      {showHintText && displayHintText && (
        <div className={`hint-text ${showError ? 'hint-error' : ''}`}>
          {displayHintText}
        </div>
      )}
    </div>
  );
};

export default InputNumber;