'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/radio-button.css';

export type RadioButtonSize = 'sm' | 'md';

export interface RadioButtonProps {
  size?: RadioButtonSize;
  disabled?: boolean;
  value?: any;
  name?: string;
  selected?: boolean;
  defaultSelected?: boolean;
  id?: string;
  className?: string;
  onChange?: (value: any) => void;
}

export const RadioButton: React.FC<RadioButtonProps> = ({
  size = 'md',
  disabled = false,
  value = null,
  name = '',
  selected,
  defaultSelected = false,
  id,
  className = '',
  onChange,
}) => {
  const [internalSelected, setInternalSelected] = React.useState(defaultSelected);
  const [isFocused, setIsFocused] = React.useState(false);
  const [isHovered, setIsHovered] = React.useState(false);

  // Determine if controlled or uncontrolled
  const isControlled = selected !== undefined;
  const isSelected = isControlled ? selected : internalSelected;

  const radioClasses = React.useMemo(() => {
    const classes = ['radio', `radio-${size}`];

    if (isSelected) {
      classes.push('radio-selected');
    }

    if (disabled) {
      classes.push('radio-disabled');
    }

    if (isFocused && !disabled) {
      classes.push('radio-focused');
    }

    if (isHovered && !disabled) {
      classes.push('radio-hover');
    }

    if (className) {
      classes.push(className);
    }

    return classes.join(' ');
  }, [size, isSelected, disabled, isFocused, isHovered, className]);

  const handleClick = React.useCallback(() => {
    if (disabled || isSelected) return; // Don't toggle if already selected

    // Always update internal state for uncontrolled components
    if (!isControlled) {
      setInternalSelected(true);
    }

    // Always call onChange if provided
    onChange?.(value);
  }, [disabled, isSelected, isControlled, value, onChange]);

  const handleFocus = React.useCallback(() => {
    setIsFocused(true);
  }, []);

  const handleBlur = React.useCallback(() => {
    setIsFocused(false);
  }, []);

  const handleMouseEnter = React.useCallback(() => {
    setIsHovered(true);
  }, []);

  const handleMouseLeave = React.useCallback(() => {
    setIsHovered(false);
  }, []);

  const handleKeyDown = React.useCallback((event: React.KeyboardEvent) => {
    if (event.key === ' ' || event.key === 'Enter') {
      event.preventDefault();
      handleClick();
    }
  }, [handleClick]);

  return (
    <div
      id={id}
      className={radioClasses}
      onClick={handleClick}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onFocus={handleFocus}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      tabIndex={disabled ? -1 : 0}
      role="radio"
      aria-checked={isSelected}
      aria-disabled={disabled}
    >
      <div className="radio-dot"></div>
    </div>
  );
};