'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/month-picker-content.css';

export interface MonthYear {
  month: number; // 0-11 (January = 0, December = 11)
  year: number;
}

export interface DisabledMonth {
  month: number;
  year: number;
}

export interface MonthPickerContentProps {
  minYear?: number;
  maxYear?: number;
  disabled?: boolean;
  disabledMonths?: DisabledMonth[];
  scrollable?: boolean;
  selectedMonth?: number | null;
  selectedYear?: number | null;
  height?: string;
  value?: MonthYear | null;
  onChange?: (value: MonthYear | null) => void;
  onMonthYearSelect?: (selection: MonthYear) => void;
}

export const MonthPickerContent: React.FC<MonthPickerContentProps> = ({
  minYear = 1998,
  maxYear = 2060,
  disabled = false,
  disabledMonths = [],
  scrollable = true,
  selectedMonth: propSelectedMonth = null,
  selectedYear: propSelectedYear = null,
  height = '375px',
  value,
  onChange,
  onMonthYearSelect,
}) => {
  const monthPickerContentRef = React.useRef<HTMLDivElement>(null);
  const [isUsingKeyboard, setIsUsingKeyboard] = React.useState(false);

  // Abbreviated month names as per Figma
  const months = [
    'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
    'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
  ];

  // Generate years array
  const years = Array.from({ length: maxYear - minYear + 1 }, (_, i) => minYear + i);

  // Track current date
  const currentDate = new Date();
  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  // Internal selected state
  const [internalSelectedMonth, setInternalSelectedMonth] = React.useState<number | null>(() => {
    if (value) return value.month;
    if (propSelectedMonth !== null) return propSelectedMonth;

    // Initialize with current date if within range
    if (currentYear >= minYear && currentYear <= maxYear) {
      return currentMonth;
    } else {
      return currentMonth;
    }
  });

  const [internalSelectedYear, setInternalSelectedYear] = React.useState<number | null>(() => {
    if (value) return value.year;
    if (propSelectedYear !== null) return propSelectedYear;

    // Initialize with current date if within range
    if (currentYear >= minYear && currentYear <= maxYear) {
      return currentYear;
    } else {
      // If current year is out of range, select closest available year
      return currentYear < minYear ? minYear : maxYear;
    }
  });

  // Sync with props
  React.useEffect(() => {
    if (value) {
      setInternalSelectedMonth(value.month);
      setInternalSelectedYear(value.year);
    } else if (propSelectedMonth !== null || propSelectedYear !== null) {
      setInternalSelectedMonth(propSelectedMonth);
      setInternalSelectedYear(propSelectedYear);
    }
  }, [value, propSelectedMonth, propSelectedYear]);

  // Scroll to selected year
  const scrollToSelectedYearInstantly = React.useCallback(() => {
    if (internalSelectedYear !== null && monthPickerContentRef.current && scrollable) {
      const yearElement = monthPickerContentRef.current.querySelector(
        `#year-${internalSelectedYear}`
      ) as HTMLElement;

      if (yearElement) {
        const container = monthPickerContentRef.current;
        const containerHeight = container.clientHeight;
        const yearElementTop = yearElement.offsetTop;
        const yearElementHeight = yearElement.offsetHeight;

        const isFirstYear = internalSelectedYear === minYear;
        const isLastYear = internalSelectedYear === maxYear;

        if (!isFirstYear && !isLastYear) {
          const scrollOffset = 50;
          const scrollTop = yearElementTop - containerHeight / 2 + yearElementHeight / 2 + scrollOffset;
          container.scrollTop = Math.max(0, scrollTop);
        } else if (isFirstYear) {
          container.scrollTop = 0;
        } else {
          container.scrollTop = container.scrollHeight;
        }
      }
    }
  }, [internalSelectedYear, minYear, maxYear, scrollable]);

  // Scroll to selected year only on mount
  React.useEffect(() => {
    if (scrollable) {
      setTimeout(scrollToSelectedYearInstantly, 0);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [scrollable]); // Only depend on scrollable, not on scrollToSelectedYearInstantly

  const handleKeyDown = () => {
    setIsUsingKeyboard(true);
  };

  const handleMouseDown = () => {
    setIsUsingKeyboard(false);
  };

  const isCurrentMonth = (monthIndex: number, year: number): boolean => {
    return currentMonth === monthIndex && currentYear === year;
  };

  const isMonthSelectable = (monthIndex: number, year: number): boolean => {
    // Check if year is within range
    if (year < minYear || year > maxYear) {
      return false;
    }

    // Check if month is in disabled list
    return !disabledMonths.some(
      (disabledMonth) => disabledMonth.month === monthIndex && disabledMonth.year === year
    );
  };

  const selectMonth = (monthIndex: number, year: number): void => {
    if (disabled || !isMonthSelectable(monthIndex, year)) {
      return;
    }

    setInternalSelectedMonth(monthIndex);
    setInternalSelectedYear(year);

    const selection: MonthYear = {
      month: monthIndex,
      year: year,
    };

    onChange?.(selection);
    onMonthYearSelect?.(selection);
  };

  const handleMonthButtonFocus = (event: React.FocusEvent<HTMLButtonElement>): void => {
    if (isUsingKeyboard) {
      event.target.classList.add('keyboard-focused');
    }
  };

  const handleMonthButtonBlur = (event: React.FocusEvent<HTMLButtonElement>): void => {
    event.target.classList.remove('keyboard-focused');
  };

  const getMonthLabel = (monthIndex: number): string => {
    return months[monthIndex];
  };

  return (
    <div
      className={`month-picker-content animate-slide-up-enter ${scrollable ? 'scrollable' : ''}`}
      style={{ height }}
      ref={monthPickerContentRef}
      onKeyDown={handleKeyDown}
      onMouseDown={handleMouseDown}
    >
      <div className="calendar">
        {years.map((year, yearIndex) => (
          <div key={year} className="year-section" id={`year-${year}`}>
            <div className="year-month-container">
              <div className="year-label">{year}</div>

              <div className="months-row">
                {/* First row: Jan-Jun */}
                <div className="month-row">
                  {months.slice(0, 6).map((monthName, monthIndex) => (
                    <button
                      key={monthIndex}
                      className={`month-button ${
                        !isMonthSelectable(monthIndex, year) ? 'inactive' : ''
                      } ${
                        internalSelectedMonth === monthIndex && internalSelectedYear === year
                          ? 'selected'
                          : ''
                      } ${isCurrentMonth(monthIndex, year) ? 'today' : ''}`}
                      disabled={!isMonthSelectable(monthIndex, year)}
                      onClick={() => selectMonth(monthIndex, year)}
                      onFocus={handleMonthButtonFocus}
                      onBlur={handleMonthButtonBlur}
                    >
                      {getMonthLabel(monthIndex)}
                    </button>
                  ))}
                </div>

                {/* Second row: Jul-Dec */}
                <div className="month-row">
                  {months.slice(6, 12).map((monthName, monthIndex) => {
                    const actualMonthIndex = monthIndex + 6;
                    return (
                      <button
                        key={actualMonthIndex}
                        className={`month-button ${
                          !isMonthSelectable(actualMonthIndex, year) ? 'inactive' : ''
                        } ${
                          internalSelectedMonth === actualMonthIndex && internalSelectedYear === year
                            ? 'selected'
                            : ''
                        } ${isCurrentMonth(actualMonthIndex, year) ? 'today' : ''}`}
                        disabled={!isMonthSelectable(actualMonthIndex, year)}
                        onClick={() => selectMonth(actualMonthIndex, year)}
                        onFocus={handleMonthButtonFocus}
                        onBlur={handleMonthButtonBlur}
                      >
                        {getMonthLabel(actualMonthIndex)}
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* Section Divider (not for last year) */}
            {yearIndex < years.length - 1 && (
              <div className="section-divider">
                <div className="divider-container">
                  <div className="divider-line"></div>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default MonthPickerContent;