'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/trend-chart.css';

export type TrendDirection = 'positive' | 'negative' | 'neutral';
export type TrendVariant = 'line-only' | 'fill-only' | 'line-fill';

export interface TrendChartProps {
  trend?: TrendDirection;
  data?: number[];
  animated?: boolean;
  variant?: TrendVariant;
  width?: number;
  height?: number;
}

export const TrendChart: React.FC<TrendChartProps> = ({
  trend = 'positive',
  data = [20, 45, 30, 60, 35, 70, 40],
  animated = true,
  variant = 'line-only',
  width = 112,
  height = 56,
}) => {
  const { pathData, backgroundPath, strokeColor, fillColor } = React.useMemo(() => {
    const normalizedPoints = normalizeData(data, width, height);
    const pathData = generateRealisticPath(normalizedPoints);
    const backgroundPath = variant !== 'line-only' ? generateBackgroundPath(normalizedPoints, height) : '';

    const strokeColor = getStrokeColor(trend);
    const fillColor = getFillColor(trend);

    return { pathData, backgroundPath, strokeColor, fillColor };
  }, [data, trend, variant, width, height]);

  const containerClasses = React.useMemo(() => {
    const classes = [
      'trend-chart',
      `trend-chart-${trend}`,
      `trend-chart-${variant}`,
    ];
    if (animated) {
      classes.push('trend-chart-animated');
    }
    return classes.join(' ');
  }, [trend, variant, animated]);

  const gradientId = `gradient-${trend}`;

  return (
    <div className={containerClasses}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="chart-svg"
      >
        <defs>
          <linearGradient
            id={gradientId}
            x1="0%"
            y1="0%"
            x2="0%"
            y2="100%"
          >
            <stop
              offset="0%"
              stopColor={fillColor}
              stopOpacity={variant === 'fill-only' ? 0.4 : 0.2}
            />
            <stop
              offset="100%"
              stopColor={fillColor}
              stopOpacity={variant === 'fill-only' ? 0.1 : 0.05}
            />
          </linearGradient>
        </defs>

        {/* Background fill (for fill-only and line-fill variants) */}
        {backgroundPath && variant !== 'line-only' && (
          <path
            className="chart-background"
            d={backgroundPath}
            fill={`url(#${gradientId})`}
          />
        )}

        {/* Stroke line (for line-only and line-fill variants) */}
        {pathData && variant !== 'fill-only' && (
          <path
            className="chart-line"
            d={pathData}
            stroke={strokeColor}
            strokeWidth="2"
            fill="none"
          />
        )}
      </svg>
    </div>
  );
};

function normalizeData(data: number[], width: number, height: number): Array<{ x: number; y: number }> {
  const maxValue = Math.max(...data);
  const minValue = Math.min(...data);
  const range = maxValue - minValue;

  return data.map((value, index) => ({
    x: (index / (data.length - 1)) * width,
    y: height - ((value - minValue) / range) * (height - 20) - 10,
  }));
}

function generateRealisticPath(points: Array<{ x: number; y: number }>): string {
  if (points.length < 2) return '';

  let path = `M ${points[0].x} ${points[0].y}`;

  for (let i = 1; i < points.length; i++) {
    const prev = points[i - 1];
    const curr = points[i];
    const tension = 0.5; // realistic tension value

    const cp1x = prev.x + (curr.x - prev.x) * tension;
    const cp1y = prev.y;
    const cp2x = curr.x - (curr.x - prev.x) * tension;
    const cp2y = curr.y;

    path += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${curr.x} ${curr.y}`;
  }

  return path;
}

function generateBackgroundPath(points: Array<{ x: number; y: number }>, height: number): string {
  if (points.length < 2) return '';

  let path = `M ${points[0].x} ${height}`;
  path += ` L ${points[0].x} ${points[0].y}`;

  // Follow the same realistic curve as the line
  for (let i = 1; i < points.length; i++) {
    const prev = points[i - 1];
    const curr = points[i];
    const tension = 0.5;

    const cp1x = prev.x + (curr.x - prev.x) * tension;
    const cp1y = prev.y;
    const cp2x = curr.x - (curr.x - prev.x) * tension;
    const cp2y = curr.y;
    path += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${curr.x} ${curr.y}`;
  }

  path += ` L ${points[points.length - 1].x} ${height}`;
  path += ' Z';

  return path;
}

function getStrokeColor(trend: TrendDirection): string {
  switch (trend) {
    case 'positive':
      return 'var(--color-success-500)';
    case 'negative':
      return 'var(--color-error-500)';
    case 'neutral':
      return 'var(--color-neutral-500)';
    default:
      return 'var(--color-neutral-500)';
  }
}

function getFillColor(trend: TrendDirection): string {
  switch (trend) {
    case 'positive':
      return 'var(--color-success-600)';
    case 'negative':
      return 'var(--color-error-600)';
    case 'neutral':
      return 'var(--color-neutral-600)';
    default:
      return 'var(--color-neutral-600)';
  }
}