'use client';

import React from 'react';
import { Illustrations, IllustrationSize } from '../illustrations/illustrations';
import { Button } from '../button';
import '../../../../../bellhopos-styles/src/components/empty-state.css';

export interface EmptyStateAction {
  label: string;
  type: 'primary' | 'secondary';
  icon?: string;
  action: () => void;
}

export interface EmptyStateProps {
  title?: string;
  description?: string;
  illustrationSize?: IllustrationSize;
  illustrationPath?: string;
  actions?: EmptyStateAction[];
  maxWidth?: string;
}

export const EmptyState: React.FC<EmptyStateProps> = ({
  title = 'No items found',
  description = 'There are no items to display at the moment.',
  illustrationSize = 'md',
  illustrationPath = '/illustrations/Search-not-found.svg',
  actions = [],
  maxWidth = '512px',
}) => {
  const handleActionClick = (action: EmptyStateAction) => {
    action.action();
  };

  return (
    <div className="empty-state" style={{ maxWidth }}>
      <div className="empty-state-content">
        {/* Illustration */}
        <div className="empty-state-illustration">
          <Illustrations
            size={illustrationSize}
            svgPath={illustrationPath}
            alt="Empty state illustration"
          />
        </div>

        {/* Text Content */}
        <div className="empty-state-text">
          <h3 className="empty-state-title">{title}</h3>
          <p className="empty-state-description">{description}</p>
        </div>
      </div>

      {/* Actions */}
      {actions.length > 0 && (
        <div className="empty-state-actions">
          {actions.map((action, index) => (
            <Button
              key={index}
              hierarchy={action.type}
              type={action.type === 'secondary' ? 'outline' : 'solid'}
              size="md"
              label={action.label}
              iconName={action.icon}
              icon={action.icon ? 'leading' : 'none'}
              onClick={() => handleActionClick(action)}
            />
          ))}
        </div>
      )}
    </div>
  );
};

EmptyState.displayName = 'EmptyState';