'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/badge.css';

export type BadgeVariant =
  | 'gray'
  | 'blue'
  | 'red'
  | 'yellow'
  | 'green'
  | 'purple'
  | 'pink'
  | 'orange';
export type BadgeSize = 'sm' | 'md' | 'lg';
export type BadgeEmphasis = 'high' | 'medium' | 'low';

export interface BadgeProps {
  variant?: BadgeVariant;
  size?: BadgeSize;
  emphasis?: BadgeEmphasis;
  label?: string;
  icon?: string;
  dismissible?: boolean;
  disabled?: boolean;
  onDismiss?: () => void;
}

export const Badge: React.FC<BadgeProps> = ({
  variant = 'gray',
  size = 'md',
  emphasis = 'high',
  label = 'Label',
  icon,
  dismissible = false,
  disabled = false,
  onDismiss,
}) => {
  const handleDismiss = (e: React.MouseEvent<HTMLButtonElement>) => {
    e.stopPropagation();
    if (dismissible && !disabled && onDismiss) {
      onDismiss();
    }
  };

  const badgeClasses = [
    'badge',
    `badge-${variant}`,
    `badge-${size}`,
    `badge-${emphasis}`,
    disabled ? 'badge-disabled' : '',
  ]
    .filter(Boolean)
    .join(' ');

  const iconColorClass = `badge-icon-${variant}-${emphasis}`;

  return (
    <span className={badgeClasses}>
      {/* Icon (if provided) */}
      {icon && (
        <span
          className={`material-symbols-outlined ${iconColorClass} ${
            icon === 'dot' ? 'badge-icon-dot' : 'badge-icon-custom'
          }`}
        >
          {icon === 'dot' ? 'fiber_manual_record' : icon}
        </span>
      )}

      {/* Label */}
      <span className="badge-label">{label}</span>

      {/* Dismiss button (if dismissible) */}
      {dismissible && (
        <button
          className="badge-dismiss"
          onClick={handleDismiss}
          disabled={disabled}
          type="button"
          aria-label="Dismiss"
        >
          <span className={`material-symbols-outlined badge-dismiss-icon ${iconColorClass}`}>
            close
          </span>
        </button>
      )}
    </span>
  );
};