'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/logo-box.css';
import { ProductSwitcher, Product } from '../product-switcher/ProductSwitcher';

export type LogoType = 'actabl' | 'al' | 'he' | 'ps' | 'tr';

export interface LogoBoxProps {
  logoType?: LogoType;
  products?: Product[];
  onProductSelect?: (product: Product) => void;
  className?: string;
}

export const LogoBox: React.FC<LogoBoxProps> = ({
  logoType = 'actabl',
  products = [
    {
      id: 'alice',
      name: 'Alice',
      description: 'Housekeeping & Guest Services',
      logo: './assets/logos/AL.svg',
    },
    {
      id: 'hotel-effectiveness',
      name: 'Hotel Effectiveness',
      description: 'Labor planning',
      logo: './assets/logos/HE.svg',
    },
    {
      id: 'profit-sword',
      name: 'ProfitSword',
      description: 'B.I and Finance',
      logo: './assets/logos/PS.svg',
    },
    {
      id: 'transcendent',
      name: 'Transcendent',
      description: 'Asset Management & CapEx',
      logo: './assets/logos/TR.svg',
    },
  ],
  onProductSelect,
  className,
}) => {
  const [isOpen, setIsOpen] = React.useState(false);
  const [anchorPosition, setAnchorPosition] = React.useState({ top: 0, left: 0 });
  const logoActiveRef = React.useRef<HTMLDivElement>(null);

  const handleLogoClick = () => {
    if (logoActiveRef.current) {
      const rect = logoActiveRef.current.getBoundingClientRect();
      setAnchorPosition({
        top: rect.bottom + 8,
        left: rect.left,
      });
      setIsOpen(!isOpen);
    }
  };

  const handleClose = () => {
    setIsOpen(false);
  };

  const handleProductSelect = (product: Product) => {
    onProductSelect?.(product);
    setIsOpen(false);
  };

  const logoBoxClasses = [
    'logo-box',
    isOpen ? 'dropdown-open' : '',
    className
  ]
    .filter(Boolean)
    .join(' ');

  const logoClasses = [
    'logo',
    `logo-${logoType}`
  ]
    .filter(Boolean)
    .join(' ');

  const getLogoSrc = () => {
    switch (logoType) {
      case 'actabl':
        return './assets/logos/actabl.svg';
      case 'al':
        return './assets/logos/AL.svg';
      case 'he':
        return './assets/logos/HE.svg';
      case 'ps':
        return './assets/logos/PS.svg';
      case 'tr':
        return './assets/logos/TR.svg';
      default:
        return './assets/logos/actabl.svg';
    }
  };

  return (
    <>
      <div className={logoBoxClasses}>
        <div
          ref={logoActiveRef}
          className="logo-active"
          onClick={handleLogoClick}
        >
          <img
            src={getLogoSrc()}
            alt={`${logoType} logo`}
            className={logoClasses}
          />
        </div>
        <div className="logo-more-products"></div>
      </div>

      <ProductSwitcher
        isOpen={isOpen}
        onClose={handleClose}
        anchorPosition={anchorPosition}
        products={products}
        onProductSelect={handleProductSelect}
      />
    </>
  );
};

export default LogoBox;