'use client';

import * as React from 'react';
import { ChildItem } from './PageNavigation';
import { PageNavigationChild } from './PageNavigationChild';
import { Button } from '../button/Button';

export interface PageNavigationMultiLevelProps {
  label: string;
  icon?: string;
  children: ChildItem[];
  isExpanded?: boolean;
  onItemClick: (childIndex?: number) => void;
  className?: string;
}

export const PageNavigationMultiLevel: React.FC<PageNavigationMultiLevelProps> = ({
  label,
  icon = 'radio_button_unchecked',
  children,
  isExpanded = false,
  onItemClick,
  className = '',
}) => {
  const [isHovered, setIsHovered] = React.useState(false);
  const [isAnimating, setIsAnimating] = React.useState(false);
  const [animationClass, setAnimationClass] = React.useState('');

  const hasActiveChild = React.useMemo(() => {
    return children.some(child => child.isActive);
  }, [children]);

  // Handle expand/collapse animations
  React.useEffect(() => {
    if (isExpanded) {
      // Expanding
      setIsAnimating(true);
      setAnimationClass('animate-slide-down-enter');
    } else if (!isExpanded && isAnimating) {
      // Collapsing
      setAnimationClass('animate-slide-down-exit');
      const timer = setTimeout(() => {
        setIsAnimating(false);
        setAnimationClass('');
      }, 150); // Match animation duration
      return () => clearTimeout(timer);
    }
  }, [isExpanded, isAnimating]);


  const itemClasses = [
    'page-navigation-multi-level',
    'page-navigation-animate-smooth',
    hasActiveChild ? 'has-active-child' : '',
    isExpanded ? 'expanded' : '',
    className,
  ].filter(Boolean).join(' ');

  const handleParentClick = () => {
    onItemClick();
  };

  const handleChildClick = (childIndex: number) => {
    onItemClick(childIndex);
  };

  return (
    <div className={itemClasses}>
      <div
        className="page-navigation-multi-level-parent"
        onClick={handleParentClick}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        <div className="page-navigation-item-content">
          {!isHovered && (
            <span className="page-navigation-item-icon material-symbols-outlined">
              {icon}
            </span>
          )}
          {isHovered && (
            <span className={`page-navigation-chevron-icon material-symbols-outlined ${isExpanded ? 'expanded' : ''}`}>
              expand_more
            </span>
          )}
          <span className="page-navigation-item-label">{label}</span>
          <Button
            hierarchy="tertiary"
            icon="only"
            size="xs"
            iconName="add"
            onClick={(e) => {
              e.stopPropagation();
              // Handle add action here
            }}
          />
        </div>
      </div>

      {(isExpanded || isAnimating) && (
        <div className={`page-navigation-children ${animationClass}`}>
          {children.map((child, index) => (
            <PageNavigationChild
              key={index}
              label={child.label}
              badge={child.badge}
              showBadge={child.showBadge}
              isActive={child.isActive}
              onItemClick={() => handleChildClick(index)}
            />
          ))}
        </div>
      )}
    </div>
  );
};