'use client';

import React from 'react';
import '../../../../../bellhopos-styles/src/components/page-navigation.css';

export interface PageNavigationChildProps {
  label: string;
  badge?: string | number;
  isActive?: boolean;
  onItemClick: () => void;
  className?: string;
}

export const PageNavigationChild: React.FC<PageNavigationChildProps> = ({
  label,
  badge,
  isActive = false,
  onItemClick,
  className = '',
}) => {
  const itemClasses = [
    'page-navigation-child',
    isActive ? 'active' : '',
    className,
  ].filter(Boolean).join(' ');

  const handleClick = () => {
    onItemClick();
  };

  return (
    <div className={itemClasses} onClick={handleClick}>
      <div className="page-navigation-child-content">
        <span className="page-navigation-child-label">{label}</span>
        {badge && (
          <span className="page-navigation-child-badge">
            {badge}
          </span>
        )}
      </div>
    </div>
  );
};