'use client';

import * as React from 'react';
import { DropdownMenu, DropdownMenuItem } from '../dropdown-menu/DropdownMenu';
import '../../../../../bellhopos-styles/src/components/property-switcher.css';

export interface PropertyOption {
  id: string;
  name: string;
  type: 'portfolio' | 'region' | 'property';
}

export interface PropertySwitcherProps {
  selectedProperty?: string;
  properties?: PropertyOption[];
  onPropertyChange?: (propertyName: string) => void;
  className?: string;
}

export const PropertySwitcher: React.FC<PropertySwitcherProps> = ({
  selectedProperty = 'Solstice Hospitality Group',
  properties = [],
  onPropertyChange,
  className = '',
}) => {
  const [isExpanded, setIsExpanded] = React.useState(false);
  const switcherRef = React.useRef<HTMLDivElement>(null);

  const dropdownMenuItems: DropdownMenuItem[] = React.useMemo(() => {
    const items: DropdownMenuItem[] = [];

    properties.forEach((property, index) => {
      if (property.type === 'portfolio') {
        items.push({
          id: property.id,
          label: property.name,
          icon: 'business',
        });
        // Add divider after portfolio
        items.push({
          id: `divider-${index}`,
          divider: true,
        });
      } else if (property.type === 'property') {
        items.push({
          id: property.id,
          label: property.name,
          icon: 'location_on',
        });
      }
    });

    return items;
  }, [properties]);

  const handleToggle = React.useCallback(() => {
    setIsExpanded(!isExpanded);
  }, [isExpanded]);

  const handleDropdownItemClick = React.useCallback((item: DropdownMenuItem) => {
    if (item.divider) return;

    const property = properties.find((p) => p.id === item.id);
    if (property) {
      onPropertyChange?.(property.name);
      setIsExpanded(false);
    }
  }, [properties, onPropertyChange]);

  // Handle clicking outside to close dropdown
  React.useEffect(() => {
    const handleDocumentClick = (event: MouseEvent) => {
      if (isExpanded && switcherRef.current && !switcherRef.current.contains(event.target as Node)) {
        setIsExpanded(false);
      }
    };

    document.addEventListener('click', handleDocumentClick);
    return () => {
      document.removeEventListener('click', handleDocumentClick);
    };
  }, [isExpanded]);

  const containerClasses = React.useMemo(() => {
    const classes = ['property-switcher', className];
    if (isExpanded) classes.push('expanded');
    return classes.filter(Boolean).join(' ');
  }, [isExpanded, className]);

  return (
    <div ref={switcherRef} className={containerClasses}>
      <button
        className="property-selector"
        onClick={handleToggle}
        aria-expanded={isExpanded}
        aria-label={`Property selector: ${selectedProperty}`}
      >
        <span className="property-name">{selectedProperty}</span>
        <span
          className="material-symbols-outlined expand-icon"
          aria-label={isExpanded ? 'Collapse Options' : 'Expand Options'}
        >
          {isExpanded ? 'unfold_less' : 'unfold_more'}
        </span>
      </button>

      <div className="dropdown-menu-container">
        <DropdownMenu
          visible={isExpanded}
          showIcons={true}
          scrollable={true}
          menuItems={dropdownMenuItems}
          onItemClick={handleDropdownItemClick}
        />
      </div>
    </div>
  );
};