'use client';

import React from 'react';
import { Badge } from '../badge/Badge';

export interface PageNavigationChildProps {
  label: string;
  badge?: string | number;
  showBadge?: boolean;
  isActive?: boolean;
  onItemClick: () => void;
  className?: string;
}

export const PageNavigationChild: React.FC<PageNavigationChildProps> = ({
  label,
  badge,
  showBadge = true,
  isActive = false,
  onItemClick,
  className = '',
}) => {
  const itemClasses = [
    'page-navigation-child',
    isActive ? 'active' : '',
    className,
  ].filter(Boolean).join(' ');

  const handleClick = () => {
    onItemClick();
  };

  return (
    <div className={itemClasses} onClick={handleClick}>
      <div className="page-navigation-child-content">
        <span className="page-navigation-child-label">{label}</span>
        {badge && showBadge && (
          <Badge
            label={String(badge)}
            size="sm"
            variant="gray"
            emphasis="medium"
          />
        )}
      </div>
    </div>
  );
};