import React from 'react';
import './LoaderSpinner.css';

export type LoaderSize = 'sm' | 'md' | 'lg' | 'xl';

export interface LoaderSpinnerProps {
  size?: LoaderSize;
  overlay?: boolean;
  overlayMessage?: string;
  showMessage?: boolean;
  message?: string;
}

export const LoaderSpinner: React.FC<LoaderSpinnerProps> = ({
  size = 'md',
  overlay = false,
  overlayMessage = '',
  showMessage = false,
  message = 'Loading...',
}) => {
  const renderSpinner = () => (
    <div className="loader-spinner">
      <div className="spinner-gradient">
        <svg className="gradient-svg" viewBox="0 0 50 50">
          <defs>
            <linearGradient
              id="bellhop-gradient"
              x1="0%"
              y1="0%"
              x2="0%"
              y2="100%"
            >
              <stop offset="0%" style={{ stopColor: 'var(--color-accent-300)' }} />
              <stop offset="51%" style={{ stopColor: 'var(--color-brand-400)' }} />
              <stop offset="100%" style={{ stopColor: 'var(--color-brand-800)' }} />
            </linearGradient>
          </defs>
          <circle
            className="gradient-path"
            cx="25"
            cy="25"
            r="20"
            fill="none"
            stroke="url(#bellhop-gradient)"
            strokeWidth="4"
            strokeLinecap="round"
          />
        </svg>
      </div>
    </div>
  );

  const renderMessage = (isOverlay: boolean) => {
    const shouldShowMessage = isOverlay 
      ? (showMessage || overlayMessage)
      : showMessage;
    
    if (!shouldShowMessage) return null;

    return (
      <div className="loader-message">
        {isOverlay ? (overlayMessage || message) : message}
      </div>
    );
  };

  if (overlay) {
    return (
      <div className="loader-overlay">
        <div className="loader-overlay-content">
          <div className={`loader-container size-${size}`}>
            {renderSpinner()}
          </div>
          {renderMessage(true)}
        </div>
      </div>
    );
  }

  return (
    <div className={`loader-container size-${size}`}>
      {renderSpinner()}
      {renderMessage(false)}
    </div>
  );
};