import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/container.css';

export interface ContainerProps {
  children: React.ReactNode;
  withFooter?: boolean;
}

export const Container: React.FC<ContainerProps> = ({ children, withFooter = false }) => {
  const containerClasses = ['container', withFooter ? 'container-with-footer' : ''].filter(Boolean).join(' ');

  return (
    <div className={containerClasses}>
      {children}
    </div>
  );
};