'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/date-picker.css';
import { Button } from '../button/Button';
import { InputText } from '../input-text/InputText';
import { PickerMenu } from '../picker-menu/PickerMenu';
import { DatePickerContent, SelectedDate, DisabledDate } from '../date-picker-content/DatePickerContent';

export type DatePickerVariant = 'dropdown-outlined' | 'dropdown-ghost' | 'input';

export interface DatePickerProps {
  variant?: DatePickerVariant;
  minYear?: number;
  maxYear?: number;
  disabled?: boolean;
  disabledDates?: DisabledDate[];
  label?: string;
  placeholder?: string;
  inputWidth?: string;
  showLabel?: boolean;
  showFooter?: boolean;
  showOtherMonthDays?: boolean;
  value?: SelectedDate | null;
  onChange?: (value: SelectedDate | null) => void;
  onDateSelect?: (value: SelectedDate | null) => void;
}

export const DatePicker: React.FC<DatePickerProps> = ({
  variant = 'input',
  minYear = 1998,
  maxYear = 2060,
  disabled = false,
  disabledDates = [],
  label = 'Select Date',
  placeholder = 'Choose date',
  inputWidth = '200px',
  showLabel = true,
  showFooter = false,
  showOtherMonthDays = true,
  value,
  onChange,
  onDateSelect,
}) => {
  const [selectedValue, setSelectedValue] = React.useState<SelectedDate | null>(value || null);
  const [tempSelection, setTempSelection] = React.useState<SelectedDate | null>(null);
  const [isMenuOpen, setIsMenuOpen] = React.useState(false);
  const [isMenuClosing, setIsMenuClosing] = React.useState(false);
  const containerRef = React.useRef<HTMLDivElement>(null);

  // Sync with external value prop
  React.useEffect(() => {
    if (value !== undefined) {
      setSelectedValue(value);
    }
  }, [value]);

  const getDisplayValue = (): string => {
    if (!selectedValue) return '';
    // Format as MM/DD/YYYY
    const month = (selectedValue.month + 1).toString().padStart(2, '0');
    const day = selectedValue.day.toString().padStart(2, '0');
    return `${month}/${day}/${selectedValue.year}`;
  };

  const getButtonLabel = (): string => {
    return getDisplayValue() || placeholder;
  };

  const handleTriggerClick = (): void => {
    if (disabled) return;
    if (!isMenuOpen && showFooter) {
      // When opening with footer, initialize temp selection with current value
      setTempSelection(selectedValue);
    }
    setIsMenuOpen(!isMenuOpen);
  };

  const handleInputValueChange = (inputValue: string): void => {
    if (disabled) return;
    parseInputValue(inputValue);
  };

  const handleInputFocus = (): void => {
    if (disabled) return;
    if (!isMenuOpen && showFooter) {
      // When opening with footer, initialize temp selection with current value
      setTempSelection(selectedValue);
    }
    setIsMenuOpen(true);
  };

  const parseInputValue = (inputValue: string): void => {
    // Parse MM/DD/YYYY format
    const match = inputValue.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if (match) {
      const month = parseInt(match[1], 10) - 1; // Convert to 0-based month
      const day = parseInt(match[2], 10);
      const year = parseInt(match[3], 10);

      // Validate date
      if (
        month >= 0 &&
        month <= 11 &&
        day >= 1 &&
        day <= 31 &&
        year >= minYear &&
        year <= maxYear
      ) {
        const date = new Date(year, month, day);
        // Verify the date is valid (handles invalid dates like Feb 30)
        if (
          date.getFullYear() === year &&
          date.getMonth() === month &&
          date.getDate() === day
        ) {
          const newValue: SelectedDate = { year, month, day };
          setSelectedValue(newValue);
          onChange?.(newValue);
          onDateSelect?.(newValue);
        }
      }
    }
  };

  const handleDateSelect = (date: SelectedDate | null): void => {
    if (showFooter && date) {
      // With footer: just update temp selection, don't apply yet
      setTempSelection(date);
    } else {
      // Without footer: immediately apply and close
      setSelectedValue(date);
      onChange?.(date);
      onDateSelect?.(date);
      if (!showFooter) {
        closeMenu();
      }
    }
  };

  const handleMenuCancel = (): void => {
    // Reset temp selection and close
    setTempSelection(null);
    closeMenu();
  };

  const handleMenuApply = (): void => {
    // Apply the temp selection and close
    if (tempSelection) {
      setSelectedValue(tempSelection);
      setTempSelection(null);
      onChange?.(tempSelection);
      onDateSelect?.(tempSelection);
    }
    closeMenu();
  };

  const handleToday = (): void => {
    const today = new Date();
    const todayDate: SelectedDate = {
      year: today.getFullYear(),
      month: today.getMonth(),
      day: today.getDate(),
    };

    if (showFooter) {
      setTempSelection(todayDate);
    } else {
      setSelectedValue(todayDate);
      onChange?.(todayDate);
      onDateSelect?.(todayDate);
      closeMenu();
    }
  };

  const closeMenu = (): void => {
    setIsMenuClosing(true);
    setTimeout(() => {
      setIsMenuOpen(false);
      setIsMenuClosing(false);
    }, 150);
  };

  const handleBackdropClick = (): void => {
    handleMenuCancel();
  };

  const handleCalendarIconClick = (): void => {
    handleTriggerClick();
  };

  return (
    <>
      <div className="date-picker-container" ref={containerRef}>
        {/* Dropdown Outlined Variant */}
        {variant === 'dropdown-outlined' && (
          <div className="date-picker-trigger" onClick={handleTriggerClick}>
            <Button
              hierarchy="secondary"
              type="outline"
              size="sm"
              icon="trailing"
              label={getButtonLabel()}
              iconName="expand_more"
              disabled={disabled}
            />
          </div>
        )}

        {/* Dropdown Ghost Variant */}
        {variant === 'dropdown-ghost' && (
          <div className="date-picker-trigger" onClick={handleTriggerClick}>
            <Button
              hierarchy="tertiary"
              type="ghost"
              size="sm"
              icon="trailing"
              label={getButtonLabel()}
              iconName="expand_more"
              disabled={disabled}
            />
          </div>
        )}

        {/* Input Variant */}
        {variant === 'input' && (
          <div className="date-picker-trigger input-field-container">
            <InputText
              label={label}
              placeholder={placeholder}
              value={getDisplayValue()}
              disabled={disabled}
              showTrailingIcon={true}
              trailingIcon="calendar_today"
              showHelpIcon={false}
              showHintText={false}
              showLabel={showLabel}
              width={inputWidth}
              onChange={handleInputValueChange}
              onFocus={handleInputFocus}
            />
            {/* Overlay for icon click detection */}
            <div className="calendar-icon-overlay" onClick={handleCalendarIconClick}></div>
          </div>
        )}

        {/* Date Picker Menu */}
        <div className="date-picker-menu-container">
          <PickerMenu
            visible={isMenuOpen}
            showFooter={showFooter}
            showTodayButton={showFooter}
            disableApply={showFooter && tempSelection === null}
            onCancel={handleMenuCancel}
            onApply={handleMenuApply}
            onToday={handleToday}
          >
            <DatePickerContent
              minYear={minYear}
              maxYear={maxYear}
              disabled={disabled}
              disabledDates={disabledDates}
              showOtherMonthDays={showOtherMonthDays}
              value={tempSelection || selectedValue}
              onDateSelect={handleDateSelect}
            />
          </PickerMenu>
        </div>
      </div>

      {/* Backdrop */}
      {(isMenuOpen || isMenuClosing) && (
        <div className="date-picker-backdrop" onClick={handleBackdropClick}></div>
      )}
    </>
  );
};

export default DatePicker;