'use client';

import * as React from 'react';
import '../../../../../bellhopos-styles/src/components/toggle.css';

export type ToggleSize = 'sm' | 'md';
export type ToggleState = 'default' | 'hover' | 'focus' | 'disabled';

export interface ToggleProps {
  size?: ToggleSize;
  showText?: boolean;
  label?: string;
  supportingText?: string;
  disabled?: boolean;
  id?: string;
  className?: string;
  checked?: boolean;
  defaultChecked?: boolean;
  onChange?: (checked: boolean) => void;
}

export const Toggle: React.FC<ToggleProps> = ({
  size = 'md',
  showText = false,
  label = '',
  supportingText = '',
  disabled = false,
  id,
  className = '',
  checked,
  defaultChecked = false,
  onChange,
}) => {
  const [internalChecked, setInternalChecked] = React.useState(defaultChecked);
  const [isFocused, setIsFocused] = React.useState(false);
  const [isHovered, setIsHovered] = React.useState(false);

  // Determine if controlled or uncontrolled
  const isControlled = checked !== undefined;
  const isChecked = isControlled ? checked : internalChecked;

  const handleToggle = React.useCallback(() => {
    if (disabled) return;

    const newChecked = !isChecked;

    // Always update internal state for uncontrolled components
    if (!isControlled) {
      setInternalChecked(newChecked);
    }

    // Always call onChange if provided
    onChange?.(newChecked);
  }, [isChecked, isControlled, disabled, onChange]);

  const handleKeyDown = React.useCallback((event: React.KeyboardEvent) => {
    if (event.key === ' ' || event.key === 'Enter') {
      event.preventDefault();
      handleToggle();
    }
  }, [handleToggle]);

  const handleMouseEnter = React.useCallback(() => {
    setIsHovered(true);
  }, []);

  const handleMouseLeave = React.useCallback(() => {
    setIsHovered(false);
  }, []);

  const handleFocus = React.useCallback(() => {
    setIsFocused(true);
  }, []);

  const handleBlur = React.useCallback(() => {
    setIsFocused(false);
  }, []);

  const wrapperClasses = React.useMemo(() => {
    const classes = ['toggle-wrapper'];
    if (showText) {
      classes.push('toggle-with-text');
    }
    classes.push(`toggle-size-${size}`);
    if (className) {
      classes.push(className);
    }
    return classes.join(' ');
  }, [showText, size, className]);

  const switchClasses = React.useMemo(() => {
    const classes = ['toggle-switch'];
    classes.push(isChecked ? 'toggle-pressed' : 'toggle-unpressed');
    classes.push(`toggle-${size}`);

    if (disabled) {
      classes.push('toggle-disabled');
    }

    if (isFocused && !disabled) {
      classes.push('toggle-focus');
    }

    if (isHovered && !disabled) {
      classes.push('toggle-hover');
    }

    return classes.join(' ');
  }, [isChecked, size, disabled, isFocused, isHovered]);

  const buttonClasses = React.useMemo(() => {
    const classes = ['toggle-button'];
    classes.push(isChecked ? 'toggle-button-pressed' : 'toggle-button-unpressed');
    classes.push(`toggle-button-${size}`);

    if (disabled) {
      classes.push('toggle-button-disabled');
    }

    return classes.join(' ');
  }, [isChecked, size, disabled]);

  const labelClasses = React.useMemo(() => {
    const classes = ['toggle-label'];
    classes.push(`toggle-label-${size}`);
    return classes.join(' ');
  }, [size]);

  return (
    <div className={wrapperClasses}>
      <div
        className={switchClasses}
        onClick={handleToggle}
        onKeyDown={handleKeyDown}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        onFocus={handleFocus}
        onBlur={handleBlur}
        tabIndex={disabled ? -1 : 0}
        id={id}
        role="switch"
        aria-checked={isChecked}
        aria-disabled={disabled}
        aria-label={label || undefined}
      >
        <div className={buttonClasses}></div>
      </div>

      {showText && (label || supportingText) && (
        <div className="toggle-text">
          {label && (
            <label htmlFor={id} className={labelClasses}>
              {label}
            </label>
          )}
          {supportingText && (
            <div className="toggle-supporting-text">
              {supportingText}
            </div>
          )}
        </div>
      )}
    </div>
  );
};