import React from 'react';
import '../../../../../bellhopos-styles/src/components/featured-icon.css';

export type FeaturedIconSize = 'sm' | 'md' | 'lg' | 'xl';
export type FeaturedIconColor =
  | 'brand'
  | 'gray'
  | 'error'
  | 'warning'
  | 'success'
  | 'highlight';
export type FeaturedIconStyle = 'outlined' | 'filled';

export interface FeaturedIconProps {
  size?: FeaturedIconSize;
  color?: FeaturedIconColor;
  style?: FeaturedIconStyle;
  icon?: string;
}

export const FeaturedIcon: React.FC<FeaturedIconProps> = ({
  size = 'md',
  color = 'gray',
  style = 'outlined',
  icon = 'star'
}) => {
  const containerClasses = [
    'featured-icon',
    `featured-icon-${size}`,
    `featured-icon-${color}`,
    `featured-icon-${style}`,
  ].join(' ');

  const materialIconClass = `material-symbols-outlined icon-${size}`;

  return (
    <div className={containerClasses}>
      <span className={materialIconClass}>
        {icon}
      </span>
    </div>
  );
};